INSERT INTO public.tasks (id, parent_task_id, creator, origin, title, purpose, description, actions, notes, position, status, days_from_start, duration, settings) VALUES
  ('bd474592-f72b-55ac-b857-e412ec074839', '2dfd71b3-a18e-5f11-b5c4-a5216dc95cc1', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'PHASE I - PREPARATION', 'The purpose of Phase I is to get the ball rolling with the new church plant project.', NULL, NULL, 'template: standard  2020-12-23 name changed from "GETTING STARTED" --pb ', 0, 'todo', 108, 109, '{}'::jsonb),
  ('77c11ec8-a16c-59cf-bcf8-47eee27e44c7', '2dfd71b3-a18e-5f11-b5c4-a5216dc95cc1', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'PHASE II - SETTING DNA', NULL, NULL, NULL, 'template:  ', 1, 'todo', 0, 0, '{}'::jsonb),
  ('cc30054d-5dec-5cdd-85dc-25d9cb848f89', '2dfd71b3-a18e-5f11-b5c4-a5216dc95cc1', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'PHASE III - STRUCTURE', NULL, NULL, NULL, 'template:  ', 2, 'todo', 0, 0, '{}'::jsonb),
  ('3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', '2dfd71b3-a18e-5f11-b5c4-a5216dc95cc1', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'PHASE IV - COMMUNITY CONNECTION', NULL, NULL, NULL, 'template:  ', 3, 'todo', 0, 0, '{}'::jsonb),
  ('3e5d7d63-90a0-5236-8757-09eab8a43f4c', '2dfd71b3-a18e-5f11-b5c4-a5216dc95cc1', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'PHASE V - WORSHIP GATHERINGS', NULL, NULL, NULL, NULL, 4, 'todo', 0, 0, '{}'::jsonb);
INSERT INTO public.tasks (id, parent_task_id, creator, origin, title, purpose, description, actions, notes, position, status, days_from_start, duration, settings) VALUES
  ('45667404-f85d-5dc7-b5f4-be7003081680', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Create a Community Networking Strategy', 'Devise a strategy to network in the community to learn about the community, develop partnerships for service and get the word out about the new church.', 'Community networking can easily be overlooked. However, it can be an essential tool for building relationships within the community.  For example, one planter joined the local Optimist Club in order to meet other community leaders. Through those relationships, the planter learned of a need for meals for under-resourced families. He leveraged the influence of the leaders in the Optimist Club to mobilize a team of volunteers and donors to provide a week''s worth of meals for 100 families in the community.  In carrying out the plan, he connected with each school in the community and got a list of under-resourced families. The planter was then able to network with principals, guidance counselors and parent liaisons within the schools. Through this community initiative, the planter was able to work directly with the schools to assist these families with their ongoing needs.  A team of 70 volunteers was recruited. Several of these volunteers became launch team members of the church. The church also gained lots of local press coverage and good PR. None of this would have happened if the planter had not been intentional about networking. The fruit of this particular networking was not seen for more than six months, but when it came, the harvest was large.  This milestone will help you target key leaders in the community to network with, and to develop a plan for connecting with them. Often times God is working upstream of us. By networking, we learn about what God is already doing and how partnerships can be built around common goals.', NULL, 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2017-11-13 content validated; "sample networking strategy" link removed --pb  2019-11-26 content overhauled& --pb  2020-12-14 changed Due in # Days from 70& to 32& & Duration from 7 to 1& --pb&  ', 0, 'todo', 136, 106, '{}'::jsonb),
  ('59cfdf08-df2f-5349-9158-bfd2e0dbf573', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Community Networking Strategy', 'Put into practice the strategies laid out in the previous Milestone to connect with community leaders and influencers.', 'Now that your Networking Strategy has been developed, it''s time to put those strategies into action. Take each action item resulting from the networking strategy and add them to this milestone. This can be done through the PlanterPlan tool. Networking will be an ongoing effort during the pre-launch phase of the church. Be sure to set realistic goals for completion.', '--no steps--', 'template: standard  2017-11-13 content updated --pb  2019-11-20 title updated from "Establish Community Contact Database" --pb  2019-12-09 content updated --pb  2020-12-14 changed Due in # Days from 83& to 58& --pb&  2020-12-23 name changed from "Choose strategic place to save contact info from networking" --pb ', 1, 'todo', 136, 99, '{}'::jsonb),
  ('e9365b1b-0717-5164-b14f-41888b5bde24', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Create a Launch Team Development Strategy', 'Build the team that will be the church and get the regular worship gatherings launched.', 'Developing the Launch Team is the most important thing the planter will do.  Studies like Ed Stetzer''s <a href="https://www.newchurches.com/">The State of Church Planting in the U.S. Research Report</a> continue to show that the size of the Launch Team prior to launch is a leading indicator of the church''s health and sustainability after launch.  Churches that launch with more than 40 adults on the launch team have fewer problems with common struggles like leadership development, financial stability and volunteerism.  Development of the Launch Team is the single most important health metric of the new church. You can develop plans, strategies, and have all the needed resources, but without a Launch Team, a new church will not be birthed.', NULL, 'template: standard  2017-06-09 content and links updated --pb  2019-12-23 content updated and links verified; removed broken hyperlink to missionglue.com blog post --pb  2020-12-14 changed Due in # Days from 56& to 51& & Duration from 7 to 1& --pb&  ', 2, 'todo', 70, 21, '{}'::jsonb),
  ('89398a75-6aa5-5b8c-b447-49f80f679f9c', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Launch Team Development Strategy', 'Put into practice what you decided to do when crafting your Launch Team Development Strategy.', 'Now that you''ve strategized how to recruit locals to your launch team and what to do with them once gathered, it is time to put those strategies into action.  Invite people, build community, and train & empower them. It''s go time!', NULL, 'template:  2019-12-10 date fields found empty&  2019-12-11 date fields re-entered manually --pb  2022-11-21 updated links --sc ', 3, 'todo', 233, 212, '{}'::jsonb),
  ('2ae93268-1d03-5256-9aac-68287a289617', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Groups Strategy', 'Pull the trigger on the strategies you laid out in the previous Milestone to launch groups at the new church.', 'Now that the Groups Strategy has been planned based on context, aim and vision, it is time to execute the strategies. The first groups launched will have significant impact on the DNA of groups for years to come.', NULL, 'template: standard  2018-03-29 overtyped legacy content about "add custom tasks to milestone" with new content --pb  2019-12-03 content validated --pb  2020-12-14 changed Due in # Days from 147& to 105 & Duration from 7 to 14 --pb&  ', 4, 'todo', 154, 95, '{}'::jsonb),
  ('3b97d06a-7109-5eb3-87df-1f4a87e71aad', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop an Outreach Strategy', 'Craft a thoughtful and coordinated approach to living out your values and beliefs in the community.', 'Outreach is being the hands and feet of Jesus. It is translating our good intentions into good deeds.  James put it well:  "In the same way, faith by itself, if it is not accompanied by action, is dead." James 2:17  As did John:  "Dear children, let us not love with words or speech but with actions and in truth." 1 John 3:18  This milestone will help you translate your church''s values and beliefs into works of service in the community. It encompasses both  go and serve  outreach (community service) as well and  come and see  outreach (events).', NULL, 'template: standard  2018-02-16 content updated --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 112& to 108& & Duration from 7 to 1& --pb&  ', 5, 'todo', 134, 44, '{}'::jsonb),
  ('1bdf3779-fc16-5f80-aba0-ce618dc1e8f0', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Outreach Strategy', 'Put into action the strategies laid out in the previous Milestone to build bridge with and in your community.', 'Now that your Outreach Strategy has been developed, it''s time to put those strategies into action. This milestone already contains tasks common to most church plants. Take other action items resulting from the outreach strategy document and add them to this milestone. You can do that right in the PlanterPlan tool.  Outreach will be an ongoing effort during the pre-launch phase of the church. Be sure to set a sustainable pace that will continue on after Launch Sunday.', '--no steps--', 'template: standard  2019-12-10 content updated --pb  2020-12-14 changed Due in # Days from 125& to 128& & Duration from 14& to 7& --pb&  ', 6, 'todo', 129, 74, '{}'::jsonb),
  ('66b5661c-2739-572c-b538-f99e336debd8', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop Strategy for Streaming Content', 'Create a strategy to stream devotionals, sermons and/or worship services prior to the launch of in-person worship gatherings.', '[content pending]', NULL, 'template:  2022-01-20 changed "digital launch" to "streaming content" language ', 7, 'todo', 111, 21, '{}'::jsonb),
  ('d5837a4d-a4a1-55f1-8be0-8f4033b39ec3', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop a Marketing Strategy', 'Create an intentional strategy to let your community know about the new church.', 'You cannot avoid marketing the new church. Whether you''re intentional about communicating with the community at large and unchurched individuals, every time they see or hear about the church,  that is marketing . Marketing is simply communication. "The greatest Message deserves the greatest marketing." -Mark Batterson  This milestone will take you through the exercises of putting together a consistent and comprehensive marketing strategy that is customized to your community. You will also create a marketing budget and be stretched to think creatively about marketing.', '--no steps--', 'template: standard  2017-11-29 content updated --pb  2018-10-26 content updated --pb&  2019-12-23 content updated --pb  2020-12-14 changed Due in # Days from 119& to 115 & Duration from 7 to 1& --pb&  ', 8, 'todo', 226, 183, '{}'::jsonb),
  ('a6f1d38b-6e68-5a78-825c-495ff8a01366', '3246d642-0bdb-5f5b-a9e5-5604e9f8e4b9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Marketing Strategy', 'Pull the trigger on the strategies you laid out in the previous Milestone to announce your new church to your community.', 'Now that the marketing strategy has been carefully planned based on audience, time tables and budget, it is time to execute the strategy. There will be a big push leading up to the launch, but marketing needs to be an ongoing discipline for the life of the congregation.', '--no steps--', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2017-12-15 content update --pb  2020-12-14 changed Due in # Days from 170& to 167& & Duration from 7 to 1& --pb &  ', 9, 'todo', 226, 183, '{}'::jsonb),
  ('e5b4e37d-7ffc-58af-a770-f5a7f6c94442', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Select a Worship Gathering Facility', 'This milestone helps you choose the best facility for your worship gatherings.', 'Choosing the right facility for the church plant is no small feat. Ron Sylvia put it best: "We shape our buildings, and then our buildings shape us."  This milestone will help the planter to think through the many aspects of selecting a facility and guide the planter in evaluating each available facility in order to choose the best fit.', '--no steps--', 'template: standard  2019-12-17 content updated --pb  2020-12-14 changed Due in # Days from 37& to 32& & Duration from 7 to 1& --pb&  ', 0, 'todo', 92, 62, '{}'::jsonb),
  ('cdf897ce-bc8d-574f-a0f5-c53e6416816c', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Initiate Ministry Teams', 'Create team structures and systems and begin identifying leaders and members for each team.', 'Team-based ministry is essential to a healthy and growing church. Initially you''ll be able to carry out most of the processes needed to start the church. However, as the church grows, these processes will also grow. If you don''t develop teams, your capacity will be the cap to church growth.  It is easiest to develop a team-based strategy from the beginning rather than to shift later by necessity. Team-based ministry also clearly supports the biblical image of the Church as the Body of Christ, in which all members of the Body serve a role.  Your job becomes one of equipping and training people to do ministry. This milestone walks you through building a teams structure, developing systems & processes to support those teams, and recruiting workers & leaders to each team.', 'Watch the Passion for Planting training video "<a href="/resources/item/257">Initiate Ministry Teams</a>" featuring Ed Stetzer.', 'template: standard  2017-05-31 content updated, audience changed to coach --pb  2018-04-20 updated content, changed audience to planter --pb  2020-01-13 content validated --pb  2020-12-14 changed Due in # Days from 95& to 128 --pb&  ', 1, 'todo', 259, 200, '{}'::jsonb),
  ('8ca53ea7-37ec-5a4e-b862-fabf9e5dfbac', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Get Startup Equipment', 'Plan, order and assemble the equipment you''ll need to accomplish the vision God has given you for the worship gatherings.', 'Having equipment to carry out a worship gathering is a necessity in today''s North American churches. With most plants holding worship gatherings in rented facilities, you''ll have to buy everything from children''s equipment to audio/visual/lighting (AVL) and sometimes even chairs.  This milestone will walk you through figuring out what kind of equipment you''ll need for the worship gatherings and managing ordering deadlines.', '--no steps--', 'template: standard  2020-01-20 content updated --pb  2020-12-16 changed Due in # Days from 112& to 122& & Duration from 7 to 1& --pb  &  &  ', 2, 'todo', 259, 200, '{}'::jsonb),
  ('c1bf46aa-4e62-5612-ba1c-7a43b3a88e78', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Determine Assimilation Strategy', 'Create a system for intentionally getting people relationally connected and sold out to the vision of the church.', 'The assimilation process can make or break a new church in the first few years. The excitement and novelty of a brand-new church will draw more guests than perhaps at any other time in the life of a congregation. The guests need to make friends and catch the vision. If you don''t get them connected, they''ll keep moving and you will have lost precious opportunity.  This milestone will walk you through setting up a written strategy to facilitate and reinforce the assimilation process.', NULL, 'template: standard  2017-05-31 content updated, audience changed to coach --pb  2019-01-11 Due in # Days corrected from 28 to 138 --pb  2012-12-02 content updated --pb  2020-12-16 changed Due in # Days from 138& to 141 --pb&  &  ', 3, 'todo', 180, 150, '{}'::jsonb),
  ('aa6cbfb8-f885-5664-8aac-a344cb41f325', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Assimilation Strategy', 'Pull the trigger on the strategies you laid out in the previous Milestone to develop repeatable processes for getting people plugged in to your church.', 'Now that the assimilation strategy has been carefully crafted to consider the various entry points, kinds of people showing up, and how to follow up with each, it is time to recruit and empower a team to execute the strategy.', NULL, 'template: standard  2017-05-19 changed plan to strategy --pb  2019-12-03 additional resources subsection added --pb  2019-12-05 content validated --pb  2021-01-28 content updated --pb ', 4, 'todo', 180, 150, '{}'::jsonb),
  ('942699a3-c0a6-51a8-82f6-53ac61e15252', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Prepare for Teaching and Preaching', 'Create sermon prep systems and plan ahead for both sermons series and individual sermons.', 'This milestone will walk you through planning months worth of sermon topics at a time and challenge to completely prep your first sermon series well in advance of Launch Sunday.', NULL, 'template: standard  2017-12-28 content overhauled --pb  2018-07-30 new resource link added --pb  2020-12-16 changed Due in # Days from 217& to 160& & Duration from 7 to 1& --pb  &  &  2020-01-24 content validated --pb  ', 5, 'todo', 259, 200, '{}'::jsonb),
  ('37145453-8c14-5a2d-a990-c8a7d677b1fa', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop Worship Planning System', 'Create systems and structures to foster an engaging worship environment that is attractive to believers and seekers alike.', 'Putting together worship services for a new church is a prime opportunity for creativity and innovation. You get to "do church" in a way that is informed by your context and your Vision Frame.  There isn''t yet any "we''ve always done it that way" resistance. But especially since people on your Launch Team are coming from all different experiences of church, you can''t just wing it or fall back on defaults. No one will have the same defaults as you.  This milestone will challenge you to create repeatable processes to craft inspiring and spiritually engaging worship gatherings. And it will walk you through some very practical things you''ll need to prepare in advance of your preview services.', NULL, 'template: standard  2017-12-27 content updated --pb  2020-01-21 content validated --pb  2020-12-16 changed Due in # Days from 180& to 161& --pb  ', 6, 'todo', 259, 200, '{}'::jsonb),
  ('5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Make Final Preparations', 'Prevent important aspects of the Opening Day of worship gatherings from falling apart or getting overlooked.', 'This milestone will walk you through making a list and checking it twice. The last 5% of any project is the hardest to complete.  With all of the things that need to happen for the Opening Day of worship gatherings, it would be easy to overlook something or not give it the attention it requires. Creating a checklist will help you think concretely about all of the different people, roles, tasks, equipment, etc... that need to be ready.  Reviewing all of the strategic work and planning you did earlier in the planting process will remind you of what''s important and will help you connect all of the busy work back to the vision & mission of the church.', NULL, 'template: standard  2017-12-28 content udpated --pb  2019-08-19 title changed from "Review Assimilation Strategy" --pb  2020-12-16 changed Due in # Days from 217& to 220& --pb &  2020-01-24 content updated --pb  ', 7, 'todo', 259, 200, '{}'::jsonb),
  ('a066a391-37ec-5e37-823d-1b1c27166d67', '3e5d7d63-90a0-5236-8757-09eab8a43f4c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Launch In-Person Worship Gatherings', 'The Opening Day of worship gatherings is an exciting day. Celebrate God! Bring Him the Glory and Honor for what He has done.', NULL, NULL, 'template: standard  2017-12-27 content & links completely overhauled --pb  2018-07-13 updated&  due in # of days  from 14 to 30 and&  duration  from 188 to 30 --pb  2018-07-20 updated vendors --pb  2021-10-05 content updated --pb  2019-03-21 updated vendors --pb  2019-11-19 updated content --pb  2021-01-18 due in days changed from 30 to 74 and duration from 30 to 14 --pb  2022-11-21 updated links --sc ', 8, 'todo', 259, 7, '{}'::jsonb),
  ('a11e086c-043b-5749-8119-414c01e8478b', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Exegete Your Community', 'Intently study the community God is calling you to reach in order to uncover Gospel opportunities.', 'You need to understand your community so that you can contextualize the Gospel and how you will "do church" so that it makes sense to them.  The tasks in this milestone will walk you step-by-step through becoming an expert on your community.', NULL, 'template: standard  2017-09-26 content validated --pb  2019-11-22 content updated --pb  2020-12-16 changed Due in # Days from 91& to 99& & Duration from 63& to 84& --pb&  ', 0, 'todo', 98, 84, '{}'::jsonb),
  ('553d3aeb-a255-51de-982b-596495e68a36', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Set Opening Day Expectations', 'Dream about what the Opening Day of worship gatherings will look like and discover how that will both benefit your leadership and propel the launch team toward a successful launch or regular worship gatherings.', 'A clear understanding of what the worship gathering will be like on Opening Day enables you to stay focused on what needs to be done during the pre-launch phase. The vision for the future (what Opening Day looks like) will shape our actions today.  This milestone will take you through the exercises of envisioning what Opening Day looks like, assessing where the launch team is currently, and making specific goals for how to get from Point A to Point B.', NULL, 'template: standard  2017-06-01 content validated --pb  2018-11-02 content updated --pb  2019-12-17 content updated --pb  2020-12-16 changed Due in # Days from 45& to 42& & Duration from 24& to 21& --pb&  ', 1, 'todo', 45, 25, '{}'::jsonb),
  ('1899b6fc-eea7-5813-9b30-fc5a2e8d5cbc', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Publish Your Launch Strategy', 'Publish a printed Launch Strategy document that will help you with fundraising, networking and Launch Team recruitment.', 'At some point, your visionary ideas will need to be implemented, or they will remain wishful thinking. The first step in the implementation process is writing things down. Creating a Launch Strategy document is exactly that.  The tasks in this Milestone will help you:  Open a conversation with your coach about crafting a Launch Strategy  Hammer out the various building blocks of a Launch Strategy and compile it into a single, useful document  Get your coach''s feedback on the Launch Strategy', NULL, 'template:  New Milestone  2018-04-20 updated content, changed audience to planter --pb  2019-12-03 content updated --pb ', 2, 'todo', 134, 113, '{}'::jsonb),
  ('fe8353d6-0b13-593c-bdba-2abf5975a65b', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Define Church Vision', 'Create clarity around your church''s mission, values, beliefs and measures.', 'Your Philosophy of Ministry defines who you are and what you do, as well as what you don''t do. It is the manifesto of the uniqueness of your church. It is your filter for making every important decision.  Each Planter lives out a Philosophy of Ministry whether it is intentional or accidental. Think through the various aspects of your Philosophy of Ministry, write it all down, be able to communicate it, and be intentional about living it out.', NULL, 'template: standard  2017-06-01 content updated --pb  2020-12-16 changed Due in # Days from 56& to 61& & Duration from 32& to 47& --pb&  ', 3, 'todo', 158, 159, '{}'::jsonb),
  ('3c968e6b-9362-5637-ade7-72b9112bc28b', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop a Culture of Multiplication', 'Establish a culture of reproduction within the church to multiply leaders, groups, sites and churches.', 'In order for the church to grow is size and effectiveness, volunteer and staff leaders need to be in place. Many church plants struggle with developing the leadership needed to grow the church. In some cases, the church growth outpaces the growth in leadership. This can quickly lead to staff burnout and a general collapse of systems.  Reproducing leaders is something that is often talked about but seldom put into practice. By setting a reproducing DNA early in the life of the church, leaders will be more effectively identified, trained and released for ministry.', NULL, 'template: standard  2017-11-13 content validated --pb  2020-12-11 changed Due in # Days from 168& to 62 --pb&  ', 4, 'todo', 136, 106, '{}'::jsonb),
  ('8db8ea3a-5e3d-535a-a35b-9ca390f78b59', '77c11ec8-a16c-59cf-bcf8-47eee27e44c7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop a Groups Strategy', 'Create systems and plan for environments that will foster relationships and disciple-making.', 'The church is about people, which means the church is about relationships. It''s hard to develop meaning relationships in an hour large-group environment on Sunday morning. There are lots of different approaches to church groups. You get to start a groups system based on what God is calling you to do in your time and place.  The tasks in this milestone will walk you through crafting strategies for your small groups structure, systems and leadership.', NULL, 'template: standard  2017-12-29 content update --pb  2018-03-28 changed Exponential channel link to discipleship.org link --pb  2018-11-19 updated content, changed title from "read this discipleship overview" --pb  2019-11-26 content updated --pb  2020-12-11 changed Due in # Days from 133& to 47& & Duration from 7 to 1 --pb&  ', 5, 'todo', 179, 136, '{}'::jsonb),
  ('9f197a08-281e-5163-aaad-3779da3b11a4', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Affirm the Calling', 'Use several different tools and resources to confirm and clarify God''s calling to plant a church.', 'Church planting is one of the most demanding and faith-stretching things you can do. It is also one of the most rewarding and satisfying. But, it is not for everyone.  Take time to study and learn about yourself and see how your gifts and strengths can be used to start a healthy church.  Also, submit yourself to the review and opinions of church planting experts to confirm that you are qualified and prepared to plant a church.  Most importantly, spend lots of time in prayer seeking God''s confirmation of the calling.', NULL, 'template: standard  2017-07-28 content validated & reformated& --pb  2019-11-22 content updated --pb  2020-12-16 changed Due in # Days from 7& to 28& & Duration from 90& to 28& --pb&  ', 0, 'todo', 48, 49, '{}'::jsonb),
  ('ef787a6e-86f7-5aef-a380-a7d82a5e790b', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Train for Church Planting', 'Learn as much as possible about disciple-making, church planting and leadership so you can maximize your God-given gifts and set the new church up for health.', 'Paul says in 1 Corinthians 9:25-27, "Everyone who competes in the games goes into strict training. They do it to get a crown that will not last; but we do it to get a crown that will last forever. Therefore I do not run like a man running aimlessly; I do not fight like a man beating the air. No, I beat my body and make it my slave so that after I have preached to others, I myself will not be disqualified for the prize."  It is a principle of life that if you want to be good at something, you must practice and train. Professional athletes train hours every day just to stay good at what they do. They do it for the paycheck and the fame.  The stakes for church planters are much higher - we are dealing with things eternal. Athletes compete against each other. Planters wage war against an unseen enemy who knows our every weakness.  Seek out the best trainers available through books, conferences, and boot camps. Also develop a plan to continue your learning and training in order to stay at the top of your game.', NULL, 'template: standard  2017-08-30 content updated --pb  2019-11-22 content updated --pb  2020-12-16 changed Duration from 90& to 45& --pb&  ', 1, 'todo', 45, 46, '{}'::jsonb),
  ('5074f41f-5aed-5e18-9135-434bdd8e6ff8', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Solidify Planter Support Structures', 'Set up solid relational structures to support yourself in the church planting process.', 'This milestone covers 3 general support structures that will give you the best fighting chance at a healthy church plant:  Coaching  Spousal Support  Management Team  While being healthy personally as a church planter doesn''t guarantee a healthy church plant, the planter becoming unhealthy through lack of support will almost certainly guarantee an unhealthy church plant. Create structures and set up support relationships that will promote health in both.  The tasks in the milestone will walk you through engaging a church planting coach, getting your spouse plugged in to a support system, and calling together a Management Team.', NULL, 'template: standard  2017-08-29 this milestone was formerly "Initiate Planter Coaching" but included WAY more than just coaching, so content has been updated to emphasize support (which includes coaching). --pb  2019-12-10 content validated --pb  2020-12-16 changed Due in # Days from 45& to 49& & Duration from 45& to 49& --pb&  ', 2, 'todo', 48, 49, '{}'::jsonb),
  ('edafb56f-8a85-5250-b916-bc340f6a1c02', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop an Intercessory Prayer Team', 'Recruit and communicate regularly with a prayer team to provide spiritual covering for your disciple-making efforts.', 'William Temple said, "When I pray, coincidences happen, and when I don''t pray, they don''t."  Making new disciples is a spiritual act. No matter how gifted and talented the church planter is, he/she will fail without being rooted in prayer.  The tasks in this milestone will walk you step-by-step through building a strong prayer team with healthy rhythms.', NULL, 'template: standard  2017-05-31 content validated --pb  2019-11-22 content updated --pb ', 3, 'todo', 13, 7, '{}'::jsonb),
  ('611a7f89-b2a5-583b-9adf-d7b0064d7c24', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Intercessory Prayer Team Strategy', 'Put into practice what you decided to do when crafting your Prayer Team Strategy.', 'If you can create a culture that communicates that God is leading this whole venture, your team will be more likely to seek God''s wisdom and counsel on the pieces they are responsible for.  In addition, a prayer culture will spill over into the life of the church as it grows and becomes more established. That helps create a leadership team and church that truly understand that, "it''s not about us." This starts by getting the Intercessory Prayer Team praying regularly for you and the plant.  If you are not a detail-oriented person, consider asking your coach to hold you accountable to the plan, or recruit a prayer team champion who will take responsibility for communicating to the prayer team.', NULL, 'template: standard  2017-05-31 content updated --pb  2019-11-22 instructions for adding custom tasks removed --pb  2019-12-03 content updated --pb  2020-12-16 changed Due in # Days from 35& to 30& & Duration from 21& to 16& --pb&  ', 4, 'todo', 29, 16, '{}'::jsonb),
  ('1e8e529f-5a19-5700-9f20-e78b72bc7a76', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Set Up Personal Accountability', 'Put a system of accountability in place to protect yourself from spiritual attack and to limit temptation.', 'Do not underestimate the spiritual implications of starting a new church. The enemy does not want to see new churches started. You will face spiritual attack and often at your most vulnerable point.  This milestone will help you create a system of accountability. One of the best things you can do for yourself and your family is to set up accountability to protect them and yourself.  The worst service you can do to yourself, your family, your church, and ultimately the Kingdom is to ignore these simple steps and set yourself up to be yet another pastor embroiled in scandal. Nothing will destroy the new church faster.', NULL, 'template: standard  2017-09-26 content updated --pb  2019-11-22 content validated --pb  2020-12-16 changed Due in # Days from 60& to 35& & Duration from 14& to 35& --pb&  ', 5, 'todo', 44, 45, '{}'::jsonb),
  ('6b7c39eb-4653-5796-8d7d-d30a90c5d6ec', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Articulate Your Disciple-Making Strategy', 'Create a document that will explain in plain language how your church will go about fulfilling Jesus'' Great Commission to make disciples of all nations.', 'There has been a much-needed rebirth of conversation around disciple-making in the United States. Throughout PlanterPlan, you will see it referred to as "disciple-making" and not "discipleship" because of the baggage and sometimes ambiguity that comes with that term.  It''s safe to say that Jesus was the best disciple maker of all time. The things we see him doing in the Gospel accounts should inspire how we approach discipleship and how we create environments and processes that multiply disciples.  This milestone will walk you through doing the hard work of digging back into scripture with fresh eyes for Jesus'' disciple-making genius.', NULL, 'template:  2020-12-11 changed Duration from 7& to 1& --pb  2021-03-12 Ephesiology& URL& added --pb  2022-11-21 updated links --sc ', 6, 'todo', 233, 220, '{}'::jsonb),
  ('fb3f6ed6-495c-51c7-842e-d21e94c696e6', 'bd474592-f72b-55ac-b857-e412ec074839', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop Fundraising Strategy', 'Set a realistic fundraising goal and strategize how to go about raising those funds.', 'Money follows vision. Start with the vision that God is giving you for the church plant and use that to reverse engineer the required fundraising goal. Fundraising requirements will be different for a different size churches. Big cities may require more funds that a smaller town. Number of initial staff and other considerations all play into the fundraising goal.  Many planters aren''t natural fundraisers, but most also become quite proficient once they try.  The tasks in this milestone will walk you through crafting a solid, actionable strategy and getting feedback from your coach.  The subsequent  Milestone: Implement Fundraising Strategy  will walk you through:  Crafting a prospectus (Launch Vision)  Developing other promotional materials  Setting up online giving and publishing a simple supporter site  Drafting scripts, pitches and letters  Implementing systems to organize and support fundraising efforts', NULL, 'template: standard  2017-05-30 content updated --pb  2019-11-19 content updated --pb  2020-12-16 changed Due in # Days from 45& to 43& & Duration from 31& to 22& --pb&  ', 7, 'todo', 45, 25, '{}'::jsonb),
  ('dfabb190-164d-5a8f-9fe2-05ba3e01943d', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Set Up Office', 'Provide an environment where you (and additional staff as appropriate) can work productively.', 'Whether you set up an office inside or outside the home, you will need to set a few things up. Typical office location choices include:  rented office space  donated space from a local church or business  working from a coffee shop or other public space  Your workspace can maximize or choke your ministry opportunities. Be intentional as you decide what your office will be and where it will be located. Your ministry will be impacted by where you set up your office based on:  whether you can host meetings at convenient times  people''s perceptions of your space  your ability to interact with not-yet-believers each day  Carefully consider the tensions of productivity, accessibility, and evangelistic opportunities as you decide.', NULL, 'template: standard  2017-08-10 content updated --pb  2019-12-10 content updated --pb  2020-12-16 changed Due in # Days from 98& to 45& & Duration from 30& to 45& --pb&  ', 0, 'todo', 44, 45, '{}'::jsonb),
  ('9aec9608-58d8-5be3-9fa8-1ba89313eff1', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Implement Fundraising Strategy', 'Put into practice the strategies laid out in the previous Milestone to provide for all of the church''s financial needs.', 'Now that a fundraising strategy has been developed, it is time to put the strategies into action. Take each action item resulting from the fundraising strategy and add them to this milestone. This can be done through the PlanterPlan tool. Fundraising will be an ongoing effort during the pre-launch phase of the church. Be sure to set realistic goals for completion.  If you''re planting through a managing partner, denomination, network or mother church, consult with them about where your financial supporters can send money or how they can give to your project online.', NULL, 'template: standard  2017-05-31 content validated --pb  2019-12-11 content validated --pb  2020-12-16 changed Due in # Days from 60 to 74& & Duration from 39& to 59& --pb&  ', 1, 'todo', 108, 109, '{}'::jsonb),
  ('ade0ccf7-7ce6-52fa-823e-4cf88bf65f62', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Establish Budget and Financial Systems', 'Establish key processes that make up a solid financial system.', 'We have to be above reproach in how we handle our finances - everything from bookkeeping to what we spend our money on. There should not be even the slightest hint of impropriety.  As clearly demonstrated in the Bible, Satan does some of his best work through sex and money. Even the smallest honest slip with our finances has the potential for scandal. For legal and for accountability reasons, the church must have clear, secure, and reliable financial processes.  This Milestone covers the following:  Bookkeeping plans  IRS tax regulations  Staff payroll  Financial software  Accounting processes  Donor management system  Budgeting', NULL, 'template: standard  2017-05-26 content udpated& --pb  2019-12-12 content updated --pb  2020-12-16 changed Duration from 40& to 45& --pb&  ', 2, 'todo', 108, 94, '{}'::jsonb),
  ('fce96968-0be0-523b-93df-31999293e240', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Take Care of Legal Requirements', 'File all the right paperwork in the right order to create the new legal entity of the church.', '"Everyone must submit himself to the governing authorities, for there is no authority except that which God has established. The authorities that exist have been established by God." Romans 13:1 NIV  Filling out government forms is not what most planters wanted to do when they grew up, but they are necessary for obeying the governing authorities in the spirit of Romans chapter 13.  The tasks in the milestone will walk you step-by-step through filing state, federal and other legal paperwork in the US.', NULL, 'template:  2020-12-14 changed Due in # Days from 78& to 45& --pb&  ', 3, 'todo', 233, 212, '{}'::jsonb),
  ('99442f16-d1fa-56a6-bd7f-a426977ba176', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Create Church''s Brand', 'Gain a clear understanding of what a brand is and why you should be intentional about building a positive one.', 'The new church will gain a reputation in the community either positive or negative. When they hear the church''s name or see the church''s logo, they will feel something about the church. Be intentional about presenting the church in a positive light.', NULL, 'template: standard  2017-10-26 content validated --pb  2019-12-09 content validated --pb  2020-12-16 changed Due in # Days from 112& to 109& & Duration from 42& to 56& --pb&  ', 4, 'todo', 127, 82, '{}'::jsonb),
  ('1299144e-2e6b-55f2-a44b-c5b4ea8ace63', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Create Initial Digital Footprint', 'Start claiming digital real estate and establishing the new church online even prior to having a fully developed brand.', NULL, NULL, 'template:  ', 5, 'todo', 233, 174, '{}'::jsonb),
  ('92c46dbf-2a14-57a9-8ad1-a9340c781243', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Develop a Staffing Strategy', 'Staffing (or planning for Staffing) can be one of the most important things you will do during the pre-launch period.', 'Staffing should come directly out of the vision for the new church. For example, if the vision includes reaching young families in the community, then an appropriate staff hire may be a children''s pastor.  Each staff hire should support the overall vision of the new church. In addition, each person hired should be sold out to the vision, beliefs and values of the new church.  Staff members will be key players in setting the DNA of the church. A bad hire can cripple the new church and kill momentum.  So the decision to hire a staff person should not be taken likely. Assess each staff member and seek the wisdom of your coach and oversight team before making any hiring decisions.  This Milestone walks you through creating a custom staffing strategy and setting up your church''s HR systems and the forms you''ll need.', '--no steps--', 'template: standard  2017-10-30 content updated --pb  2018-11-12 title changed from "Read this hiring staff overview" --pb  2019-12-20 content validated --pb  2020-12-14 changed Due in # Days from 63& to 51& & Duration from 7 to 1& --pb&  ', 6, 'todo', 136, 106, '{}'::jsonb),
  ('98d4b9df-64f2-5b1c-bc36-923cc09c8418', 'cc30054d-5dec-5cdd-85dc-25d9cb848f89', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Milestone: Begin Scouting for Facility', 'Begin actively searching for the facility that will accommodate your weekly worship gatherings.', 'While you aren''t ready for weekly worship yet, it can take months to find the right facility, negotiate terms, and finally get to a signed agreement. Start that hunt now so that when you get to your 8th small group, you can put the pedal to the metal toward launching weekly worship gatherings.  If you wait to hunt  until  you''ve launched your 8th group and it ends up taking 6-9 months to finalize, you may have forfeited your team''s excitement and momentum.', NULL, 'template:  2019-12-10 date fields found empty  2019-12-11 date fields re-entered manually --pb  2020-01-14 fixed broken links that were pointing to resource on Dev server --pb  2020-11-19 added the section about Digital Tools  2020-12-11 changed Due in # Days from 21& to 36 & Duration from 7 to 14 --pb ', 7, 'todo', 233, 220, '{}'::jsonb);
INSERT INTO public.tasks (id, parent_task_id, creator, origin, title, purpose, description, actions, notes, position, status, days_from_start, duration, settings) VALUES
  ('2d079dd8-07ce-54e9-b2a6-cd8bd840e0a7', '1299144e-2e6b-55f2-a44b-c5b4ea8ace63', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Decide which social media apps to use', 'Discover which social media platforms your target families use and decide which ones the church will use.', 'There are hundreds of social media platforms out there, too many for you possibly to participate in. Besides, if the people you''re trying to reach aren''t using those sites, why even bother?  Do a little research on which platforms are most popular generally, and then research which ones are most popular in your context. Chances are the resulting list will be relatively small since they have the same ''choice overload'' your church suffers from.', 'Determine which social media sites will be most effective in reaching your community.  Choose which social media sites your church will utilize from the start. Consider adding the  Milestone: Connect Through Social Media  to your launch plan.  This action is complete when you''ve decided which social media platforms to focus on.', 'template: standard  2017-11-14 content updated --pb  2019-12-09 content validated --pb  2020-12-14 changed Due in # Days from 98& to 81& --pb&  ', 0, 'todo', 62, 7, '{}'::jsonb),
  ('4b216c29-17cf-5495-946a-5b4e59c05396', '1299144e-2e6b-55f2-a44b-c5b4ea8ace63', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Claim username on social media sites', 'Claim your brand online as digital real estate.', 'It''s important to establish your digital footprint online and protect your brand. Not only does it allow you to own the digital real estate, a consistent brand online gets your church website ranked higher with search engines.  If at all possible, grab the identical username at each site so that it''s consistent and identifiable.  Confusion  One of the reason you want to claim a common user name is to prevent another church with a similar name accidentally picking it on another platform. If you''re @examplechurch on Facebook, it would be tragic for @examplechurch on Twitter to be an entirely different church elsewhere in the country.  There are sites where you can check name availability across the most popular platforms so you can know in advance if it''s already taken, especially on the major platforms. These services also check to see if the web address of the same name is available:  <a href="https://www.namecheckr.com">namecheckr</a> - "check domain & social username availability across multiple networks" (53+ domains & platforms)  <a href="https://namechk.com/">namechk</a> - "see if your desired username or vanity url is still available at dozens of popular Social Networking and Social Bookmarking websites" (35+ domains, 122 social platforms  plus  the US Trademark database)  <a href="https://knowem.com/">knowem</a> - "Search over 500 popular social networks, over 150 domain names, and the entire USPTO Trademark Database to instantly secure your brand on the internet" (<a href="https://knowem.com/signup-service.php">for a fee</a>, these guys will do the registering for you)  Imposters  Another reason you want to claim common usernames is that anyone with an email address can sign up for social media accounts. That means that anyone could potentially publish social media content under the name of your church. Celebrities have even gone to court to try and gain access to social media accounts created in their name. It''s not difficult to imagine someone maliciously posting information to defame the church.  To prevent this, your church should claim its real estate on multiple social media sites. Even though they may not be popular now, they could be next week''s big thing. The general rule should be if you''ve heard of it, get a profile.  With hundreds of social media sites available, there is no way to have a profile on all of them. Delegate this task to a team member or outside supporter. This is obviously a low priority task that can be accomplished either before launch or after. Do not lose a day yourself by going online and filling out profiles.  These should be non-negotiables:  <a href="https://www.facebook.com/">Facebook</a>  <a href="https://twitter.com/">Twitter</a>  <a href="https://www.instagram.com/">Instagram</a>  <a href="https://www.youtube.com">YouTube</a>  <a href="https://vimeo.com/">Vimeo</a>  Consider these as well, along with myriad others:  <a href="https://www.linkedin.com/">LinkedIn</a>  <a href="https://www.flickr.com/">Flickr</a>  <a href="https://www.pinterest.com/">Pintrest</a>  <a href="https://www.tumblr.com/">Tumblr</a>  <a href="https://www.stumbleupon.com/">StumbleUpon</a>', 'Find a social media username that you can claim across platforms.  Claim that name on at least the 6 non-negotiable sites above.  Recruit a volunteer to claim that username on other sites.  Make sure each social media profile is  completely  filled out.  This action is complete when the pages and/or profiles have been created at several social networking sites.', 'template: standard  2018-02-16 content updated, links verified --pb  2020-01-31 additional resources subsection& added --pb  2020-12-14 changed Due in # Days from 128& to 84; name changed from "monitor online communications" --pb&  2024-03-08 overhauled content & resource links --pb ', 1, 'todo', 76, 14, '{}'::jsonb),
  ('04d616d2-4111-5b27-8855-5d53536bace9', '1299144e-2e6b-55f2-a44b-c5b4ea8ace63', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a response plan for online comments & reviews', 'Listen, engage and respond to online communication about the church.', 'This task is all about listening and being responsive.  ### Outbound: What''s the Online Chatter?  People will soon be talking about your church online. How will you know what they are saying? Some of the most raw / honest feedback you can get comes from social media.  Consider using one or more of these tools to listen to online communications about your church:  Create a saved hashtag search using a social media management app (<a href="https://buffer.com/pricing" rel="noopener">Buffer</a>,& <a href="https://www.zoho.com/social/pricing.html" rel="noopener">Zoho Social</a>, <a href="https://vistasocial.com/pricing" rel="noopener">Vista Social</a>)  Create a <a href="https://www.google.com/alerts" rel="noopener">Google Alert</a> with the "name of your church" in quotes  Use advanced search on <a href="https://twitter.com/search-advanced?lang=en" rel="noopener">X (Twitter)</a>  ### Inbound: How will You Respond to DMs and Reviews?  Your Facebook page, WhatsApp, Yelp listing, Google Business listing, etc. should send you a notification for every direct message and review that someone posts. Make sure you''re getting notified for all DMs and reviews on your listings, and be sure to respond to those promptly&  to every review, whether positive and negative  - usually the same day if at all possible. Many of those apps publish a rating for how quickly you respond!', 'Set up at least one of the ''listening'' tools above.  Have a friend or Launch Team member DM you through your new church social media page(s) to test that you''re getting notifications.  This action is complete when Google Alerts and Twitter RSS feeds have been set up to monitor online communication about the church.', 'template: standard  2018-02-16 content updated --pb&  2020-01-14 content updated --pb  2020-12-14 changed Due in # Days from 128& to 181& & Duration from 7 to 90; name changed from "create a facebook strategy" --pb&  ', 2, 'todo', 83, 7, '{}'::jsonb),
  ('7bdc7173-873d-5a6d-b1f1-fd2d04dd4674', '1299144e-2e6b-55f2-a44b-c5b4ea8ace63', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Publish simple 1-page website', 'Create a simple web page to publish basic information about the new church for your community.', 'Having already created a page or site for your donors, it''s time to create a simple 1-page website for a different audience:  Stage 2: Your Team  As you network in the community and begin gathering a team, you''re going to want a website to establish your credibility.  If you''re co-opting or transitioning your existing donor site, it''s time to de-emphasize the ''money talk'' and emphasize vision, community involvement, and recruitment. You''ll write new content addressed not to the community at large, but to people that you''re meeting personally. Bury the donor page in the menus or hide it from the menus so that only donors with the link can find it.  If you''re leaving the donor site running, you can launch another website at this point. But who wants to manage 2 websites?  Stage 3: Your Community  Several months before your digital launch or grand opening of in-person worship gatherings, you''ll need to transition the website to its permanent audience: your community. That is covered in more detail in the subsequent PlanterPlan task  <a href="/projects/project-tasks/[[project_id]]/all-tasks/584">Publish your website</a> .', 'Decide whether to keep your donor site running and start a 2nd website, or transition your one site to the new audience.  Write basic content around vision, community involvement and recruitment.  Publish the new content at the new domain name just established for your church.  Have a friend test and proofread the site.  This task is complete when the 1-page website is published and tested.', 'template:  ', 3, 'todo', 73, 14, '{}'::jsonb),
  ('41130810-5655-5afc-900f-d3e6d7a3cbcf', '1299144e-2e6b-55f2-a44b-c5b4ea8ace63', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set up email capture system on church website', 'Install a form and/or popup on your website to encourage visitors to leave their email address.', 'Getting someone to visit your website can take quite a bit of effort, but that should only be another step toward getting more connected. It would be a shame if they visit your site and don''t identify themselves, provide contact information, or otherwise take a next step in getting connected.  Offer Something  Think through what would encourage a website visitor in your context to give you their email address. Your form might say:  let me know about upcoming events  let me know about upcoming community service opportunities  send me your monthly newsletter  download free parenting guide (regarding parenting challenges in your context like drugs, porn, gangs, cyber bullying, etc)  download free spiritual guide  You get the idea. Just be sure you deliver on what you''re offering them!', 'Create a plan for getting email addresses.  Create the resource, etc. so you can deliver on your promise.  Create the signup form or popup on your website.  Use an email account you own to test the signup process.  This action is complete when you have published and tested the email capture system.', 'template:  ', 4, 'todo', 73, 7, '{}'::jsonb),
  ('77f4353e-4f92-534f-9884-f847709d1d68', '1899b6fc-eea7-5813-9b30-fc5a2e8d5cbc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this Launch Strategy overview', 'Understand what a Launch Strategy document is and how it helps you.', 'The Launch Strategy document is something like a business plan or battle strategy. The process and discipline of creating this document will spark new ideas and reveal flawed assumptions. The document itself can be used to raise major funds from savvy donors who want to know that you''ve done your homework. And it will crystallize your thinking about various aspects of the church plant.  It is like a Launch Vision booklet, but is more detailed with less color and fewer images. It''s typically a 12+ page description of how you''re going to plant the church, an initial manifesto of why and how you''ll go about it. We''ll give you a template to make the task easier.  Will everything turn out exactly as you''ve strategized? No, but,  "In preparing for battle, I have always found that plans are useless, but planning is indispensable." -Dwight D. Eisenhower, US President & planner of the D-Day Invasion of Normandy', 'Subsequent PlanterPlan tasks will walk you step-by-step through the process of creating your Launch Strategy document.  Read the description above.  Review sample Launch Strategies from other church planters.  This action is complete once you''ve read the brief description and reviewed at least 1 sample Launch Strategy.', 'template:  2020-12-16 changed Due in # Days from 35& to 51& & Duration from 28& to 37& --pb&  ', 0, 'todo', 28, 1, '{}'::jsonb),
  ('b6f37dba-3c97-5911-90e3-0e434f980ddc', '1899b6fc-eea7-5813-9b30-fc5a2e8d5cbc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about crafting a Launch Strategy', 'Open a conversation with your coach about creating a Launch Strategy document.', 'The Launch Strategy document is like a business proposal, the kind of thing you would take to the Shark Tank to pitch venture capitalists on investing in a new business.  You need to have a strategy that is concrete enough to execute. Creating a Launch Strategy document disciplines you to make important decisions and choose language to communicate your strategy. It''s going to be a lot of work.  Sample issues to process with your coach:  Hidden obstacles that will stall completion  How the coach used his/her Launch Strategy document in practical ways  What not to include or say in the Launch Strategy  How much time to commit to creating a Launch Strategy', 'This action is complete when you have called your coach about crafting a Launch Strategy document.', 'template:  New Milestone  2018-05-07 added& google& doc template version --pb  2019-12-03 content validated --pb ', 1, 'todo', 35, 7, '{}'::jsonb),
  ('0e219cb1-e0b0-5f19-995b-556254711a18', '1899b6fc-eea7-5813-9b30-fc5a2e8d5cbc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Launch Strategy document', 'Create a detailed document that lays out the various strategies that will be used to launch the new church.', 'A Launch Strategy document will be a 12+ page detailed description of your approach to planting the new church. The document itself may prove very helpful in the fundraising process, but the exercise of working through each item below will better prepare you to actually plant the church.  The Launch Strategy contains the following sections:  Vision, mission & values  Target area  Opening Day expectations  Timeline  Budget  Key strategies  PlanterPlan will walk you through crafting each of these sections.', 'Download Passion for Planting''s  Launch Strategy Template  (<a href="/resources/item/144">MS Word</a> or <a href="/resources/item/365">Google Doc</a>).  Work through each of the sub-tasks in PlanterPlan, filling in the corresponding section of the template as you go.  Send the document to your coach for review & feedback.  This action is complete when you have sent your Launch Strategy to your coach.', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2019-02-12 changed "philosophy of ministry document" to "vision frame" --pb  2019-12-03 content updated --pb ', 2, 'todo', 62, 21, '{}'::jsonb),
  ('d5acf3b8-2518-5f49-b08c-1f7ab7757600', '1899b6fc-eea7-5813-9b30-fc5a2e8d5cbc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm planter''s Launch Strategy', 'Review the planter''s Launch Strategy document to provide feedback and ensure that it covers the bases.', 'The Launch Strategy document is the culmination of an entire Milestone worth of tasks in PlanterPlan. It is the business plan for launching the new church.  It should incorporate all of the following:  Vision, mission & values  Target area  Opening Day expectations  Timeline  Budget  Key strategies', 'Review the Launch Strategy document.  Provide feedback to the Planter.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Launch Strategy document.', 'template:  2018-04-20 new task --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 56 to 36 & Duration from 7 to 14 --pb&  ', 3, 'todo', 62, 7, '{}'::jsonb),
  ('18690b16-c66a-5e46-bc15-3000c736ea7b', '1bdf3779-fc16-5f80-aba0-ce618dc1e8f0', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Order a banner for events', 'Design and order a banner to create brand awareness at events.', 'Buy a banner to use at events you join or host. It helps with visibility and begins to establish the church''s identity in the community.  The banner should be generic enough so you can use it at any event.  Basic banner types are:  vinyl banner (make sure there''s a place to hang it at the event!)  flag or sail banner  A-frame or sidewalk sign  At a minimum, the banner should include your logo. If you have a website up, you should include your website address, too.  Church Sign Vendors  Here are some companies that have served our planters in the past:  <a href="https://store.groupimaging.com/">Group Imaging</a>  <a href="https://outreach.com/Church-Banners/?ref=TopNavJS">Outreach Marketing</a>', 'Browse sign companies to determine what type of sign to use for events.  Work with your graphic artist or the sign company to design the banner.  Have the banner printed.  This action is complete when a banner for events has been ordered.', 'template: standard  2017-10-27 content updated --pb  2019-12-10 content updated --pb  2020-12-14 changed Due in # Days from 112& to 128& & Duration from 14& to 7& --pb&  ', 0, 'todo', 127, 7, '{}'::jsonb),
  ('fdc5f657-57fe-588f-8f4d-e43f828f9ad3', '1bdf3779-fc16-5f80-aba0-ce618dc1e8f0', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine how to get the word out about outreach events', 'Create an intentional plan to get the word out to the community regarding outreach events.', 'Advertising outreach events serves two purposes: First, it will draw more people to the event so they can meet your people. Second, it will make people who don''t come to the event aware of you and your church. Either way, it may help anyone who gets word have a good first impression about the church because they see you are active in the community.  For events that you host or plan a major role in, determine to get the word out both online and offline.  Create a goal to hit for each event, such as:  post and promote the event on Facebook, and  post 50 fliers in local business windows, and  set up A-frame street signs, and  send out photocopied mailers in the community  There are lots of things that you can do to get the word out about each event:  publicize on the church website  send out a church e-mail blast  include it in the preview service bulletin  encourage your team to share it on social media  post it on community calendars  submit press releases  submit it to local radio as a public service announcement  Most of these methods are free. Create a simple publicity checklist of the tools that will be used for each event.', 'Brainstorm all the methods you might regularly use for getting the word out about events.  Research the cost, timeline, and feasibility of each method.  Create a publicity checklist that will be used for every event.  Customize the checklist for each event as appropriate.  Put the checklist into the hands of whoever is responsible for the event(s).  This action is complete when the person responsible for planning each event has the publicity checklist and understands what expectations you have for getting the word out about the event in the community.', 'template: standard  2017-02-16 content updated --pb  2019-12-10 content updated --pb  2020-12-14 changed Due in # Days from 125& to 128 --pb&  ', 1, 'todo', 127, 7, '{}'::jsonb),
  ('1555737d-3f4f-5038-9c6d-c99e1cebba65', '1bdf3779-fc16-5f80-aba0-ce618dc1e8f0', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine outreach equipment needs and purchase timeline', 'Plan ahead to purchase or rent any special equipment you''ll need for your outreach event(s).', 'Depending on what you have planned, you may need special equipment for outreach events. It could be anything from commercial popcorn machines to bounce houses.  Equipment can either be borrowed, rented, or purchased. Depending on how many times you''re going to need the equipment, it may be better to buy it outright rather than keep renting it. For example, a commercial popcorn machine may cost $100 to rent and $1,000 to buy. It will only take 10 uses for the machine to pay for itself.  Also consider in your decision where you''ll store the equipment. Maybe you''d like to buy it but have no place to store it.  For ideas on kinds of special events equipment to purchase, check out the <a href="/resources/item/74">Church Plant Equipment List</a>.', 'Review each event to determine what special equipment may be needed.  Get price estimates and how much lead time you''ll need to rent or purchase each piece of equipment.  Decide what equipment to purchase.  Make sure it''s included in the budget.  Add the equipment to your list of equipment to purchase.  This action is complete when you have identified equipment needs and a purchasing timeline to support your outreach events.', 'template: standard  -- ok; verified by& amg  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2018-02-16 content updated --pb  2020-01-13 content updated --pb  2020-12-14 changed Due in # Days from 126& to 130& & Duration from 7 to 21& --pb&  ', 2, 'todo', 127, 7, '{}'::jsonb),
  ('f2467c71-18a5-5051-8258-66f3ba5c50c1', '1bdf3779-fc16-5f80-aba0-ce618dc1e8f0', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Select and schedule outreach events', 'Put specific outreach events and service projects on the calendar and in the budget.  You won''t do what you don''t plan', 'The list of possible outreach/service events is way bigger than your church will be able to accomplish. It probably wouldn''t take you very long to make a list of over 200 different opportunities. You need a filter through which to decide what events to actually pursue.  Here are a few considerations in developing your filter:  Understand your target demographic and their felt needs  - For example, if your target is young families with children, Bingo nights are probably not the right answer.  Understand what other churches and organizations are already doing  - Establish your own niche. Don''t try to duplicate what is already being done well.  Understand the reputation you are trying to establish  - You will become known to your community as the "  church". Outreach events will shape how people think of you. That''s your brand. You may be known as the fun church, the legalistic church, the service oriented church, the church with the big building, or something else; but you will have a reputation. Use outreach events to build that reputation.  Determine the intended size and/or reach of events  - Some events are quick and easy to pull off. They don''t take a lot of time and effort; others do. Obviously there is a trade off: you might be able to do 10 small neighborhood events for each large regional event. However, you will get 10x as many people and name recognition with a regional event as you will with a local neighborhood event.  Plan a balanced mix of different size events. For example, you may plan one large regional event the weekend before launch Sunday. In the three months prior to launch, you may have one community event each month. In addition to these community and regional events, you may challenge your launch team to take ownership for local neighborhood events.  There is no shortage of great outreach event ideas. Ask around your ministry circles and review Passion for Planting''s <a href="/resources/item/199">Sample Outreach Ideas</a>. Wherever possible, meet with local community leaders to discuss their knowledge of the community and which events may be most strategic.  Review these lists and add additional potential events based on your knowledge of the target area. After a thorough review, consolidate the list to include only those items which are strong possibilities for your target area. This process of removing items from the list will be largely driven by your personal preferences and understanding of the target area. If you have trouble narrowing the list down, use the <a href="/resources/item/80">Outreach Event Selection Worksheet</a>.  Each church will earn a reputation in the community. Choose outreach/service events deliberately to help shape and form a positive reputation.  Every event on your shortlist will not necessarily come together. Think of it as a ''wish list'' of events.  Avoid events which are already common in the area. For example, if three other churches already have successful fall festivals, do something different in the fall, or maybe use a festival concept at different time of year.  Although the schedule may change over time, it is super helpful to tentatively schedule events as early as possible (even before you are certain about them). This will give you the opportunity to pray through the calendar and consider what types of events may be successful during specific times of the year (back to school, summertime, Holidays).', 'Grab your list of events and service projects already happening in your community.  Review the <a href="/resources/item/199">Sample Outreach Ideas</a>. Brainstorm additional ideas to add to your list.  Get input from your launch team and add those to the list.  Identify existing events being conducted by the community and decide whether to pursue participation in these events (e.g., sponsoring kids programming at a community celebration).  Use the filters above to narrow the list down.  Select specific events consistent with the goal you set for how many to do. Do not worry about getting exactly the right events. It''s OK to change a specific event later. Put them on the calendar now as place holders to ensure that you do an event during that time frame.  Tentatively select dates for each event and put them on the church calendar.  Identify a budget for each event (rough estimate, not exact numbers).  This action is complete when you have developed an initial schedule of events.', 'template: standard  2012-12-02 content updated --pb  2020-12-14 changed Due in # Days from 105& to 114& & Duration from 14& to 7& --pb&  ', 3, 'todo', 134, 14, '{}'::jsonb),
  ('ea1d2539-8db1-53e3-8aa4-582f1d582e09', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Plan downtime for move', 'Schedule time in your calendar to take care of everything associated with moving to your target community.', 'Inevitably, moving takes more time than you plan for. There''s the packing of boxes, scheduling a moving truck, forwarding mail, getting new license plates and driver''s license, unpacking, etc. Rather than stressing about what you are not accomplishing, set aside days on the calendar to take care of all the moving details. Schedule other church planting tasks to be done later.  You should try to live within your target area. Avoid living in a much nicer home/neighborhood than the average family you will be reaching.  There is also no better way to begin forming a core group on-site than through relationships with neighbors. You may consider renting a home or apartment in the area prior to buying in order to gain a better understanding of the area and where your target demographic lives.', 'Determine your move date.  Estimate reasonable time required for move (both packing and unpacking at least one to two weeks where you plan not to work).  Add moving dates to the church calendar.  Review your Launch Plan schedule to determine schedule conflicts.  Adjust schedule as necessary to provide adequate time for move.  This action is complete when you have scheduled time off to move.', 'template:  2020-01-24 content updated --pb  2020-12-11 changed Due in # Days from 56 to 7 & Duration from 14 to 7 --pb ', 0, 'todo', 6, 7, '{}'::jsonb),
  ('96d7c5d6-38bd-5847-9f1d-3310480c2adf', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about personal accountability', 'Open a conversation with your coach about your own personal accountability systems and structures.', 'Every Christian needs to have accountability. You are no exception. Too many pastors have failed morally or otherwise, in part, because they never put good accountability in place.  Sample issues to process with your coach:  How to balance family and ministry time, especially evening meetings  Leaving margin in your calendar for sabbath and renewal  Staying spiritually alive amidst the busyness of planting  How to remain engaged in meeting people who do not know God  Leadership reproduction accountability mechanisms  Creating a culture of accountability among staff', 'This action is complete when you have called your coach about accountability.', 'template: standard  2017-05-30 content updated,  audience changed to coach  --pb  2019-11-22 content updated --pb  2020-12-11 changed Due in # Days from 53 to 14 & Duration from 7 to 1 --pb ', 1, 'todo', 13, 1, '{}'::jsonb),
  ('2b905d53-e301-5a8c-8076-d8fceb4ae839', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop a personal accountability plan', 'Create an intentional plan to support your own personal accountability.', 'Its the fourth quarter of the Super Bowl. Your team is driving down the field for the go-ahead points. Your right guard has a broken hand and on the last play he went down with a knee injury. With no one to back him up he stays in the game. The defense comes to the line and is showing blitz. Can you take a guess at who they are coming at with the bull rush? It doesn''t take a football expert to know that right guard is going to be tested.  In the same way, the forces of darkness will test your spiritual life. Part of being human is to have a bent towards sin. It is why Jesus died for us. Each of us has our own unique struggles with sin. It is what Paul called  the thorn in his side .  But Scripture teaches us that,  "No temptation has seized you except what is common to man. And God is faithful; he will not let you be tempted beyond what you can bear. But when you are tempted, he will also provide a way out so that you can stand up under it."  1 Corinthians 10:13 NIV .  One of the ways that God provides a way out is through a plan of accountability. This plan will function as a safeguard. You wouldn''t play pro football without pads and a helmet, and you shouldn''t try and live the Christian life without accountability.  Your personal accountability plan should include the following topics:  Sabbath rest:  This one made it in the 10 commandments, so its probably important.  Honor God by resting. What day will you rest? Who will hold you to it? How will you remind yourself and protect the day?  Personal Relationship with God : Take time to write out your habits for spiritual disciplines.  What are your areas of strength? What areas do you need to improve? What steps can you take to grow closer to God through disciplines?  Family Life : If you are married and if you have kids, they are your first church.  What healthy boundaries will you put in place to ensure you are spending time with them? How will you fulfill your responsibilities to them?  Building relationships with those that don''t know God yet : Your people won''t follow where you don''t lead.  What are you personally doing to build bridges with those who don''t know God? How are you putting yourself in places to come in contact with not-yet-believers?  Reproducing leaders and teams :  Who are your "disciples"? Who are the leaders you are investing in to build the church?  Launch Plan :  Who is holding you accountable to complete the tasks of the launch plan to ensure a healthy church launch?  Internet Accountability :  What Internet monitoring or filtering software are you using? Who gets the reports?  (see subsequent PlanterPlan task for help)  Mentoring :  Who is your mentor? Who is the person whom you confide in about your temptations and weaknesses? Who is your Nathan that will call you out if you fail?  The Team :  How will you provide accountability for your staff and other leaders in the church?', 'Read through each of the areas above and create a written plan for each topic.  Brainstorm additional areas in your life for which you need to be held accountable.  Add a written plan for each of those areas.  Send the plan to your coach or mentor for review and feedback.  This action is complete when you have developed a written plan of accountability.', 'template: standard  2017-09-26 content validated --pb  2019-11-22 content validated --pb  2020-12-11 changed Due in # Days from 60 to 28 --pb  2022-11-21 updated links --sc ', 2, 'todo', 27, 7, '{}'::jsonb),
  ('d74759a7-3571-5af4-a82a-65fb5ad55123', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Install an internet filtering or accountability app', 'Install internet monitoring or filtering software to set a good example and to help with your own online integrity.', 'Pornography is predatory. Even if you haven''t had an addiction in the past, the Enemy would like nothing better than to get you caught up in porn during the crazy-difficult season of planting a church. You need to have an extra layer or two of prevention on all of your electronic devices.  A secondary reason to protect all your devices is to set a precedent for your staff & key volunteer leaders. Also, some of the services below give you the side benefit is having documentary evidence/history if you''re ever accused of porn use.  There are 3 main avenues to secure your devices:  Accountability & Filtering Software  Accountability software doesn''t prevent a user from viewing inappropriate content, but instead sends a report to an accountability partner. Filtering software attempts to prevent the user from visiting those sites, and will also send reports.  Current best options (Fall 2019):  <a href="https://x3watch.com/x3watch-plan-features/?v=2.1">X3Watch</a> - $70/yr individual or $100/yr family plan  <a href="https://accountable2you.com/pricing">Accountable2You</a> - $70/yr individual, $120/yr family, or $120/yr + $67/yr per user group license  <a href="https://everaccountable.com/plans/">EverAccountable</a> - $70/yr individual or $100/yr family plan  <a href="https://www.covenanteyes.com/how-it-works/">CovenantEyes</a> - $192/yr group (10 users)  Parental Control Software  These are really designed to help parents with the kids'' online activity. This could serve a 2-fold purpose if you set your spouse up as the admin and you don''t have the password.  Current best options (Fall 2019):  <a href="https://www.qustodio.com/en/premium/">Qustodio</a> - $55/yr for 5 devices  <a href="https://www.netnanny.com/alt/">NetNanny</a> - $55/yr for 5 devices  <a href="https://www.bark.us/#pricing">Bark</a> - $99/yr for unlimited devices  Router-Based Filters  These are economical because you don''t have to purchase or install an app on every connected device. Any device that connects to the router gets only filtered internet.  The downside is that as soon as you leave the house or decide to use cellular data, the router is circumvented. Some of the services below are beginning to write mobile apps to address that.  Consider using a router solution along with one of the other solutions above.  Current best options (Fall 2019):  <a href="https://www.bark.us/learn/router-limits-bark-home/">RouterLimits</a> - $80 for the router (1-time), free subscription  <a href="https://meetcircle.com/">Circle</a> - $129 for the router and first year (1-time), $120/yr for 10 devices  <a href="https://cleanrouter.com/pricing/">CleanRouter</a> - $180 upgrade option (1-time), requires $120/yr basic subscription or $180/yr premium subscription  None of these solutions is bullet-proof: a savvy user will be able to defeat or circumvent the app. And you still need to install at least one of these safeguards on every internet-connected computer, tablet & phone.', 'Choose an accountability software and install it on all computers you use.  Install it on all your phones and tablets.  If you chose a monitoring software, ask an accountability partner''s permission to receive your reports.  This action is complete when you have installed internet filtering or accountability software.', 'template: standard  2019-11-22 content & links verified and updated --pb  2020-12-11 changed Due in # Days from 60 to 28 --pb ', 3, 'todo', 27, 7, '{}'::jsonb),
  ('3e86b95d-a95d-53e9-bb75-a660ad7f33d2', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Initiate a mentoring/accountability relationship', 'Find someone who is more interested in supporting you than in the progress of your church plant project.', 'You''re about to face many trials and temptations. Being a pastor can be a very lonely job.  But it doesn''t have to be. Seek out a mentoring relationship with someone who understands the unique trials a church planter faces. This person should be someone you trust and someone who can speak truth and wisdom into your life. You should feel like you can tell the mentor anything and that he will treat you with love and grace.  "Though one may be overpowered, two can defend themselves. A cord of three strands is not quickly broken."  Ecclesiastes 4:12 .', 'Brainstorm a list of people who could serve as your mentor. If needed, ask others whom a good candidate might be.  Ask that person to serve as your mentor.  Give them a copy of your plan of accountability.  Set up a regular schedule to talk.  This action is complete when you have a regular schedule in place to talk to you mentor.', 'template: standard  2017-09-26 content validated --pb  2019-11-22 content updated --pb  2020-12-11 changed Due in # Days from 60 to 28 --pb ', 4, 'todo', 27, 7, '{}'::jsonb),
  ('b69848e7-de3e-593b-af1c-3165bf6d0e10', '1e8e529f-5a19-5700-9f20-e78b72bc7a76', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm personal accountability plan', 'Review the planter''s accountability plan and provide feedback where necessary.', 'After completing the accountability plan, the planter will send it to you for review. Read and review the plan and ensure that it covers the essentials, including:  Sabbath rest  Personal relationship with God (including spiritual disciplines)  Family Life  Building relationships with those that don''t know God yet  Reproducing leaders and teams  Executing the Launch Plan  Internet accountability  Mentoring  Staff accountability', 'Receive an accountability plan from the church planter.  Read and ensure the above areas have been addressed by the plan.  This action is complete when the coach has reviewed and affirmed the planter''s accountability plan.', 'template: standard  2017-09-26 content validated --pb  2019-11-22 content validated --pb  2020-12-11 changed Due in # Days from 60 to 35& --pb ', 5, 'todo', 34, 7, '{}'::jsonb),
  ('36725a0f-46fd-581c-82a0-2623b072880a', '2ae93268-1d03-5256-9aac-68287a289617', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Build out groups in your church management software', 'Keep track of how many groups you have and utilize advanced groups functionality in your church management software.', 'All modern church management software (ChMS) platforms come with a groups module or feature. You will be able to create each group and add details like time, location, etc. You will also be able to assign its leader(s) and members.  In the short run, you may be able to remember all of your current groups in your head. But that system is not scalable in the long run. Plus, many ChMS platforms provide extended functionality that you need to start practicing now, such as:  taking attendance  recording and sharing prayer requests  summary reports from group leader to their coach  group finder plugin for your website', 'Build each current and planned group in your ChMS.  Decide which features to use and train groups leaders in using them.  This action is complete when you have all of your groups built in your church management software.', 'template: standard  2018-03-29 content updated --pb  2018-11-19 content updated & moved to subtask of #695 Issue Written Assimilation Strategy from #679  2012-12-02 content updated --pb  2020-12-16 changed Due in # Days from 137& to 155 --pb&  ', 0, 'todo', 104, 14, '{}'::jsonb),
  ('715ff332-df9a-54e1-9cc0-0ed6d3242e1b', '2ae93268-1d03-5256-9aac-68287a289617', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Select group curriculum or content', 'Make strategic decisions about the content of the groups.', 'There are lots of options for the curriculum or content of the groups. Some of that may be driven by the kind of group in question. Common approaches include:  Have the entire church going through the same curriculum simultaneously  Have groups review the sermon and go deeper into the text  Write your own curriculum in-house  Use a simple Bible study framework (ex: <a href="https://soapstudies.com/">SOAP</a>)  Allow small group leaders to choose curriculum based on the felt needs of the group  etc.  If you''re going to let leaders choose their own curriculum, consider creating an approval process or publishing a list of approved resources. Group curriculum resources from theological camps different than yours are readily available online.', 'Decide on the format or content of each category of group you''re starting.  Include it in your  Church Groups Strategy  document.  This action is complete when you have articulated the content or curriculum of each group type.', 'template: standard  2019-11-26 content updated --pb  2020-12-11 changed Due in # Days from 154& to 67 --pb&  ', 1, 'todo', 73, 14, '{}'::jsonb),
  ('9134ad8e-fb51-530a-939f-2c8fe530e700', '2ae93268-1d03-5256-9aac-68287a289617', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Schedule first group leader training', 'Put the first group leader training on the calendar to proactively begin growing new leaders towards multiplying the groups.', 'Once a training plan has been developed and a job description has been written, set the wheels in motion to train new leaders.  When  you schedule the first training will depend some on the leaders and potential leaders God has provided. Anticipate the need to multiply groups and leaders, then put a training event or turbo group on the calendar to be ready.', 'Identify potential small group leaders.  Have the ICNU conversation with each one.  Based on who you have and how many groups you''ll need, put leader training on the church calendar.  Invite the leaders to the event.  This action is complete when you have invited leaders & potential leaders to the first training event.', 'template: standard  2017-12-29 content updated --pb  2018-03-29 "small groups" changed to "groups" --pb  2019-12-03 content updated --pb  2020-12-14 changed Due in # Days from 168& to 90& & Duration from 7 to 30& --pb&  ', 2, 'todo', 73, 14, '{}'::jsonb),
  ('77522df1-dcb0-5637-9265-2fbee1d92a37', '2ae93268-1d03-5256-9aac-68287a289617', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Start first group(s)', 'Hold the first meeting of the first group and set the DNA of what groups will be like at the church.', 'You''ve dreamed up strategies for how to run groups at the new church. Now is the time for the rubber to meet the road!  Start with the end in mind and be very intentional about what happens at the first group meeting. This becomes the precedent for how other groups are started.', 'Schedule a time and place for the first group meeting.  Determine what the group leader will facilitate or lead during the meeting.  Begin meeting on a regular, ongoing basis.  This task is complete when the first group begins meeting on a regular basis.', 'template: standard  2017-05-19 changed plan to strategy --pb  2017-12-26 content updated --pb  2012-12-02 content updated --pb  2020-12-16 changed Due in # Days from 147& to 162& --pb  ', 3, 'todo', 89, 30, '{}'::jsonb),
  ('d0d01f64-0940-5e33-854f-b9342395440c', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Decide on the worship gathering atmosphere', 'Choose an intentional mood, tone and environment for your worship gatherings.', 'The atmosphere of the worship gathering will have a huge impact on how the unchurched feel about the new church, and even how they feel about God. And it plays into how easy or difficult it is for everyone there to connect with God.  When you visit someone''s home, they can make you feel welcome or unwelcome by the setup of the furniture, the relative cleanliness, and by the things they say and do. Similarly, you need to be conscious of guests and do what makes guests feel comfortable over what makes the church comfortable.  This is an important exercise. Most pastors are wired up more for vision, theory and theology, while the majority of the general population is geared much more toward the tangible and sensory. Plan worship gatherings that intentionally engage people on both levels.  A lot goes into creating the atmosphere, including:  The Physical Environment  Each of these communicate in subtle ways whether you''ve expected guests or not, and whether you expect people to experience God that day or not:  Facility layout - space for people to hang out & chat, how chairs are arranged, how the stage is set up  Outdoor and interior signage - information and context cues for guests  Aesthetics - banners, drapes, backdrops, colors, etc.  Lighting  Aroma - nightclubs and school gymnatoriums may need a little work  Bathrooms - cleanliness, location, comfort  Style of Music  For both background music and the worship songs, does the music style reflect local culture and preference, or does it reflect a churchy preference?  Mood and Tone  Through the things you do and say, the atmosphere of the service can be:  fun and humorous  serious and thoughtful  happy and celebratory  Warm and emotive  etc...  Assumptions  Through the things you do and say, you also communicate in subtle ways who is ''in'' and who is ''out''.  If you provide no explanation or context for the things that are done during the worship gathering, unchurched people will be confused at best or made to feel unwelcome at worst.  In the same way, the little hints dropped from the platform can be confusing or un-inclusive:  "You remember the story of Jesus and the 10 lepers&hellip;" - the unchurched and dechurched probably don''t  "You know how when you''re praying&hellip;" - someone who''s never prayed can''t relate to this  "First Thessalonians 3:12 says&hellip;" - Biblical literacy is very low and some won''t know that this is a scripture reference, or even that scripture is broken down into books, chapters and verses  Alignment is Key  Consider each of these elements and be intentional with each. They should all work together in agreement. How jolting would it be to tell a joke right after a reverent silence cued up by a deep, thought-provoking element?  Don''t feel locked into one mood, but know that the atmosphere communicates the church''s personality and affects how people engage during the gathering.', 'Describe the atmosphere that would connect best with your community and your average target family.  Make intentional decision about each of the items above.  Base your initial sermon series and facility layout on those choices.  Communicate them to the worship leader and others involved in the creative process.  Remind the volunteers and leaders before the service what the feel should be.  This action is complete when you have determined the desired worship service atmosphere for the initial services.', 'template: standard  2017-12-27 content updated, Due in # of Days changed from 208 to 201 --pb&  2020-01-21 content validated --pb  2020-12-16 changed Due in # Days from 208& to 168& --pb  ', 0, 'todo', 160, 7, '{}'::jsonb),
  ('82599f59-14cf-59eb-a139-04318cf24c27', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop framework for typical worship gathering', 'Decide what will go into the typical order of service so that there''s a common understanding and expectation for your teams.', 'There will be lots of people involved in planning and executing the weekly worship gatherings. Having a standard framework allows more people to be included in the process.  You don''t want to get locked into doing the same old thing every week, but you also don''t want all of your teams left guessing from week to week what they''ll have to do. Creating a typical order of service or framework allows you to train your teams, gain efficiencies, and deviate for an intentional purpose.  Common elements of a worship gathering include:  Welcome  Message/Sermon  Worship songs  Announcements  Communion  Offering  Special Element (video or song)  Liturgical Element (responsive reading or scripture reading)  Prayer  But don''t feel locked into  only  doing these things or having to do  all of them  every week.', 'Create a list of all the elements you''ll include in the typical worship gathering.  Decide how much time you''ll typically spend on each element.  Share this with the worship planning team so you can develop a weekly service schedule.  If you use worship service planning software, have a team member build a template based on your framework.  This action is complete when you have finalized the framework of a typical worship gathering.', 'template: standard  2017-12-27 content updated; due in # of days changed from 180 to 208 --pb  2019-08-19 title changed from "Implement Process for Planning Worship Gatherings" --pb  2020-12-16 changed Due in # Days from 168& to 171 --pb  2020-02-25 additional resources subsection added --pb&  2020-01-21 content updated & links validated --pb  2020-12-16 changed Due in # Days from 208& to 168& --pb ', 1, 'todo', 167, 7, '{}'::jsonb),
  ('ab93a7ec-c489-5e51-8fe7-c97a3b7281ba', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Implement collaborative process for planning worship gatherings', 'Create a system for planning worship gatherings that includes other people and provides enough time for collaboration.', 'Regardless of what you include in each worship gathering, you need a process in place that includes the worship leader, projectionist, bulletin designer and anyone else involved in preparing various elements and creative aspects of the gatherings.  Nothing cripples creativity like having no time to create. The process for planning the gatherings should include ample time for creative elements to be crafted or prepared. Don''t wait until Saturday night to provide the sermon topic & notes to the worship leader and the people who will be making up the slides and the bulletin.  Create a calendar that plans out your worship gatherings at least 6 months in advance. Then create a rhythm for reviewing the plan at each week''s creative team meeting. For example, Community Christian Church outlines in their book,  <a href="https://read.amazon.com/kp/embed?asin=B000SEIA2I&preview=newtab&linkCode=kpe&ref_=cm_sw_r_kb_dp_iO4jEbJ0JWK9W">The Big Idea</a>,  that each week they:  Introduce the sermon series roughly 13 weeks out  Plan the gathering that is 9 weeks out  Check the status of pieces being created for the gathering 5 weeks out  Outline the sermon that is 3 weeks out  Review the manuscript of the sermon that is 2 weeks out  Put final touches on the gathering that is 1 week out  Choose a software tool that supports this process. You could use a collaborative spreadsheet (like <a href="https://sheets.google.com">Google Sheets</a>), but the following solutions make your life easier with song databases, volunteer scheduling and more:  Planning Center <a href="https://www.planningcenter.com/services">Services</a>  Church Community Builder <a href="https://pushpay.com/product/chms-software/">Schedules</a>  Tithely CMS <a href="https://get.tithe.ly/product/church-management">Worship Planning</a>  <a href="https://worshipplanning.com">WorshipPlanning.com</a>', 'Decide how far in advance sermon topics & notes will be provided to others involved in the planning process.  Choose a software tool to support the planning process.  Schedule a regular creative team meeting and invite contributors.  This action is complete when you have planned the the first worship gathering using these new processes.', 'template: standard  2017-06-15 content & blog links updated (former post by Furtick expired) --pb  2017-12-27 content re-updated --pb  2018-06-27 new ''additional resource'' added --pb&  2020-01-21 content updated & links validated --pb  2020-12-16 changed Due in # Days from 180& to 168& --pb  ', 2, 'todo', 167, 7, '{}'::jsonb),
  ('875ad838-521b-5735-ad93-388c9278c2e1', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create an evaluation process for worship gatherings', 'Create a system to continually improve your regular worship gatherings.', 'Evaluation is an important part of ministry. Evaluation is the time in where you learn, grow, and better prepare for the next time. Spend time with staff and key leaders every week debriefing the worship gathering. Each element should be evaluated for how well it connected.  There is a spiritual element to the worship gathering that must be evaluated as well. Remember that the goal of the worship gathering is to worship God, make disciple  and preach the good news to not-yet-believers; it''s not to entertain or keep people happy.  The result of a solid evaluation process will be a culture of excellence that cares about the quality of the worship gathering. It also reinforces intentionality in the planning process.', 'Determine the ''win'' for a worship gathering.  Determine which elements will be evaluated and what questions you''ll ask.  Create a reusable worship gathering evaluation form.  Schedule a regular evaluation meeting and invite contributors.  This action is complete when you have invited contributors to the first evaluation meeting.', 'template: standard  2017-12-27 content and links updated --pb  2018-02-09 removed link to PCO Project (product discontinued)  2018-04-20 moved Equipment milestone --pb  2020-12-16 changed Due in # Days from 152& to 183& & Duration from 21& to 30 --pb&  2018-08-21 made child/subordinate to 814 --pb  &  2020-01-20 content validated, LiveWorship& link removed --pb  ', 3, 'todo', 167, 7, '{}'::jsonb),
  ('a68a90c5-6eb2-5eeb-a263-6c9d8a4c9335', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Design a printed or electronic bulletin', 'Create a bulletin/program design that will let newcomers know what to expect throughout the worship gathering.', 'Call it whatever you want, some version of a bulletin is a great way to make guests feel at home. It can also provide them with information about the church and/or upcoming events that may interest them. And it can be a great vehicle for delivering a connection card to everyone.  Using a shell allows you to have professional graphics on the cover but print custom content each week.  In-House Design  Some planters have their graphic designer create a bulletin shell that is a theme for a season or whole year, or one that is simply branded with the church logo. These can be printed in large quantities at a local print shop on online printers like <a href="https://www.gotprint.com/products/brochures/info.html">GotPrint.com</a>  Alternatively, you can print the entire program on plain paper in color or B&W each week. The small disadvantage here is that few if any home printers can print to the edge of the paper, so there will always be a white boarder around any artwork. Bulletins that ''bleed to the edge'' look cleaner and more professional.  Stock Design  A great place to order pre-printed program shells is <a href="https://www.outreach.com/Church-Bulletins/">Outreach Marketing</a>. They provide templates for printing your own internal contents each week.  Electronic  Another option, which can supplement or replace your printed bulletin, is to post it electronically. <a href="https://www.bible.com/events#section1">The Bible App</a> events feature is a great, free tool. There are other tools available, too.  The biggest consideration in going digital is helping people find it. Post it on your website as a menu option that redirects to the electronic bulletin and/or make a vanity URL that will redirect over to your bulletin (ex: www.xyzchurch.com/bulletin). You can also experiment with QR codes on announcement slides. Whatever you do, make it short for ease of thumb typing and simple for ease of remembering.', 'Decide whether or not you''ll use some version of a bulletin/program.  Decide whether to design or purchase a pre-printed program ''shell''.  Enlist the aid of a designer to lay out the internal contents template.  Lay out the content for the first preview service.  This action is complete when the template has been designed and the bulletins are printed or published for your first preview service.', 'template: standard  2020-01-21 content updated --pb  2020-12-16 changed Due in # Days from 208& to 211& --pb ', 4, 'todo', 197, 14, '{}'::jsonb),
  ('f6bf15ec-1aca-5e8f-91b0-e92db0a01741', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a streaming license', 'Purchase a copyright license that covers worship music streamed during your online services, honors Christian composers, and keeps your church in copyright compliance.', 'Rather than the church having to get written permission to perform every piece of music, there are licensing agencies that provide blanket permissions for the church.  United States Copyright Law provides that any music (live or recorded) performed during the course of a regular worship gathering (typically Sunday morning, Wednesday night, etc.) is exempt from copyright licensing.  However, churches are required to clear the copyrights for any music used outside of worship gatherings. That includes, but is not limited to  online streaming of the worship music performed during service .  That''s right: you can''t stream the worship performance from your worship gatherings legally without a copyright license. People watching online aren''t technically at your place or worship, so that falls outside of the freedom of religion exemption.  Providers we''re aware of are:  CCLI <a href="https://us.ccli.com/streaming/">Streaming or Streaming PLUS</a> license  Church Copyright Solutions <a href="https://christiancopyrightsolutions.com/worshipcast/">WORSHIPcast</a> license', 'Determine which license(s) you need.  Obtain the licenses individually or in a bundle.  This action is complete when you have purchased the appropriate license(s).', 'template:  ', 5, 'todo', 127, 7, '{}'::jsonb),
  ('4baa7b2d-ee6b-59f6-943d-e2c64d6cc071', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a copyright license for printed music (CCLI)', 'Purchase a copyright license that covers printed copyrighted material, honors Christian composers, and keeps your church in copyright compliance.', 'As Christians, it is imperative that we and the church respect copyright laws. A copyright license allows a church to reproduce printed music and lyrics in accordance with copyright laws, and honor our brothers and sisters who have labored to create the music.  Rather than the church having to get written permission to use every piece of music, there are licensing agencies that provide blanket permissions for the church.  Printed music and lyrics are protected by copyright law:  song sheets for musicians  printed lyrics in bulletins  projected lyrics on screen (song slides)  Unless you are only going to use music that your church writes itself, you need a CCLI license. <a href="https://us.ccli.com">Christian Copyright Licensing International</a> (CCLI) provides copyright licensing.  Jury Duty  They require reporting of the songs that are being reproduced, but only in a ''jury-duty'' fashion. Several churches are selected each year to participate in a 6-month reporting period where usage reporting is completed online. Other churches are encouraged to keep some kind of record, but will not need to report.  Song Sheets for Your Band  CCLI also offers another very useful service for an extra fee called <a href="https://songselect.ccli.com"> SongSelect</a>. This service provides chord charts and lead sheets online for thousands of worship songs. You can can quickly transpose to any key and then print right from your browser. And you can sync the lyrics right into your projection software. This will save your worship leader tons of administrative time.', 'Purchase a <a href="https://us.ccli.com">CCLI</a> license.  Recommended: Subscribe to the <a href="https://songselect.ccli.com">SongSelect</a> service while obtaining the CCLI license.  This action is complete when you have purchased the CCLI license.', 'template: standard  Pat is more familiar with the latest& processes here - please review/update.&  ----ds  2017-05-26 content updated --pb  2020-12-16 changed Due in # Days from 210& to 213& --pb  2020-01-21 content & links updated --pb  2021-01-26 moved streaming license info to new task specific to streaming --pb ', 6, 'todo', 127, 7, '{}'::jsonb),
  ('17f9cd03-bf55-5e9b-b155-4283b4821618', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a copyright license for performed music', 'Purchase a copyright license that covers music performed outside of worship gatherings to keep your church in copyright compliance.', 'Rather than the church having to get written permission to perform every piece of music, there are licensing agencies that provide blanket permissions for the church.  United States Copyright Law provides that any music (live or recorded) performed during the course of a regular worship gathering (typically Sunday morning, Wednesday night, etc.) is  exempt  from public performance licensing.  However, churches are required to clear the copyrights for any music used  outside  of worship gatherings. That includes, but is not limited to:  canned music played before or after the service  youth functions  banquets/award ceremonies  concert events  Bundled or a la Carte  Consider what copyright licenses you''ll purchase based on your performance needs. Every piece you will use will be covered by one of the following:  <a href="https://christiancopyrightsolutions.com/performmusic/">PERFORMmusic</a> Facilities License (includes all 3 below)  BMI (<a href="https://www.bmi.com/">Broadcast Music, Inc</a>)  ASCAP (<a href="https://www.ascap.com/">American Society of Composers, Authors and Publishers</a>)  SESAC <a href="https://www.sesac.com/">Society of European Stage Authors & Composers</a> are organizations that can assist with copyright licensing', 'Determine which license(s) you need.  Obtain the licenses individually or in a bundle.  This action is complete when you have purchased the appropriate license(s).', 'template: standard  Pat is more familiar with the latest& processes here - please review/update.&  ----ds  2017-05-26 content updated --pb  2020-12-16 changed Due in # Days from 210& to 213& --pb  2020-01-21 content & links updated --pb  ', 7, 'todo', 212, 7, '{}'::jsonb),
  ('fbcb9741-992c-5036-ba26-0aaeb34a1e33', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a copyright license for projecting movies', 'Purchase a copyright license that covers projecting movies and movie clips during services and outreach events.', 'The Federal copyright act provides that videos released  For Home Use Only  (as most videos for sale or rent are) can only be shown in private homes to family and close friends. So you can''t just rent something from Redbox and shoot it up on a screen at a church event or worship gathering.  The following licenses are available:  <a href="https://us.cvli.com">CVLI</a> (annual blanket copyright coverage for titles from 1,000+ producers)  <a href="https://www.swank.com/religious-organizations/">Swank</a> (for a single full-length movie showing)', 'Determine which licenses are required.  Obtain the licenses.  This action is complete when you have selected and purchased the appropriate license(s).', 'template: standard  2020-12-16 changed Due in # Days from 245& to 71& & Duration from 196& to 21& --pb&  ', 8, 'todo', 212, 7, '{}'::jsonb),
  ('845dffe3-f6e5-5856-ab40-c67036453f7b', '37145453-8c14-5a2d-a990-c8a7d677b1fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Conduct the first preview service', 'Conduct scheduled preview services (worship gatherings) to create excitement with the launch team and community, and to practice everything prior to a full public launch.', 'A prior PlanterPlan task walked you through scheduling preview services. Now it is time to pull them together.  During the preview service, describe what they''re about from the platform so that you''ll get more grace and patience when something inevitably goes wrong. That''s why you''re doing this now instead of figuring out these weak spots on Launch Sunday  For the first preview service, do your level best to have  all  the systems, equipment and teams in place that you would for the Opening Day of worship gatherings. If some piece is simply not coming together at the last minute, then confess it from the platform and set an expectation of when it will be added.  Who Should Be Invited  Friends, family, neighbors and co-workers could and should be coming to these previews.  You may or may not want to advertise the preview services directly, but you should coach & encourage your team to invite people through word-of-mouth.  An Important Opportunity  Have a clear call to action or next step for everyone, especially guests, to take. Don''t miss the opportunity to build some excitement and relational momentum.  Debrief  Practice your evaluation process to record learnings and jot down things that need to be changed or purchased before the next preview service. Debrief the Launch Team in a way that is exciting and congratulatory.', 'Train and empower all ministry teams to fully execute at the preview services.  Encourage Launch Team members to invite friends, family, neighbors and co-workers.  Conduct the first full preview service.  Get feedback through your worship gathering evaluation process.  Debrief your Launch Team and celebrate this major milestone!  This action is complete when you have debriefed the launch team after the first preview service.', 'template: standard  2017-12-28 content updated --pb&  2020-01-24 content updated --pb  2020-12-16 changed Due in # Days from 237& to 241& & Duration from 27 to 28& --pb&  ', 9, 'todo', 210, 30, '{}'::jsonb),
  ('07dc18da-7ceb-5e84-9aca-a4ae068163e9', '3b97d06a-7109-5eb3-87df-1f4a87e71aad', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this outreach overview', 'Brief yourself on what goes in to a cohesive outreach strategy and the process you''ll follow to create one.', 'The tasks in this milestone will walk you step-by-step through crafting an outreach strategy that inspires your people to serve, makes a real impact in your community, and is sustainable.  Your outreach strategy will contain:  A brief philosophy of outreach  A summary description of your community  Brainstorm of potential events to participate in or host  Goals for how many and what kind of events  A plan to debrief events  A pre-launch schedule of events you commit to  The decisions you make here and the kinds of outreach you do in the first year will have a lasting impact of your church''s culture and its reputation in the community.', 'Watch the Passion for Planting training video "<a href="/resources/item/201">Outreach - Starting Conversations</a>" featuring Ed Stetzer.  This task is complete when you have read the content above and watched the training video by Dr. Ed Stetzer.', 'template: standard  2017-05-31 content updated, audience changed to coach --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 112& to 114 --pb&  ', 0, 'todo', 107, 1, '{}'::jsonb),
  ('bef2f744-19d0-5ddd-b0fd-feba4280049c', '3b97d06a-7109-5eb3-87df-1f4a87e71aad', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about outreach', 'Open a conversation with your coach about outreach.', 'Outreach is the ministry where the church lives out its values and beliefs in the community. Spend time with your coach thinking through how to strategically reach out in the community.  Sample issues to process with your coach:  How to discover/discern the best ways to serve in the community  The difference between outreach and community service  Outreach and building your launch team  Strategic community partnerships  Sustainable pace of events', 'This task is complete when you have called your coach about outreach.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' and updated hyperlinks --pb  2018-02-16 updated content --pb  2018-06-01 additional resources subsection added,& gdoc& template added --pb  2020-02-26 outreach ministries list added --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 125& to 121& & Duration from 7 to 30& --pb&  2021-10-21 added Dad Camp --pb ', 1, 'todo', 113, 7, '{}'::jsonb),
  ('079b13eb-7edf-56b1-aaa7-de97eab549b4', '3b97d06a-7109-5eb3-87df-1f4a87e71aad', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft an Outreach Strategy', 'Create a strategy for outreach in your community that both demonstrates your church''s values and creates culture in your church.', 'Your written outreach strategy is simply the culmination of each of its subtasks. It will be a document that you can share with Launch Team members to help cast the vision for what you are trying to accomplish and to help individual members take ownership for the strategy.  Your outreach strategy will contain:  A brief philosophy of outreach  A summary description of your community  Brainstorm of potential events to participate in or host  Goals for how many and what kind of events  A plan to debrief events  A pre-launch schedule of events you commit to', 'Download Passion for Planting''s  Outreach Strategy Template  (<a href="/resources/item/200">MS Word</a> or <a href="/resources/item/375">Google Doc</a>)  Fill in the blanks to craft your own Outreach Strategy.  Add each scheduled event to your church calendar.  Send the written outreach strategy to the coach for review.  This task is complete when you''ve written down your strategy to reach out to your community.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2018-02-16 content updated, additional& resources added --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 125& to 121& & Duration from 7 to 30& --pb&  ', 2, 'todo', 134, 44, '{}'::jsonb),
  ('58532d83-087e-5e40-9651-7c37385a8a7e', '3b97d06a-7109-5eb3-87df-1f4a87e71aad', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm Outreach Strategy', 'Review the planter''s outreach strategy and provide feedback on the ideas for serving and building bridges in the community.', 'Your planter''s outreach strategy needs to be well thought through and coordinated in advance. The plan should be focused and intentional, rather than left to chance. It needs to:  be appropriate to their target community and target family  coordinate events and efforts to work together  support the vision & values of the church plant  The written outreach strategy document should include the following elements:  A brief philosophy of outreach  A summary description of his community  Brainstorm of potential events to participate in or host  Goals for number & types of events  A plan to debrief events  A pre-launch schedule of event commitments  Read over the written outreach strategy and provide feedback to the planter. Specifically, affirm the number of outreach/serving events planned. Spend time talking through the strategy. Provide wisdom and insight for effective community outreach.', 'Read over the outreach strategy provided by the planter.  Affirm his philosophy of outreach.  Affirm the goals for number and types of events.  Affirm the pre-launch calendar of events.  Affirm that the budget supports the scheduled events.  Affirm to the Network Partners in the coaching report that the planter''s strategy is sufficient.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Outreach Strategy.', 'template: standard  Need to update the process on how to add new tasks to a document. Does the text exist somewhere within the database already?  Resources # 78 & 79& --am  I added this text on how to add tasks. --sc  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2019-12-10 content validated --pb  2020-12-16 changed Due in # Days from 139& to 135& & Duration from 32& to 14& --pb&  ', 3, 'todo', 127, 7, '{}'::jsonb),
  ('cb4ea885-d86b-5df1-90f9-f39d2ecab5fa', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this leadership multiplication overview', 'Understand what''s at stake in multiplying leaders in the church plant.', 'Don''t complain about not being able to find enough good leaders. If you don''t want to find yourself leading alone, you need a farm system to grow more leaders around you.  "Everything rises and falls on leadership." - John C. Maxwell  The  free agent  era of church leadership is dying. Not that it probably ever really thrived. Because it usually worked this way: recruit a high-capacity leader from outside of your organization, use them up, spit them out, and then find another.  A farm system identifies untapped potential in people within your organization, invites them to grow (and embraces still-learning levels of execution), equips and coaches them, and unleashes them into their calling.  Which of those cultures would you rather be a part of?  Yeah, a farm system takes longer, but you end up with an ongoing supply of better, more bought-in leaders that  are  the DNA of the church.  Everything that happens in a volunteer-based organization like a church requires leadership. Your church needs disciple-making leaders, small group leaders, serving team leaders, and so many more.  And your church needs to grow and reproduce teams, groups, sites and church plants. How will that happen without leaders?', 'Read the content above.  Commit to creating a culture of leadership empowerment and reproduction.  This task is complete when you have read the content of this overview.', 'template:  2019-12-03 due date fields found empty -pb&  ', 0, 'todo', 48, 1, '{}'::jsonb),
  ('88a7fa01-6319-55bf-83e9-3c278a319367', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about multiplying leaders', 'Open a conversation with your coach about growing and multiplying leaders.', 'Leadership development is critical to the sustainability of this new church. Too few organizations, churches or otherwise, have developed a healthy culture of leadership multiplication. Chances are good you haven''t experienced what it''s like. Or maybe it''s been a while since you have.  Now you have the awesome responsibility of creating that healthy culture in this new church. Lean on your coach''s wisdom and experience and really pick his brain on leadership multiplication.  Sample issues to process with your coach:  How to get started multiplying leaders  Spotting potential leaders  How to have an ICNU conversation  Embrace imperfect performance as the leader-in-training is learning  When to entrust responsibility  How to restore trust once broken', 'This task is complete when you have called your coach about leadership multiplication.', 'template:  2019-12-03 due date fields found empty -pb ', 1, 'todo', 54, 7, '{}'::jsonb),
  ('a7440d52-27fb-5791-a9a8-04d6792e46a5', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Leadership Multiplication Strategy', 'Create a strategy for multiplying leaders that is simple and reproducible.', 'The Leadership Multiplication Strategy document is aimed at helping you craft a simple process and simple language to communicate leadership multiplication ideas, principles and processes at the church. Complexity is the enemy of multiplication.  Work through the sub-tasks and put your completed answers in the Leadership Development Strategy Template (below).  Develop a Leadership Pathway  Create a Leadership Development Map', 'Download Passion for Planting''s  Leadership Multiplication Strategy Template  (<a href="/resources/item/388">MS Word</a> or <a href="/resources/item/389">Google Doc</a>).  Work through the subtasks which follow.  Compile all of your ideas and answers in the template.  Send your completed Leadership Multiplication Strategy to your coach for feedback.  This task is complete when you''ve written down your strategy to develop and multiply leaders in your church.  Additional Resources  Passion for Planting''s <a href="/resources/item/390">Sample Leadership Multiplication Strategy</a>', 'template:  2019-12-05 due date fields found empty --pb ', 2, 'todo', 141, 80, '{}'::jsonb),
  ('8f842069-bcdd-5cfe-9c77-b802aecb9273', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm Leadership Multiplication Strategy', 'Ensure that the planter has crafted a Leadership Multiplication Strategy that is simple and reproducible.', 'Review the planter''s Leadership Multiplication Strategy document. Either encourage the planter to rework the insufficient section(s) or affirm that it is a workable and reproducible strategy.  The document should include:  a simple ''leadership pathway'' that depicts next levels for leaders to grow into  a leadership development map that lays out:  steps used to develop leaders  things done to help move leaders along  specific content, curriculum or events to be used', 'Review the planter''s Leadership Multiplication Strategy document and provide feedback where necessary.  This task is complete when you, the coach, have reviewed and affirmed the planter''s Leadership Multiplication Strategy document.', 'template:  2019-12-23 content updated --pb  2020-12-14 changed Due in # Days from 135& to 142& --pb&  ', 3, 'todo', 68, 7, '{}'::jsonb),
  ('acf2ea1c-361e-5aba-9896-feee03f070af', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get ongoing leadership development meetings on the calendar', 'Start leadership meetings as soon as you recruit leaders to both equip and support those leaders.', 'Plan your leadership meetings in a way that enables busy people to participate. Not only will these meetings provide a context for training, prayer, and support, but problems can be dealt with before they develop.  Once you''ve decided on a sustainable rhythm, put a recurring event on the church calendar.', 'Determine when and where your leadership meetings will be held.  Determine the typical agenda for these meetings.  Start the meetings and make adjustments as needed.  This action is complete when you schedule the first leadership development meeting and have a plan for the frequency of those meetings.', 'template: standard  2019-11-20 name updated from "Create a Networking Strategy" --pb  2019-11-26 content validated --pb  2020-12-16 changed Due in # Days from 98& to 52& & Duration from 35& to 21& --pb&  ', 4, 'todo', 68, 7, '{}'::jsonb),
  ('4de0d2cb-f344-5fa4-940b-de3843b74ee9', '3c968e6b-9362-5637-ade7-72b9112bc28b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Church Multiplication Strategy', 'Create a strategy for how you''ll work church multiplication into the very fiber of your church''s DNA, and how you''ll make it stick.', 'You, as the leader, may have a clear and tangible picture of what a culture of multiplication could look like. Maybe you''ve experienced it firsthand, or maybe you''ve been inspired by various books on the subject. But how do you transition from dream to reality?  Working through this strategy document will help you think about multiplication systems and craft some clear next steps.  By Age 3 or Not at All  Don''t put off developing this strategy until later. Research has revealed that churches that don''t start a new church by their third birthday rarely ever become multiplying churches.  If you wait until your church is "ready" to plant, you probably never will.', 'Download the  Church Multiplication Strategy Template  (<a href="/resources/item/323">MS Word</a> or <a href="/resources/item/360">Google Doc</a>).  Work the subtasks that follow to assist you in filling out the template.  Send your Church Multiplication Strategy to your coach for feedback.  This action is complete when you have an actionable church multiplication strategy for the new church.', 'template:  2019-10-14 new task --pb  2020-12-16 changed Due in # Days from 200& to 143& & Duration from 45& to 112& --pb&  ', 5, 'todo', 233, 220, '{}'::jsonb),
  ('c86410a0-311c-5999-b090-a6ff9f18552b', '45667404-f85d-5dc7-b5f4-be7003081680', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this community networking overview', 'Create a strategy for networking with community leaders to connect with the right people in the most effective way.', 'Networking is all about deliberately starting conversations with key community leaders.  Why is networking important? The networking relationships you foster can open up community service, outreach and marketing opportunities. Sometimes they will lead you to  the facility you''ll end up renting for worship gatherings. Often the initial relationships open up their networks to you, people you''d otherwise not be able to meet with.  Begin as a student of your community. Understand who the key organizations and leaders in the community are. There will be more leaders to network with than you will time for prior to your launch. You''ll have to prioritize and be strategic.  Community leaders have a good grasp on your community and can help you discover the best ways to serve. Chances are good that they''ve gotten to their current position because of their charisma and ability to network. You''ll commonly find good vision-casters among them, too, which is a skill you will always need to hone. Your community leaders have the ability to influence others, so get them on your side.  Networking is like a needle in a haystack. If you think there is no needle, you will not find it. But if you are certain there is, you will find it. God has placed people in the community that you need to find. Your networking strategy is one of the best ways to find them. Pray that God will reveal the several persons of peace in your community who will make a profound impact on the eternity of tons of people when they come to believe.  Lastly, as the "CEO" of the church, you should be meeting with with other C-Suite leaders in your community. They''re your peers.', 'Watch the Passion for Planting training video "<a href="/resources/item/181">Networking - Connect in the Community</a>" featuring Ed Stetzer.  This action is complete when you have read this overview and watched the training video by Dr. Ed Stetzer.', 'template: standard  2017-05-31 content updated, audience changed to coach --pb  2018-04-20 updated content, changed audience to planter --pb  2019-11-26 content updated --pb  2020-12-14 changed Due in # Days from 70& to 38 --pb&  ', 0, 'todo', 31, 1, '{}'::jsonb),
  ('1be7d097-a2b5-5d62-8b4a-c1932378206f', '45667404-f85d-5dc7-b5f4-be7003081680', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about networking in the community', 'Open a conversation with your coach about community networking.', 'Meeting leaders and civic influencers in your community will build your church''s credibility, uncover community service opportunities, and may even help identify a worship gathering facility.  Sample issues to process with your coach:  Building relationships with leaders outside the church  How to identify key leaders in your community  Cold calling community leaders  Finding time to network', 'This action is complete when you have called your coach about networking in the community.', 'template: standard  2016-06-19 resource link updated --pb  2017-11-13 content & links validated --pb  2018-05-07 added& google& doc template version --pb  2019-11-26 content overhauled& --pb  2020-12-14 changed Due in # Days from 98& to 45& --pb&  ', 1, 'todo', 37, 7, '{}'::jsonb),
  ('ef5549b6-92e2-59a2-8336-e6fc416efce5', '45667404-f85d-5dc7-b5f4-be7003081680', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Community Networking Strategy', 'Document the approach you''ll take to meeting leaders and influencers in your community.', 'The single best resource for understanding your community''s needs are people in positions of power and influence in the community. These leaders will be heavily vested in the community and care deeply for it. With this common bond, conversations should be easy to start.  These conversations are learning expeditions. You may not gain a single person to the launch team by talking with community leaders. But it''s still a huge win if all you accomplish is learning the needs of the community, discovering opportunities for partnership, and planting the seed that your church is about serving the community. Look for areas where God is already working through these leaders and seek ways to partner.  The two basic approaches to get your first meetings are to create a Top 20 list of leaders and cold call them, or somehow manufacture the first meeting and follow their introductions to other leaders.  Your Community Networking Strategy will contain the following:  A basic philosophy or approach to community networking  A goal for how many leaders to meet each week  A short list of questions to ask in person  A way to keep track of contact information and important notes  A system for circling back and following up so it''s not a one-and-done "relationship"', 'Download Passion for Planting''s  Community  Networking Strategy Template  (<a href="/resources/item/182">MS Word</a> or <a href="/resources/item/358">Google Doc</a>).  Think through how to prioritize community leaders to network with.  Determine a goal for how many leaders to meet with.  Compile all of your ideas and answers in the template.  Send your completed  Community Networking Strategy  to your coach for feedback.  This action is complete when you''ve sent your  Community Networking Strategy  to your coach for review.', 'template: standard  2017-11-13 content validated --pb  2019-11-26 content updated --pb  2020-12-14 changed Due in # Days from 105& to 52& --pb&  ', 2, 'todo', 136, 99, '{}'::jsonb),
  ('e78987ea-0319-53c4-9a3f-16344b9fe927', '45667404-f85d-5dc7-b5f4-be7003081680', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm Community Networking Strategy', 'Review the planter''s Community Networking Strategy and provide feedback on his ideas for connecting with key leaders in the community.', 'The planter will send you their  Community Networking  Strategy . It should include the following elements:  A basic philosophy or approach to community networking  A goal for how many leaders to meet each week  A short list of questions to ask in person  A way to keep track of contact information and important notes  A system for circling back and following up so it''s not a one-and-done "relationship"  Read over the strategy and provide feedback to the planter. Specifically, affirm the goal for the number of leaders the planter wants to connect with. Does the goal seem realistic? Does the goal seem too small? Spend time talking through the strategy. Provide wisdom and insight for how to get a meeting with the leaders and how to make the most of that meeting.', 'Read over the networking strategy provided by the planter.  Affirm the goal for the number of leaders to network with.  Affirm the questions the planter will ask leaders.  Affirm the tracking and follow up process.  Provide any other feedback as appropriate.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Community Networking Strategy document.', 'template: standard  2017-11-13 content updated --pb  2020-12-16 changed Due in # Days from 160& to 137& & Duration from 83& to 93& --pb&  ', 3, 'todo', 51, 7, '{}'::jsonb),
  ('83cb108f-f6b3-5e15-a9b8-a31cca275efc', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Partner with a church planting network', 'Actively pursue partnership with a church planting network for support and credibility.', 'Never plant alone. Church planting networks create community and common purpose around disciple-making and church planting. And there are secondary benefits as well.  You Get Services  Many church planting networks provide key services and support to the planter, such as:  coaching  assessment  training  bookkeeping  project management  administrative support  spouse support  etc.  This could save you a great deal of time and effort, which would give you more time to spend in the target community with non-Christians. Starting a new church is not something you should try and do alone. Being part of a network brings the kind of of support that can help maximize the health of the new church.  You Gain Credibility  Church planting networks can also bring credibility to your plant. When you''re fundraising, you can tell prospective supporters that you''re part of a network and not going it alone. And when you''re networking with other churches, businesses and nonprofits in your community, you have the brand of your network to lean on.  Dozens to Choose From  From the Exponential post <a href="https://outreachmagazine.com/features/church-planting/51456-10-church-networking-models-part-1.html">10 Models of Networks</a>, check out their directory of over 60 networks in the following categories:  Collaborative Networks  Regional Networks  Cooperative Networks  Franchise Networks  Church-Based Networks  City-Focused Networks  Rural Networks  Family of Churches Networks  Specialty Networks  Support Networks  Explore a network''s beliefs and planting approaches to determine if they are a good fit.  There May Be Obligations  Networks need to carry out their mission the same as any church, which requires involvement and resources. Most networks will have some kind of relational and financial participation requirement. Make sure you understand what those are before you sign on the dotted line.', 'Become familiar with the different church planting networks. Determine which groups seem to be a good fit.  Contact networks that are a good fit to determine next steps.  Partner with a church planting network, signing any required covenants or agreements.  This action is complete when you have partnered with a church planting network.', 'template: standard  2017-05-31 content and links validated --pb  2019-01-11 Due in # Days changed from& 60 to& 31 --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from & 31 to 14 & Duration from 21 to 14 --pb  2022-11-21 updated Network link --sc ', 0, 'todo', 13, 14, '{}'::jsonb),
  ('1504d34b-4070-56e1-88fc-4f449d386c7c', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this coaching overview', 'Understand why having a coach should be a non-negotiable.', 'Coaching has become a ''best practice'' of church planting and is required by the majority of church planting networks and denominations. In fact, according to the Leadership Network, planters who have a coach are  twice as likely to plant a healthy church that survives .  As in double.  Coaches offer an experienced perspective on the unique tasks and experiences you''ll go through. Better than just providing sage advice, your coach will help bring out the best in your thoughts and planning process: coaching is not telling people what to do and how to do it. Coaches are trained to listen and not impose their experience on you.  Coaches also hold you accountable. When a planter has committed to making 10 networking appointments by the end of the week, does he really want to call his coach and admit that he didn''t do it? We all need this kind of motivation for time to time.  Coaches can also be your confidante. You can tell your coach anything. You can share honest thoughts, feelings, and emotions about what is happening in the new church. People who will do that for you are rare in the life of any planter, but so very needed.  After experiencing the support of a coaching relationship, many leaders will continue to intentionally seek out a coach for the rest of their time in ministry.  Christian Coaching  Here are some basic assumptions of Christian coaching:  People have unique visions and values  People have a need to discover  individually  what God wants them to do  The Holy Spirit provides the Christian with personal guidance  Each person has a unique background, knowledge, experience, insight and setting  Christians need to lead according to a unique calling from God  If you discover it yourself, you own it better  A coach is not the expert on  your  life and won''t tell you what to do  People are more committed to what they help create  God leads each of us uniquely to unique paths  Prayer is our most powerful tool  A Tale of Two Coaches  Andre had to pick between launching worship gatherings in February at a decent location, or waiting until April to launch in a  fantastic  location. He didn''t know how to choose between buying more time before the first summer and waiting for the better location. Through conversations with his coach, he was able to determine the best choice for his church. Without the counsel of someone who has ''been there and done that'', Andre wouldn''t have had anyone with experience to help weigh the options.  Chris had a different problem: people he invited to join the Launch Team kept telling him, "Let us know when you''ve started weekly services, then we''ll come be a part of what you''re doing." His frustration grew and he couldn''t figure out how to gain traction. To save money, he had chosen not to hire a coach, but he really needed someone with experience to process this landmine and figure out how to diffuse it.  You may be tempted to save money and not hire a coach. Don''t cut corners on this one! Make hiring a coach a non-negotiable for yourself.', '<a href="/resources/item/208">View the training video by Dr. Ed Stetzer</a>.  This action is complete when you have viewed the training video.', 'template: standard  2017-08-29 content updated --pb  2019-12-10 content validated --pb  2020-12-11 changed Due in # Days & Duration from 7 to 1 ', 1, 'todo', 0, 1, '{}'::jsonb),
  ('dcd7b853-a934-56d0-b8ee-c15a782b3d35', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Select your coach', 'Find a church planting coach to help you through the planting process.', 'Have you ever noticed that Steph Curry, LeBron James, and Tom Brady all have coaches? Doesn''t it seem like players of that caliber wouldn''t need a coach?  Whether in sports, business, or church planting, everyone needs a coach. In sports, the coach''s primary role is to bring out the best in the athlete, and in team sports to get all the players working together.  In church planting these two goals still apply: bringing out the best in you, the church planter, and getting you working with God. The coach accomplishes these goals through asking the right questions and challenging you to think God-thoughts and make Godly decisions. This can include:  Training and empowering you  Bring you wisdom, experience and external perspective  Being your cheerleader  Helping you see your blind spots  Helping you navigate the stress of being an entrepreneur with the demands of of a healthy family life  Providing a safe place for you to have doubts and ask questions  Asking  you  the tough questions  Qualifications  To be effective, the coach should have personally planted a successful church or have other similar personal experience with church planting. Since you probably haven''t planted a church before (usually), the coach''s experience is a great way for the church planter to learn from someone else, both the good and the bad.  Choosing the right coach is critical. Sometimes church planting networks train and select coaches for the church planter. Other times you choose your own coach. Regardless, you need a coach you respect both personally and professionally. And you need to share fundamental beliefs.  As an absolute minimum, the coach should be available for a monthly conference call. A more ideal arrangement is a biweekly 1-hour phone call with the church planter. The coach should commit to working with the Church Planter for 1-2 years. Whenever possible, you should be involved in choosing your coach.  Gain Wisdom  Building a church is complicated. It requires a great deal of broad knowledge that few church planters possess.  Instruct a wise man and he will be wiser still; teach a righteous man and he will add to his learning. - Proverbs 9:9  The way of a fool seems right to him, but a wise man listens to advice. - Proverbs 12:15  We all need someone to bounce ideas off. Get a coach.', 'Check with your church planting network to see if they provide a coach.  If not, consider contracting with Passion for Planting for a <a href="https://church-planting.net/coaching/">church planting coach</a>.  Interview potential coaches over the phone or face to face.  Ask for (and check) references.  Select your coach.  Establish a formal agreement with the coach to make sure that expectations are explicit.  This action is complete when you establish a formal agreement with the church planting coach.', 'template: standard  2017-08-29 content updated --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from 14 to 13 & Duration from 14 to 7 & --pb ', 2, 'todo', 12, 7, '{}'::jsonb),
  ('094c2808-d0e2-5407-9218-ff89c5077b7f', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Schedule regular meetings with your coach', 'Set up a recurring calendar appointment to facilitate meeting with your coach on a regular basis.', 'Sometimes the hardest part of developing a coaching relationship is simply beginning the relationship. Once you''ve selected a coach, take the lead to contact the coach and set up an initial meeting. This meeting will probably happen by phone or video call. If you can swing it, meet with the coach in person the first time around.  The first meeting should open a dialog about what both parties hope to gain from the relationship. It is also important at this time to set expectations on what a typical meeting will entail. Spend some time casting vision about the new church for the coach, too.  The most important thing to accomplish at the first meeting is to set up the ongoing rhythm of calls. It''s common for that to be biweekly or semi-monthly, but planting a church is a fast-moving target, so Passion for Planting recommends meeting no less than once a month with your coach.', 'Set initial meeting agenda.  Conduct initial meeting.  At that meeting, schedule ongoing meetings.  Add the new schedule to your calendar as a recurring appointment.  This action is complete when regular meetings have been scheduled with the coach.', 'template: standard  2017-08-30 content updated --pb  2019-01-11 Due in # days& corrected from 7 to 21 --pb  2019-12-10 content updated --pb ', 3, 'todo', 20, 7, '{}'::jsonb),
  ('835dfb33-50b6-533e-acb9-b898bdb356cd', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Show your coach how to use PlanterPlan', 'Train the coach on the use of PlanterPlan so that coaching calls can focus on the big issues that you face.', 'The coach should review the project status via PlanterPlan prior to any coaching calls or meetings to understand the current status of the church plant. This will enable the coach to focus on the most important issues facing the planter.  Integrated into PlanterPlan are scheduled coaching calls and coaching checkpoints. The coaching call tasks equip the coach with questions to ask that are pertinent to the planter within the timeline of the launch plan. The coaching checkpoints allow the coach to provide input and affirmation of critical strategy documents the planter creates.  The coach may also see trends in the planter''s work patterns and determine adjustments need to be made.', 'Grant the coach access to your PlanterPlan project by clicking "Manage Team" in the Project menu.  Encourage the coach to watch the PlanterPlan tutorial.  If necessary, the coach can <a href="https://church-planting.net/">contact Passion for Planting</a> for further instruction.  This action is complete when the coach understands how to use PlanterPlan.', 'template: standard  Action #3:& http://www.church-planting.net/contact.htm& is a 404.  Changed to& <a href="http://www.church-planting.net">http://www.church-planting.net</a>  2017-08-30 content validated and hyperlink updated --pb  2019-01-11 Due in # days corrected from 7 to 28 (Due & Duration were swapped) --pb  2019-12-10 content updated --pb ', 4, 'todo', 27, 7, '{}'::jsonb),
  ('e9b50103-3ab2-59d2-a606-c5b9e1f10936', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about your assessment report', 'Open a conversation with your coach about what to do with your Assessment Team''s recommendations.', 'After receiving the formal report from the Assessment Team, review all their developmental recommendations. Work with your coach to develop a plan of attack to address each one. Be sure to include concrete dates and measurable goals.  Sample issues to process with your coach:  Which recommendation will be the hardest to address  Which recommendation gave you the strongest emotional response  Which order to address them in  Which recommendation will give you the biggest return on investment', 'This action is complete when have called your coach to start kicking around your plan to address the Assessment Team''s developmental recommendations.', 'template: standard  2017-05-30 updated content, changed audience to coach --pb  2018-04-20 updated content, changed audience to planter --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from 28 to 14 & Duration from 7 to 1 --pb ', 5, 'todo', 13, 1, '{}'::jsonb),
  ('0c7329a2-d558-5092-bcf9-2570e41f1f34', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Write your personal development plan', 'Create a plan to implement the health and improvement recommendations made by your church planter assessment team.', 'No planter is the perfect candidate for planting a church. We are all human and naturally have strengths and areas of weakness. Part of the benefit of assessment is increasing our awareness of these areas.  As a part of the final assessment report, you should have been provided with a list of developmental suggestions to maximize your effectiveness as a planter.  We all want to be the best stewards of the gifts and resources that God has given us. It''s important to develop a plan to implement the recommendations given by the assessment team.', 'Go over the assessment recommendations and give yourself an honest evaluation in each area.  Write out a plan and timeline for addressing each of the recommendations.  Put due dates on your calendar for completing each recommendation.  Ask a coach or mentor to hold you accountable to the plan you have created.  This action is complete when you have developed an action plan from the assessment recommendations.', 'template: standard  2017-08-30 content updated --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from 36 to 28 --pb ', 6, 'todo', 27, 7, '{}'::jsonb),
  ('f599aabb-4627-5d8d-a2b1-826eb09d8c5c', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm planter''s Developmental Plan of Action', 'Ensure that the planter''s Developmental Plan of Action covers the bases while remaining realistic.', 'The planter got some very specific feedback through the assessment process. His Developmental Plan of Action should include actionable steps to maximize his identified strengths and shore up any gaps they pointed out.  Help the planter avoid the 2 extremes of being overly ambitious or distractedly negligent.', 'Review the planter''s completed Developmental Plan of Action.  Provide feedback to the planter.  Affirm to the planter that the plan is actionable and realistic.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Developmental Plan of Action.', 'template: standard  2018-11-02 content updated --pb  2019-12-10 content validated --pb  2020-12-11 changed Due in # Days from 43 to 35 --pb ', 7, 'todo', 34, 7, '{}'::jsonb),
  ('d2494142-875e-52db-9ae8-fe29fef91b6e', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Make sure your spouse has a support system', 'Get the church planting spouse connected to a support system.', 'You are being supported by coaches and mentors, but who is caring for your spouse?  Planting a church is difficult for the planter''s family, too. What a tragedy it is when a planter ends up with a successful church, but a failed marriage.  Many church planting networks provide spousal support ministries.', 'Get your spouse connected to the support system your church planting network has for church planting spouses.  This action is complete when the planter''s spouse has joined a spouse support network.', 'template:  2017-03-08 link to churchplantingwives.com takes user away from PlanterPlan, tried to update link to open new window --pb  2017-08-30 link target fixed, content validated --pb  2019-12-10 content updated --pb  2020-02-24 additional resources subsection added --pb  2020-05-26 new additional resource added --pb  2020-06-11 new additional resource& added --pb  2022-03-31 new additional resource& added --pb  2022-11-21 new additional resource added --sc ', 8, 'todo', 13, 7, '{}'::jsonb),
  ('17298d03-2b7a-5ced-ba15-5be3ac84ac9e', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Form a Management Team (oversight)', 'Put oversight and accountability mechanisms in place for the new church.', 'It''s a bad idea for new churches to put local Biblical Elders in place too soon. Resist installing elders before the 2nd anniversary of launching worship gatherings. You''ll end up installing leaders with pre-existing agendas or moving new believers too quickly into leadership.  But holding off places an increased burden of responsibility on you. During this critical time, you need spiritual coverage and wise counsel. In the absence of a Biblical Eldership, you need a trusted group of godly people to provide oversight.  Where a Biblical Eldership is not in place, Passion for Planting recommends forming a Management Team. Management teams typically:  Provide counsel  Define the church plant''s scorecard  Approve big-decision items like staffing, facilities, budget, etc.  Keep the new church true to its vision, values and beliefs  Provide accountability for progress toward defined goals and expectations  Provide spiritual prayer coverage for the new church  Ensure the planter is maintaining healthy boundaries  Consist of 3 to 7 people  Include one representative from each group that is providing significant financial support  Remain in place until local Biblical Eldership is put in place (and they have a say in the timing of this) and/or the new church is financially self-sufficient  Are recognized in the church''s Bylaws as the initial leadership team for the new church  Meet  at least  2 times per year during the first 2 years;  Passion for Planting recommends meeting monthly where possible  The tricky part is that though you my have invited them to serve on the team, you are placing them in a collective position of authority over you. Build a team of people who can speak the hard truth to you in love and not simply rubber stamp everything.  Resist the temptation to skip a Management Team. You need the spiritual coverage and wise counsel of Godly people who are committed to you and the new church.', 'Put a Management Team or similar oversight structure in place using the guidelines above.  Have the Management Team read the brief post  <a href="https://www.churchplantingtactics.com/when-does-a-management-team-win/">When Does a Management Team Win?</a>  Meet for the first time.  This action is complete when the Management Team has convened their first meeting.', 'template: standard  2017-08-30 content updated --pb  2022-11-15 nick wrote in a comment, nothing else --nz ', 9, 'todo', 20, 21, '{}'::jsonb),
  ('126654f4-3456-58ce-8544-0b429927ad7b', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about church planting goals and expectations', 'Open a conversation with your coach about how you will measure pre-launch health and live up to what your sending church or church planting network expects of you.', 'Your management team (oversight) is charged with defining the church plant''s scorecard and holding you, the planter, accountable to goals for each metric. They should also ensure that the expectations of the sending church or church planting network are being met. Tap into your coach''s wisdom and experience to explore setting your own church planting goals and meeting all of the expectations placed on you.  Sample issues to process with your coach:  The management team''s desired outcomes (the scorecard)  The sending church or church planting network''s expectations  Uncovering assumptions  Making sure everyone is on the same page about your model or approach to planting  How to negotiate changing something that''s expected of you', 'This action is complete when you have called your coach about your goals and expectations.', 'template: standard  2017-05-30 content updated, audience changed to coach --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from 45 to 35 --pb  2021-01-25 content updated --pb ', 10, 'todo', 34, 7, '{}'::jsonb),
  ('ab28aa07-8d66-56eb-af97-e5ecfc96f81f', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get your stakeholders to agree on a scorecard and other expectations', 'Get your Management Team to unite around what needs to be accomplished in the planting process.', 'Your entire Management Team needs to be in complete agreement on the desired outcomes of the church plant. An effective way of getting there is to create a scorecard for the pre-launch season. In that process you''ll have to decide on what to measure and how much to shoot for in each of those metrics.  Measure what''s most important to the DNA of the new church. What gets measured gets done. Broadly, that might include:  people  finances  groups  multiplication  etc.  On top of that, your sponsoring church or church planting network will have expectations of you, the planter, and of the new church. You may have had to agree to something in writing, or the expectations may be implicit. If those were put in place before your Management Team was formed, each of them need to know what those things are and be in alignment with them.  Possible expectations could include:  When to launch in-person worship gatherings  The basic approach or model for planting the church  Location  Attendance Goals or other metrics  Fundraising Goals  Style of Worship  Date for the planter to move on location  Governance of the new church  An expectation to complete an assessment and/or training  A "tithe back" or other financial participation in the network  Kinds of marketing that should(n''t) be used  Whether expressed or implied, now is the best time to get the expectations out in the open. Neither side wants surprises here.', 'Prayerfully draft a scorecard for the church plant, both categories to measure and goals for each.  Request a written list or summary of expectations from your sending church or church planting network.  All parties, including the planter and coach, should agree to these expectations.  This action is complete when written expectations have been agreed upon by all parties.', 'template: standard  2017-08-30 content updated --pb  2019-01-11 Due in # Days changed from 45 to 52 --pb  2019-12-10 content updated --pb  2020-12-11 changed Due in # Days from 52 to 42 --pb  2021-01-25 content updated --pb ', 11, 'todo', 41, 14, '{}'::jsonb),
  ('8bf807b1-f925-5e63-9d69-1122aa3a85de', '5074f41f-5aed-5e18-9135-434bdd8e6ff8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: Review and Affirm the planter''s church planting scorecard', 'Ensure that the planter is measuring the most important things in support of the vision of the new church plant.', 'The church planter, along with the Management Team, gets to set the DNA of this new congregation. To some degree, the planter gets to start with a blank slate as far as what gets measured. The traditional scorecard of the church in the West has been attendance, offerings, and square footage, which is an incomplete scorecard at best.  A healthy scorecard for the pre-launch season will have approximately 6 metrics with goals set for each. Dozens of things could be measured, but to save hiring more staff just to measure stuff, only the most important things should be tracked at this point.', 'Review the planter''s proposed scorecard.  Provide feedback to the planter.  Instruct the planter to present it to the Management Team for deliberation and approval.  This action is complete when you, the coach, have provided feedback on the proposed church planting scorecard.', 'template: standard  2017-08-30 content updated, audience of task changed to coach --pb  2018-08-21 title tweaked, content tweaked --pb  2019-01-11 Due in # Days changed from 45 to 52 --pb  2019-12-10 content updated --pb  2021-01-25 content update --pb  2020-12-11 changed Due in # Days from 52 to 49 --pb ', 12, 'todo', 48, 7, '{}'::jsonb),
  ('a0b6b19c-1621-5e2f-96e6-93604f05b537', '553d3aeb-a255-51de-982b-596495e68a36', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this Opening Day Expectations overview', 'Understand why it''s important to have the end in mind and set expectations for the Opening Day of worship gatherings.', 'You already have a vision for what the first worship gathering will be like. Whether near or far, that''s the "Opening Day" (aka "Launch") of your worship gatherings. It''s the picture on the puzzle box that helps everyone put the pieces in the right order to complete the puzzle.  It''s not really the opening day  of the new church itself ; you should have other elements of what it means to be a church in place well before you start worship gatherings. In that sense, you''ve already "opened".  Elements/Activities of the Early Church from Acts 2:41-47  repenting & believing, baptizing, making disciples, leadership (implied)  teaching, fellowship, breaking of bread, prayer  common awe, signs & wonders by leadership, worship (implied)  love & fellowship  sharing financial resources  corporate worship, meeting in homes, sharing meals  favor in the community, making disciples  The  Opening Day  for the tasks in the Milestone refers to  the start of worship gatherings . The Opening Day Expectations document will walk you through the process of getting the visions and dreams out of your imagination and onto paper.  If you don''t have a clear description of  Opening Day , it''s like giving your team a bag of 1,000 puzzle pieces but no box lid for them to know what the assembled puzzle should look like.  The document helps you get everyone on your Launch Team on the same page. Because here are the 2 kinds of people that will be joining your Launch Team:  people with no church background that have little a frame of reference for worship gatherings  churched and de-churched people that come with their own preconceived notions about what worship gatherings should look like  Get everyone shooting at the same target and pulling in the same direction by giving them the puzzle box cover for Opening Day of worship gatherings.', 'Read the content above.  Watch the Passion for Planting training video <a href="/resources/item/82">Opening Day Expectations</a> featuring Ed Stetzer.  Commit to writing down your expectations for the Opening Day of worship gatherings.  This action is complete when you have read the content of this overview.', 'template:  2020-12-11 changed Due in # Days from 28& to 22 & Duration from 7 to 1 --pb ', 0, 'todo', 21, 1, '{}'::jsonb),
  ('95d7408e-a657-5140-9017-da5f63f48edc', '553d3aeb-a255-51de-982b-596495e68a36', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about Opening Day Expectations', 'Open a conversation with your coach about your expectations for Opening Day of worship gatherings.', 'Imagining and quantifying what the opening day of worship gatherings looks like will be critical to your ability to communicate about it and inspire others. If you don''t know where you''re going, any old road will do.  Sample issues to process with your coach:  Ways of ''doing church'' that will alienate people in your community  How to deconstruct elements of a church service in order to translate them into the local context  Realistic numeric expectations  How each element connects with the target audience', 'This action is complete when you have called your coach about your Opening Day Expectations.', 'template: standard  2017-05-30 content updated, audience changed to coach --pb  2019-12-16 content updated --pb&  ', 1, 'todo', 27, 7, '{}'::jsonb),
  ('90a076b7-5cc7-5c67-a171-85b0159daf8f', '553d3aeb-a255-51de-982b-596495e68a36', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft your Opening Day Expectations', 'Clarify vision and focus your teams by writing down dreams and expectations for the Opening Day of worship gatherings.', 'Having a clear understanding of what the worship gathering will be like on Opening Day enables you to stay focused on what needs to be done during the pre-launch phase. The vision of that preferred future (what Opening Day of worship gatherings looks like) will shape your actions today by pointing you at the right target.  There are many different approaches and philosophies to planning. No matter which approach you use, planning is simply a means to an end. Planning lays out what has to be done to get from where you are today to where you want to be in the future. No matter what planning approach you use, the basic steps include:  Define a clear picture of a preferable future (Opening Day of worship gatherings)  Vision is all about painting a picture of a preferable future, and then moving deliberately forward in pursuit of that vision. The preliminary launch plan starts with this end in mind: "We believe God''s vision for the Opening Day of worship gathering looks like [fill in the blank]." By defining a picture of the future, you can then name the specific actions to move in that direction.  Understand where we are today  Before you can put a plan together for moving to where God wants to be in the future, you have to be sober about where you are today. This second step of planning leads you through the process of understanding where you are. For planters, the starting point is typically to a blank canvas, starting from scratch. A big help in understanding where you are today is having gone through a planter assessment process.  Plan of action for moving from where you are today to where you want to be  After describing a clear vision for the future and assessing where you are today, the final step in planning is identifying steps to get you where you want to be.  Consider the process of building a new house. The first step is to draw up blueprints. What do you want the finished product to look like? Developing a clear picture of the new house influences every aspect of turning the vision into reality. It affects your choice of builder, lot, how long it will take to construct, and the cost. You just can''t develop a good plan without a clear vision of the end.  The picture does not need to be perfect. Just get it roughly right based on what you sense God is leading your church to be. The  Opening Day Expectations Template  (below) helps you work through specific aspects of the Sunday morning gathering. The template identifies over 50 characteristics of a Sunday morning experience for you to consider. This helps you write out a description with specific/concrete expectations for what the church will look like on the Opening Day of worship gatherings.  NOTE: This description of Opening Day is not the final product. The church may end up looking different than this first draft. This task simply gets you thinking through Opening Day and setting an initial target.', 'Download Passion for Planting''s  Opening Day Expectations Template  (<a href="/resources/item/197">MS Word</a> or <a href="/resources/item/374">Google Doc</a>).  Answer each question as a guided daydream about what your Opening Day of worship gatherings will be like.  Send the completed template to your coach for feedback.  Present the completed template to your Management Team to make sure everyone is on the same page.  This action is complete after you fill out the template to produce a written description of the opening day of worship gatherings.', 'template: standard  2017-06-01 content & resource links updated --pb  2018-06-01 additional resources subsection added,& gdoc& template added --pb  2019-12-16 content updated --pb  2020-06-21 content updated --pb  2020-12-11 changed Due in # Days from 45& to 35& --pb ', 2, 'todo', 34, 7, '{}'::jsonb),
  ('23768c24-fa8c-531f-8645-82349dab10e5', '553d3aeb-a255-51de-982b-596495e68a36', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm Opening Day Expectations', 'Ensure that the planter has clearly defined expectations for both Opening Day of worship gatherings and the period immediately following.', 'The planter''s Opening Day expectations need to be well thought through and frequently communicated. The planter should also have a plan for how to prepare the launch team for the challenges and opportunities of both the launch of worship gatherings and post-launch  Milestones .', 'Review the written Opening Day Expectations.  Provide feedback to the planter.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Opening Day expectations.', 'template: standard  2017-06-01 content validated --pb  2018-11-02 content updated --pb  2019-12-16 content updated --pb  2020-12-11 changed Due in # Days from 52& to 42& --pb ', 3, 'todo', 41, 7, '{}'::jsonb),
  ('3125ee64-b538-514e-bf15-5f7aad9e723d', '59cfdf08-df2f-5349-9158-bfd2e0dbf573', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a Networking database or address book', 'Establish a community contact database for keeping track of community leaders and organizations and their contact information.', 'As you network in your community, you will be meeting lots of people. Whether you dug up their contact information or they handed you a business card, you will be collecting lots of very useful contact information. It''s time to think through a simple place to keep all that so it''s together.  You have 2 basic options for the database:  keep the information in your church management software  keep it elsewhere, for example:  in your phone''s contacts with a tag or folder for "network"  in a spreadsheet you can access from all your devices  in a free customer relationship management (CRM) app  At least as important is keeping track of when you met with them and when is a good time to follow up with them, along with an occasional important note when you talked about something important you want to remember.  So if your choice of database doesn''t have that built-in, consider creating a sub-calendar dedicated to networking. You can save your appointments and schedule follow-ups there.', 'Decide whether to use your church management software or some other tool for keeping track.  If you''re starting with list of contacts, upload them to your app or recruit a supporter to do the data entry for you.  Make sure your solution is easy to use while you''re out and about.  This action is complete when you have added your first contact to your database option.', 'template: standard  2017-11-13 content & links updated --pb  2019-12-09 content updated --pb ', 0, 'todo', 57, 14, '{}'::jsonb),
  ('bcaa904b-3888-5a29-99be-bf0f8c0ddbf0', '59cfdf08-df2f-5349-9158-bfd2e0dbf573', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Identify and join local civic associations', 'Develop relationships through civic associations to uncover opportunities and resources you wouldn''t otherwise know about.', 'One easy way to network and get the word out about the new church is by joining a local civic organization.  Consider joining:  Chamber of Commerce  Rotary  Kiwanis  Lion''s Club  Optimist Club  etc.  These organizations will put you in contact with multiple community leaders.  These groups have events to serve the community. You may be able to partner with them at their events by providing volunteers to help make them happen. This can help you establish a positive reputation amongst the leaders in the community quickly.', 'Determine which association(s) to join.  Call them or swing by to sign up.  This task is complete when you have joined at least one local association.', 'template: standard  2018-02-16 content validated --pb  2019-12-02 content update --pb  2020-12-16 changed Due in # Days from 128& to 128& & Duration from 34& to 37& --pb&  ', 1, 'todo', 57, 7, '{}'::jsonb),
  ('70921984-414c-5eb1-9325-5a314a3860f2', '59cfdf08-df2f-5349-9158-bfd2e0dbf573', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Write a community needs survey', 'Develop a survey to use in the community so you can gain insight into its greatest strengths and needs.', 'The community needs survey should be limited to what can fit on one page. Passion for Planting has provided a <a href="/resources/item/53">Community Needs and Assets Survey Template</a> as a starting point.  The questions you ask will largely influence the results of the survey. Keep the questions broad in nature, provide lots of multiple choice options and allow room for people to make comments.  For example, rather than asking a specific question such as, "Do you think this community needs more recreational facilities?" ask, "The greatest areas in which our community needs to improve are..." Allow people to choose multiple answers.  Especially if you''re planting in an under-resourced neighborhood, don''t just ask about its needs. Ask about its strengths. Search for areas of opportunity within the community. Then your church can work with the community to meet needs while developing the good already being done. To learn more on asset based community development visit <a href="https://resources.depaul.edu/abcd-institute/">ABCDinstitute.org</a>  The larger the population of the community, the more surveys you will want to collect to get a good sampling. As you collect the surveys you should begin to see trends emerging as to what the greatest strengths and weaknesses of the community are.  In the template you will notice the suggestion to give a gift or have a drawing for participants. This provides incentive for people to fill out the survey. It also gives you a reason to have additional contact with them through email.  One strategy is to use the survey as a means to collect emails for a community database. Then you can invite them to volunteer at your next community service initiative.  Online Surveys  Consider creating surveys that can gather information via the internet. If you have a presence on Facebook, consider creating a Facebook survey and ask people to share it with as many local people as possible. Make sure the survey is clear that only residents of your community should take it. As a safe guard, the first question can be a simple yes or no, do you live in [name of community]?  Other free online survey options include:  <a href="https://www.surveymonkey.com">SurveyMonkey.com</a>  <a href="https://docs.google.com/forms/">Google Forms</a>  <a href="https://www.pollfish.com">PollFish.com</a>', 'Download the <a href="/resources/item/53">Community Needs and Assets Survey Template</a>.  For inspiration, also see the <a href="/resources/item/338">Sample Community Needs and Assets Survey</a>.  Write your own community needs and assets survey.  This action is complete when you have composed your own community survey.', 'template: standard  2017-11-13 content update --pb  2019-11-26 content updated --pb  2020-12-14 changed Due in # Days from 91& to 45& --pb&  ', 2, 'todo', 91, 14, '{}'::jsonb),
  ('1b01227e-d354-59cd-8b48-cc15d95f845a', '59cfdf08-df2f-5349-9158-bfd2e0dbf573', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Have your team conduct the community needs survey', 'Recruit your team members to get completed surveys from people in the community.', 'Once the community needs and assets survey has been written, determine the forum for collecting them.  The more surveys collected, the better. Keep in mind that the denser the population is in the community, the more surveys you will need to collect in order to get a good representation.  Also, keep in mind that the more diverse your community is, the more difficult it will become to get a good sampling. Be intentional about choosing the forums for collecting surveys to ensure that a good representation of the community is present:  A great forum for collecting surveys are at community events. Consider purchasing booth space to conduct the survey.  Another great forum are big box stores and grocery stores. Approach the management and ask them to partner in with you in doing the survey.  Another option is to conduct the surveys online (see options included in previous PlanterPlan task).  Once the surveys have been collected, you must analyze the data. Through your analysis, determine what community needs have been revealed. Compare these results with what was learned by networking with community leaders.', 'Recruit volunteers to help conduct the survey.  Determine the forum(s) for conducting the survey.  Get out there and collect surveys.  Analyze the results.  This action is complete the results of the community needs assessment have been analyzed.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2017-11-13 content updated --pb  2019-12-09 content updated --pb  2020-12-14 changed Due in # Days from 140& to 111& & Duration from 21& to 60& --pb&  ', 3, 'todo', 136, 45, '{}'::jsonb),
  ('7f343c3d-ac64-5597-8dce-97cb74befba9', '59cfdf08-df2f-5349-9158-bfd2e0dbf573', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Meet with community leaders', 'Get face time with civic leaders and influencers to build relationships and learn about your community.', 'Scheduling face to face meetings with leaders is key as you begin to build bridges in your community. Leaders identify with leaders. Asking for face time with these key people will communicate your own level of commitment to the overall community picture.  In a previous task, you set a goal for the number of leaders to meet with prior to launch. You also prioritized your list to identify specific people you want to meet with. Now the rubber meets the road.  The brief first impression you get with these high-profile leaders gets you off on the right foot in the community. Think through what you really need to talk about in your initial meeting.  Once in the meeting, take time to ask about their background (birthplace, education, family, job journey). Finding common talking points helps to move the conversation along. Look for a transition into discussing why you are there and what your vision is. Be prepared to answer the question, "How can I help you?" Use this question to throw out ideas of future potential partnerships with them. Ask questions about the community needs/assets and demographics. Finally, ask permission to meet with them again in the future. Sometimes it may be appropriate to close in prayer.  Power Tips:  Try and do some research about the leader you are preparing to meet with. They may have a profile on their website or LinkedIn.  Dress appropriately. Which community leader you are meeting with may dictate how you dress.  Carry with you:  your calendar  a notepad (so you''re not distracted by technology)  and at least a business card or pre-launch brochure  Take mental notes of the leader''s personal info (name, title, background details, family, etc...).  Only take written notes if the leader begins to give you data, community info, people to contact, etc.', 'Pursue meeting with the leaders on your prioritized list.  Meet with them.  After each meeting, jot down notes and schedule your next follow-up with them.  This action is complete after you have met with the first 10 community leaders prioritized in your networking strategy.', 'template: standard  2017-11-13 content updated --pb  2019-12-09 content updated --pb  2020-12-14 changed Due in # Days from 84& to 58& --pb&  ', 4, 'todo', 110, 60, '{}'::jsonb),
  ('c97886a7-8b34-5730-b565-5c8279013780', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Test your assimilation followup processes', 'Circle back to your  Assimilation Strategy  to make sure that all the pieces are in place and your team is ready to execute.', 'Now is the time to test drive your assimilation strategies to uncover any breakdowns, incomplete pieces or training gaps.  Use the following questions to drill the followup team to help them be ready:  Is the invitation to fill out the connection card script written?  Does that invitation include clear instruction for how guests are to turn the card in?  Is mention of the connection card planned at least 3 times during the worship gathering?  Review the church''s connection card. Does the followup software have a process built for each inquiry option on the card? (ex: I want info about...)  Create a practice guest profile with a valid email address and your mobile number, and then send it through the followup process.  Did each team member get notified of their followup task(s)?  Did the practice guest receive each of the followup messages?  Is there any placeholder or default text in any of the followup messages?  Run a report on the followup process. Can you see that the practice profile has made it through the process?  How will the followup system scale if you had 100 guests to follow up with the first Sunday?  The followup system cannot fail in the first several months of the church.', 'Review your  Assimilation Strategy  document.  Using the questions above as a springboard, work with your followup team to poke holes in the system and try to break it.  Empower your followup team to fix anything that is incomplete or broken.  This action is complete when you have thoroughly tested the assimilation processes and made the necessary updates to ensure they will work on the Opening Day of worship gatherings.', 'template: standard  2017-06-20 resource links updated --pb  2017-12-29 content updated --pb  2020-12-16 changed Due in # Days from 237& to 241& --pb &  2020-01-24 content updated --pb  ', 0, 'todo', 219, 7, '{}'::jsonb),
  ('7ab56661-a691-5015-90ea-0ac24f3fb18f', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Pre-address predictable post-launch challenges', 'Set goals and pre-address predictable challenges that will come in the first months of the regular worship gatherings.', 'The Opening Day of worship gatherings isn''t the finish line; it''s the starting line. What a shame it would be to arrive at Opening Day and have no plans or vision for the next Sunday!  A vision for the future will help you proactively shape the future. Don''t become so consumed in pre-launch activity that you miss looking beyond the Opening Day. Here are 4 predictable things that will happen if you have no post-launch goals:  You Lose Focus  - healthy, growing churches are always looking to the future and how to reach for the next level. If you''ve never thought past Launch Sunday, you''ll soon find yourself wandering aimlessly, or worse: following a clear path to a lesser future.  People Don''t Stick  - you''ll will see an influx of guests. Whether they stick or not will be influenced by the consistency of your followup processes and by your road map for the first year after launch. If you''re not reviewing the effectiveness of your followup and/or don''t have clear onramps for people to get connected, you''ll find yourself with a big back door.  Money Gets Tight  - you can run into financial problems in the months after launch if you''re not watching projected cash flow and bank account balances. How are you doing against your budget? You need to know, both for budgeted expenses AND budgeted income.  Momentum Stalls  - if you make Launch Sunday your goal, people will be prone to take their foot off the gas pedal soon after the grand opening. That''s exactly when you need everyone leaning in.  Deal with these challenges by naming them and heading them off at the pass during the pre-launch phase. Once the excitement of the Opening Day of worship gatherings begins to dwindle, you should already be casting vision for next steps. Provide needed encouragement to the troops and lead the charge.', 'Talk with several other seasoned planters about their experience, challenges and recommendations regarding the months after they launched worship gatherings. What were their biggest challenges? What would they do differently?  Make a list of predictable challenges that will occur during your first three months. Begin proactively preparing your Launch Team for these obstacles.  Identify at least 3 specific and measurable things that you could do during the first three months to proactively address your predicted challenges.  This action is complete when you have written out immediate post-launch expectations.', 'template: standard  2017-12-29 content updated --pb&  2020-01-24 content updated --pb  2020-12-16 changed Due in # Days from 223& to 227& --pb  ', 1, 'todo', 226, 7, '{}'::jsonb),
  ('f7aa7a5b-b900-51b5-b3c3-44fdf5e9135f', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a Year-One scorecard', 'Set goals and measures for the year following the launch of worship gatherings.', 'The traditional scorecard for the American church is butts, bucks & buildings; an incomplete scorecard at best. You get the chance now to create a better scorecard that helps shape and reinforce the DNA of this new church.  What gets measured gets done. Reverse engineer what health looks like at the first anniversary of the Opening Day of worship gatherings and create metrics and reports around those things.  Look back to your  Vision Frame  and consider the ''vision proper''. That was an early exercise in dreaming about where the church should be headed. What are the steps you''d need to take to get closer to that preferred future? What could you measure between the Opening Day of worship gatherings and the first anniversary that would keep you on track?  Consider setting goals in the following broad categories:  Small groups  Community Service  Baptisms  Attendance  Diversity  Assimilation  Offerings  Generosity (giving money and people away)  Ministry Teams  Leadership  Church Planting  Whatever your scorecard, consider the trade-off: measuring anything creates administrative burden. There are literally hundreds of things you  could  measure, but you''d have to hire extra staff just to measure stuff. Choose the things that are most important, balancing information against the cost of measurement.  Work with your church management software champion to create reports or dashboards that will show you month to month how the church is doing. Enforcing this discipline will help you in a couple of ways:  You''ll have information to make better decisions  The first reports will quickly show whether you have adequate systems in place to measure the right things; if they don''t reflect what you know to be true, your team has some infrastructure to build out', 'Prayerfully consider what is to be measured over the first year of the church.  Establish a baseline - where is the church on each these measures right now?  Prayerfully set S.M.A.R.T. goals for where the Spirit is calling you to be at the first anniversary.  Work with your ChMS champion to create monthly reports or a monthly dashboard that will measure your progress.  This action is complete when you have established goals for each metric and reviewed them with your coach and Management Team (oversight).', 'template: standard  2017-12-29 content updated --pb  2019-11-20 title updated from "Get Everyone Praying" --pb  2020-12-16 changed Due in # Days from 230& to 234& --pb &  2020-01-24 content updated --pb  ', 2, 'todo', 226, 7, '{}'::jsonb),
  ('d1ed018a-ee78-5ff9-8f49-29cfd9c45615', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Plan a Launch Team celebration event', 'Plan something shortly after the Opening Day of worship gatherings to celebrate the people that worked so hard to call the gatherings into existence.', 'Your Launch Team has been working hard. Celebrate their efforts and sacrifice by planning some kind of thank-you event.  Here are some creative ideas:  Cater a lunch or dinner  Reserve the party room at the local pizza place  Cater a picnic  Bring in 2 or 3 food trucks immediately following service  BUT NO POTLUCKS! They already worked hard enough.  Here''s what one planter sent to his team via text:  "You''re Invited! If you consider yourself a part of the [Name of Church] Team, we would love to bless you with a free fun morning at the pumpkin patch. Bring your family to [Name of Patch] on Saturday at 10 am. We''ll meet you at the gate and pay for your entry. Thank you for being part of the team!"  You''re Fired!  A celebration event like this is a great time to disband the Launch Team. Their job was to launch the weekly worship gatherings, and now that''s done. The Launch Team should dissolve into the congregation at large and begin identifying with other ongoing serving teams.', 'Choose a Launch Team celebration event to be held shortly after launch.  Recruit a detail-oriented relative or supporter (NOT someone on the Launch Team) to organize everything.  Invite your Launch Team and their families to come and enjoy.  Consider formally disbanding the Launch Team at the event.  This action is complete when you have invited your Launch Team to the planned celebration event.', 'template:  ', 3, 'todo', 233, 14, '{}'::jsonb),
  ('3b02fba1-dec2-5848-891c-c5638c6deef9', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Plan a prayer event around the grand opening', 'Engage the Prayer Team and Launch Team in praying during the lead up to the Opening Day of worship gatherings.', 'Spiritual warfare is real. But the prayers of the righteous are powerful and effective.  Covenant with yourself to do something to elevate the temperature of prayer in the weeks leading up to the Opening Day of worship gatherings. Here are a couple of ideas:  Prayer Walk  - get together and pray through the community and/or around the facility  Prayer Vigil  - orchestrate constant prayer over 24 hours (or some other period of time); <a href="https://www.signupgenius.com">SignUpGenius.com</a> can be a helpful tool  Prayer Campaign  - orchestrate prayer over a week or month on given days or at specific times each day  Choose the one (or combination) that best suits your people, prayer teams and particular situation.', 'Decide how to get everyone praying and when you want it to happen - include length, start time, end time and communication channel(s).  Cast vision for the event amongst your Prayer Team and Launch Team.  Make it easy to sign up.  Conduct the prayer event.  This action is complete when people have begun signing up for the prayer event.', 'template: standard  2017-12-29 content validated --pb&  2020-01-24 content updated --pb  2020-12-16 changed Due in # Days from 252& to 260& --pb  ', 4, 'todo', 233, 14, '{}'::jsonb),
  ('a688e7ab-c836-5e53-ae1b-f1743d317c84', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get well-wishers to come on 2nd or 3rd Sunday', 'Guard your team''s morale by inviting well-wishers to come that week instead of on launch Sunday.', 'There was once a new church that saw 193 people show up on Opening Day. This was significantly more people than they were expecting, so they figured the following Sunday they''d see a dip in attendance, but when only 33 people showed up the following Sunday, they were devastated. They knew not everyone from Opening Day Sunday would return the following week, but seeing only 17% return made them wonder what they did wrong. They felt rejected.  The chief reason this church plant saw such a drastic dip in attendance after Opening Day was not because the preaching was boring or the worship was horrendous. It was because so many well-wishers came on that first Sunday. These well-wishers were friends and family who came to show their support of the new church. However, come week two, they were back worshipping at their own churches.  While there''s nothing wrong with well-wishers attending worship gatherings to show their support, unless they''re coming to serve, invite them to visit on the 2nd and 3rd Sunday instead of Opening Day. That way when attendance dips those subsequent weeks, the well-wishers will be there to help with critical mass.', 'Develop a list of potential well-wishers (parents, financial supporters, friends from other churches).  Contact these potential well-wishers, inviting them to pray for your opening day and to attend on the 2nd or 3rd Sunday instead of launch Sunday.  This action is complete once you''ve invited well-wishers to visit on a Sunday that''s not opening day.', 'template:  2022-05-16 tweaked content --pb  ', 5, 'todo', 233, 7, '{}'::jsonb),
  ('05758971-8eee-52e0-9358-638221432922', '5c3ae2d7-e051-5fb6-b0bb-aebea57154a3', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Review the Launch Sunday Checklist with your teams', 'Use your customized Launch Sunday Checklist to lovingly drill your teams to make sure everything is in place and ready.', 'There are so many moving parts, processes and systems that need to be in place for Launch Sunday that it would be easy for something to slip through the cracks. Help your teams cover all their bases by reviewing all of those processes and systems with them.  Use Passion for Planting''s Launch Sunday Checklist as a helping tool for your teams. Review it all together at a Launch Team meeting or review it individually with each ministry team. Optionally, you could send a copy to each of the team leaders, have them review their section with their team and then report back to you.  The end result will be a list of things that need to be addressed - the completed checklist becomes a handy to-do list for your ministry teams. Make sure anything missing or broken gets fixed.', 'Download and review Passion for Planting''s <a href="/resources/item/147">Launch Sunday Checklist</a> with your team(s).  Cross off all the items that have been completed.  Make a list of items that need to be addressed and assign each to a specific person.  Empower your teams to make the necessary changes.  This action is complete when you have reviewed all the items on the checklist and ensured plans are in place for everything that needs to happen between now and the Opening Day of worship gatherings.', 'template: standard  2017-12-29 content updated --pb  2020-12-16 changed Due in # Days from 223& to 227& --pb &  ', 6, 'todo', 240, 7, '{}'::jsonb),
  ('12e60840-c069-5373-8e0b-f9644946f6a5', '611a7f89-b2a5-583b-9adf-d7b0064d7c24', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit prayer partners', 'Invite people to opt in to your Prayer Team and increase the prayer covering of your church plant.', 'Allow people to opt in to your intercessory Prayer Team updates rather than spamming them and forcing them to opt out. It honors them to give them a choice in the matter.  One or two initial email blasts or social media invitations to invite people to join is appropriate. Decide how you''ll send out invitations and what expectations you''ll communicate, both for them and for you.  Get a minimum of 10 people praying regularly immediately. Especially approach those individuals who are known to be consistent prayer warriors. Then grow your list to several dozen or even  several hundred .', 'Use the contact list you brainstormed in a previous PlanterPlan action.  Contact them about being on your prayer team.  Add an online sign-up form to your supporter website or social media page so that people can continue to join.  This action is complete when you have received commitments from  at least 10  people to pray on an ongoing and regular basis for you, your family and the new church. But set your sights on 100.', 'template: standard  2017-05-31 content updated --pb  2019-11-22 content updated --pb  2020-12-11 changed Due in # Days from 14 to 28 & Duration from 7 to 14 --pb ', 0, 'todo', 27, 14, '{}'::jsonb),
  ('0a08ca38-e117-50d1-a5cd-cb0f407af2f2', '611a7f89-b2a5-583b-9adf-d7b0064d7c24', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Initiate regular Prayer Team updates', 'Initiate regular Prayer Team updates so that they can most effectively present your requests to God.', 'Passion for Planting recommends weekly communication with the prayer team. This is frequent enough to stay in the minds of the team members, but not so frequent as to be annoying.  The weekly update is a great way to celebrate wins and God''s provision and to keep people informed of needs.  Suggested initial prayer requests:  You - You need God''s wisdom, patience and strength  Your family - specifically balance and health in your marriage and family  Protection - Satan will attack you, your family, and anyone who wants to join you  Vision - that God would guide your planning and give you a clear vision for the new church  Finances - only God can provide  Consider rotating through the following in your ongoing, regular updates:  Completed milestones from your launch plan (especially big decisions like choosing a name or selecting a facility)  Unexpected blessings and provisions (key contacts and relationships in the community, unexpected financial donations, etc.)  Answers to prayers (finding a location to meet)  Upcoming launch plan actions  Your biggest celebrations and your biggest concerns  Financial status  Staffing status  Facilities status  Spiritual warfare issues  Be consistent. You absolutely have to send updates regularly, so keep the system lightweight. If you are not a detail-oriented person, consider recruiting a prayer team champion who will own communicating to the Prayer Team.', 'Craft a simple communications template that you can easily reuse in sending out regular updates.  Send out the first prayer team update.  Recruit someone to hold you accountable to sending regular updates.  This action is complete when you have set up each medium and sent the inaugural prayer update.', 'template: standard  2017-05-31 content updated --pb  2019-11-22 content updated --pb  2020-12-11 changed Due in # Days from 35 to 30 --pb ', 1, 'todo', 29, 7, '{}'::jsonb),
  ('84817603-2d32-5762-9fbd-e69946a4ad8d', '66b5661c-2739-572c-b538-f99e336debd8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this service streaming overview', 'Understand why streaming devotionals, sermons or worship services prior to the launch of in-person worship gatherings is becoming a non-negotiable.', 'There are several reasons you should stream content prior to gathering weekly in person.  People Will Check You Out Online  Before you go to a new restaurant, hotel, dentist, etc. you check them out online, right? You want to know what their offerings are and what people are saying about them. The same will be true of your in-person worship gatherings.  Come your first anniversary, it''s highly likely that guests will have binge-watched your church''s video content before showing up in person the first time, even if they''ve been invited by a friend.  If you start posting sermons & similar content only beginning with your grand opening of in-person worship gatherings, what will people base their decision to come on? You need to have a library of sermons, lessons, devotionals and/or even worship services already published.  Launching streaming content will allow you to engage with people now  and  provide the discipline to create content consistently.  You Can Reach People Now  There are some people in your community that you''ll never meet unless you run into them online. And whether it starts with a social media interaction or else-wise, especially online they''re going to check you out first.  If that''s where they''re spending hours and hours each day, meet them where they live and be ready to engage them with content.  It Helps Your Website Rank  It takes time and consistency to get found by search engines like Google. Would you rather get to the grand opening in complete online obscurity or with established online credibility and web rank?  The hands-down best thing you can do to increase your website rank is to post new, relevant content on a regular basis.  Fortunately, launching streaming content is easier than ever and not terribly expensive. And there are different ways to approach it; it is not one-size-fits-all.', 'Read the content above.  Commit to planning out some version of a streaming content launch that will happen ahead of the launch of in-person worship gatherings.  This action is complete when you have read the content of this overview.', 'template:  ', 0, 'todo', 91, 1, '{}'::jsonb),
  ('e3406c8c-943f-57e4-ac43-2b52d04daf8b', '66b5661c-2739-572c-b538-f99e336debd8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about launching streaming content', 'Open a conversation with your coach about how to utilize streaming teaching and/or worship as a steppingstone toward in-person worship gatherings.', 'The pandemic forced churches to create an online church option, which has quickly become an expectation that all churches follow suit. Talk to your coach about how you will utilize a content streaming launch as part of your overall launch strategy.  Sample issues to process with your coach:  What the coach has learned recently about having taken their church online  How similar or different online church should be to in-person worship gatherings  Whether to edit video in-house or hire it out  Which platform(s) to stream or broadcast on  When to start streaming content in relation to the in-person launch', 'This action is complete when you have called your coach about launching content streaming.', 'template:  2021-04-19 video content added --pb  2022-01-20 changed "digital launch" to "streaming content" language, updated broken video link ', 1, 'todo', 97, 7, '{}'::jsonb),
  ('87c1ffc5-a07e-59a6-a33f-24e90aada533', '66b5661c-2739-572c-b538-f99e336debd8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Content Streaming Launch Strategy', 'Put together a document that includes your philosophy and strategy for using a content streaming launch strategy in conjunction with your in-person launch.', '[content pending]', NULL, 'template:  2022-01-20 changed "digital launch" to "streaming content" language; fixed broken video hyperlink --pb ', 2, 'todo', 104, 7, '{}'::jsonb),
  ('89898f16-4ffe-577a-ba3e-80931ac14e34', '66b5661c-2739-572c-b538-f99e336debd8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: Review and affirm Content Streaming Launch Strategy', 'Ensure the planter has made contextual decisions on how to utilize streaming devotionals, sermons or worship services in conjunction with the launch of in-person worship gatherings.', 'Review the planter''s Content Streaming Launch Strategy document. Either encourage the planter to rework the insufficient section(s) or affirm that it is a workable and contextual strategy.  The document should include:  A definition of ''success'' and/or goals for a content streaming launch  A strategy to reach non-christians and what that target audience looks like for them  An understanding of the content that the target audience expects  A strategy to get participants to interact online and begin forming community', 'Review the planter''s  Content Streaming Launch Strategy  document and provide feedback where necessary.  This action is complete when you, the coach, have reviewed and affirmed the planter''s Content Streaming Launch Strategy document.', 'template:  ', 3, 'todo', 111, 7, '{}'::jsonb),
  ('a8ae9d56-c625-5eaa-9be2-33b53daa7b01', '66b5661c-2739-572c-b538-f99e336debd8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase AVL hardware for content streaming launch', 'Get your hands on the equipment you''ll need to stream or broadcast online content.', '[content pending]', NULL, NULL, 4, 'todo', 111, 7, '{}'::jsonb),
  ('1995f88e-80a1-5097-8ef5-809b4d0e1936', '6b7c39eb-4653-5796-8d7d-d30a90c5d6ec', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Read this evangelism & disciple-making overview', 'Understand the key elements of a Disciple-Making Strategy and how it relates to evangelism.', 'Planting churches  was not Jesus'' Great Commission. That''s challenging.  He sends us to make disciples of all nations, baptizing them in the name of the Father and the Son and the Holy Spirit, and teaching them to obey everything He commanded us.  When we see making disciple-makers as our job, then everyone we meet is someone we can help on their journey to becoming a disciple-maker themselves:  If they aren''t already trusting and following Jesus, then they need to hear the Good News and be challenged to respond  If they trust Jesus but aren''t a disciple-maker, they need tools, experiential training and loving accountability  If they''re an obedient disciple-maker, then they''re an ally and co-laborer  When disciple-making multiplication takes hold, churches inevitably result.  "As wise stewards of the mystery of Christ, we must subscribe to a definition of biblical church planting as evangelism that results in new churches. Or, to communicate it in other terms: disciple-making that results in new churches." <a href="https://vergenetwork.org/2013/09/09/why-jesus-never-commanded-us-to-plant-churches/">J.D. Payne</a>  The danger we fall into is wanting to plant churches so that we can reach people for Christ. That''s completely backwards.  "Don''t plant churches  for  evangelism. Plant churches  through  evangelism." unknown  Especially because the Western Church hasn''t done this well for years, perhaps generations, you need to be clear about your disciple-making process. It needs to scriptural, prayed through, and easily reproducible.  The tasks in this milestone will help you write down your disciple-making process, which will include getting out there and ''evangelizing'' your community (identifying new disciples).', 'Watch Jim Putman''s video <a href="https://www.youtube.com/watch?v=fDE-uVpMqzM">Discipleship at the Core</a> by Exponential.  This action is complete when you have watched the video and read the overview above. "', 'template:  2019-10-14 new task --pb  2020-12-11 changed Due in # Days from 14& to 21& --pb ', 0, 'todo', 14, 1, '{}'::jsonb),
  ('da45b800-7819-5ffa-bc08-f44ba6ce4e19', '6b7c39eb-4653-5796-8d7d-d30a90c5d6ec', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Call your coach about evangelism & making disciples', 'Open a conversation with your coach about making disciples that make disciples.', 'You may or may not have ever experienced healthy disciple-making, the kind that reproduces generations of disciple-making disciples. You may have to learn some new skills and unlearn a few old habits or assumptions.  You need to come into this church plant with a clear & compelling vision for making disciple-makers, along with a simple, reproducible process for getting it done.  Sample issue to process with your coach:  The relationship between evangelism and disciple-making  The difference between information and obedience  How to get to the 3rd generation of disciple-makers before launching weekly worship gatherings  Ways that the coach has experienced Biblical disciple-making', 'This action is complete when you have called your coach about evangelism and disciple-making.', 'template:  2020-12-11 changed Due in # Days from 28& to 43& --pb ', 1, 'todo', 20, 7, '{}'::jsonb),
  ('79aed685-16bd-5ce6-b75a-ad54e629c8f8', '6b7c39eb-4653-5796-8d7d-d30a90c5d6ec', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft a Disciple-Making Strategy', 'Draft a comprehensive strategy for launching a disciple-making movement.', 'How you make disciples is ultimately how your disciples will make them, too. Now is the time pray & think through what you''re going to do and how.  Making disciples is the Church''s God-given mandate.  Devoted disciples attract people outside the church because of the change others see in their Christ-like lives. And they reproduce themselves in others, refusing to be the last link of the chain stretching all the way back to the first Disciples.  The purpose of this Disciple-Making Strategy is to imagine and implement a biblical process to empower Christians to be more like Christ as they intentionally develop relationships with not-yet-believers.  It''s safe to say that Jesus was the best disciple maker of all time. The things we see him doing in the Gospel accounts should inspire how we approach discipleship and how we create environments and processes that multiply disciples.  Using the  Disciple-Making Strategy Template  (<a href="/resources/item/321">MS Word</a> or <a href="/resources/item/361">Google Doc</a>), you will work through the following:  Why disciple-making?  Disciple-making in the Bible  Disciple-making at your church  Disciple-making in our community  Your approach  The tools you''ll use  Digital Tools  When someone comes to faith at your church, what resource(s) do you offer them to help them take next steps in their spiritual development? Many churches are seeing the benefit of offering new believers a spiritual starter kit to guide them towards maturity and challenge them to put their new faith into practice. (For the early church it was simple creeds) Will your church have such a resource to help new believers invest in their relationship with God? While this resource could be a physical book or pamphlet, we recommend you equip people with a digital resource, so they can easily access it, not worry about misplacing it, and freely share it with their friends. Here are some examples:  <a href="https://www.startingwithgod.com">Starting With God</a>  <a href="https://thechapel.com/site/assets/files/6625/yourfirstweekdevotional_2020.pdf">Your First Week As A Disciple</a>  <a href="https://www.bible.com/reading-plans/13502-start-here-first-steps-with-jesus">Start Here</a> - Bible Reading Plan  Resources like these are not intended to take the place of personal, relational discipleship, but could serve as an initial guide for that discipleship relationship and as a springboard to help new believers begin feeding themselves and others spiritually. Develop this resource yourself or use content that''s already been created.', 'Download Passion for Planting''s  Disciple-Making Strategy Template  (<a href="/resources/item/321">MS Word</a> or <a href="/resources/item/361">Google Doc</a>).  Work through the content above and the subsequent PlanterPlan subtasks; record your thoughts & decisions in the template.  Interview leaders of other disciple-making movements you respect about their structure and systems.  Finalize your Disciple-Making Strategy.  Send the completed Disciple-Making Strategy to your coach for feedback.  This action is complete when you have submitted your written Disciple-Making Strategy to your coach.', 'template:  ', 2, 'todo', 233, 220, '{}'::jsonb),
  ('c154caf9-dcd5-50d0-8a84-04800cc14636', '6b7c39eb-4653-5796-8d7d-d30a90c5d6ec', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Coaching Checkpoint: review and affirm planter''s Disciple-Making Strategy', 'Review the planter''s Disciple-Making Strategy document to provide feedback and ensure it will be simple and reproducible.', 'The Disciple-Making Strategy document should incorporate all of the following:
INSERT INTO public.tasks (id, parent_task_id, creator, origin, title, purpose, description, actions, notes, position, status, days_from_start, duration, settings) VALUES
  ('47ff111b-e9bb-5a52-90b1-9f2fb6931002', '012af6fa-5734-5c29-bd6c-a865e099c7fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Draft Articles of Incorporation', 'Fill out the required paperwork to establish the new church as a legal entity in its state.', 'You will need to decide whether to prepare the Articles yourself or have someone else do them. The good news is that this has never been easier with all of the help available online.  Most states have websites that provide step-by-step instructions for preparing and submitting nonprofit Articles of Incorporation. Often they include a template the church may use. Some state require you to file online through their website, but for most states you''ll mail or walk them in. Considering downloading Passion for Planting''s <a href="/resources/item/8">Articles of Incorporation Template</a> as a starting point.  Articles of Incorporation should be kept to a minimum, typically three pages or less, and should include the minimum required information. They are difficult to amend, so only include the information required by the state and the IRS for 501c3 purposes, and not much more.  State Requirements  Call your <a href="https://www.llcuniversity.com/50-secretary-of-state-sos-business-entity-search/">Secretary of State''s office</a> to find out if they have any other filing requirements:  Must we use your form, or can we use our own custom format if it covers your basic requirements?  Do you have to use "Inc." or similar in the name?  Does it have to be notarized?  If you''re filing from out of state, do they accept digital or facsimile signatures (so it can be emailed to a friend to walk it in)?  Does the Registered Agent have to sign an acceptance statement?  Does it need to be published afterwards in a local paper or law journal?  Will I automatically receive the Certificate, or will I need to download it from somewhere?  What are the current filing fees?  What are current processing times? If you''re in a hurry, is there an fee for rush processing?  Are there any other tips or tricks we should know about as we incorporate our new church?  In some states (GA & AZ at least), you have to publish the incorporation in a local paper, usually within 24-48 hours. In Louisiana, you have to register your approved Articles with your local Parish within 30 days. Heads up!  You will need to submit some or all of the following in your Articles of Incorporation (in descending order of commonality between states):  Unique legal name  Name of the incorporator (the person calling the corporation into existence)  Physical address of corporation  Name & address of your Registered Agent (aka Agent for Service of Process, Statutory Agent)  Purpose clause that satisfies IRS requirements  Dissolution clause that satisfies IRS requirements  Additional provisions that set you up for IRS 501c3 nonprofit status  Names & addresses of initial Directors  Whether or not church members will have voting power  Mailing address of corporation  If you are working with a denomination or other affiliation, check with them regarding things they require you to include  Church Bylaws, which are easier to change and do not require state approval, are typically a better place to put the other things you may be tempted to include in the Articles.  IRS Requirements  Your state may not require this to be included, so it''s all too easy to file paperwork that satisfies your state but not the feds. Include this wording now to avoid problems later when filing your 501c3 application:  a Purpose Clause  This corporation is a RELIGIOUS CORPORATION and is not organized for the private gain of any person. It is organized under the Nonprofit Religious Corporation Law exclusively for religious purposes. This corporation is organized and operated exclusively for religious purposes within the meaning of Section 501(c)(3) of the Internal Revenue Code.  a Dissolution Clause  Upon the dissolution of this corporation, after paying or adequately providing for the debts and obligations of the corporation, all assets shall be distributed to [Name of Benefactor] which operates within the meaning of Section 501(c)(3) of the Internal Revenue Code. Should [Name of Benefactor] no longer exist, all remaining assets shall be distributed for one or more exempt purposes within the meaning of Section 501(c)(3) of the Internal Revenue Code or shall be distributed to the federal government, or to a state or local government, for a public purpose. Such distribution shall be made in accordance with all applicable provisions of the laws of the state of [Name of State].  On Forming a Board of Directors  Most states will ask for contact information for the initial Board of Directors. Reference the previous PlanterPlan task  Form a Management Team (oversight)  if you do not already have a Board in place.  The Registered Agent  Most states require the name and address of an individual  in that state  who will serve as the Registered Agent (aka Statutory Agent, Agent for Service of Process). This is the state''s point of contact if legal papers have to be served (e.g. summons, subpoena).  The Registered Agent is not held liable for anything the church does or does not do; the agent is just a messenger. If the planter has not already moved on site, he''ll have to find someone in the destination state to volunteer. If he doesn''t know anyone that already lives in the target state, he should network with his affiliation of churches to find someone willing to be his Registered Agent.', 'Decide whether to prepare the Articles yourself or to pay a professional.  Prepare the Articles of Incorporation based on state and church planting network guidelines.  Review the Articles of Incorporation (with a lawyer if necessary) to ensure they meet the needs of the church.  Approve the Articles of Incorporation (typically signed by an officer of the organization).  This action is complete when you have signed the finalized Articles of Incorporation.', 'template: standard  2017-05-24 content updated --pb  2019-12-10 content updated --pb  2021-01-18& outdented& from child to& parent task; due it days changed from 52 to 60 --pb ', 0, 'todo', 52, 14, '{}'::jsonb),
  ('763e2f7a-52e0-5b3c-bb40-719a863cdbd0', '012af6fa-5734-5c29-bd6c-a865e099c7fa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Submit Articles of Incorporation', 'File the completed paperwork and get officially incorporated in your state.', 'Filing the Articles of Incorporation can be done online (in most states), in person, by mail, or by fax. The filing option you choose will have timeline implications.  The Articles of Incorporation are an important first step in getting the church legally formed. You won''t be able to pay salaries until you''ve done the following:  obtained a Federal EIN (see subsequent PlanterPlan action)  opened a checking account, and  filed for appropriate state employer tax numbers  You can''t do any of these until you''ve incorporated. It is best to get the approved Articles back as quickly as possible.  If you''re Filing Online  A word of caution - some of the states that require you to file online do not make it easy to include the extra language you need to make the IRS happy (see previous PlanterPlan task  Complete Articles of Incorporation ). Look for an ''Other'' field or ''Upload Addendum'' function.  If they don''t allow you room for those important clauses (Kansas is a particular culprit), then you''ll either have to file online and then submit an addendum later, or forgo the online option and mail in good, old-fashioned papers.', 'Determine if and where the Articles can be filed online with your state.  Create an online required as required.  Complete all the fields  and be sure to include the clauses the IRS will require  .  If it is impractical or impossible to file them online, then determine which mailing address or fax number to send the paperwork to. Be sure to include proper payment or the papers will be delayed and/or returned.  This task is complete when you have successfully submitted the Articles of Incorporation to the state along with proper payment.', 'template: standard  2017-05-24 content updated --pb  2019-12-12 content updated --pb  2020-12-14 changed Duration from 14& to 7& --pb&  ', 1, 'todo', 59, 15, '{}'::jsonb),
  ('a6e8c3cd-3af9-53d2-a801-9212334a7187', '02d259d8-601d-582d-94eb-ed60825537f8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit hospitality team leader', 'Identify and empower a relational, reliable leader for the hospitality team so that  every guest feels welcomed and accepted at the worship gatherings.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has both leadership potential and emotional intelligence.  Your hospitality team leader needs to quickly embrace the values of the church; they''ll be responsible to live them out and communicate those values to team members.  Consider writing out a job description and basic expectations you''d have of any hospitality team leader. Go over those with your candidate and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  recruiting team members  scheduling a training event  scheduling volunteers so that there are no gaping holes in the schedule', 'Spend time in prayer asking God to raise up leaders.  Identify a person to lead the Guest Services Team.  Communicate expectations to the leader.  Get a a commitment from the leader to own the processes and leadership of the team.  This action is complete when you have recruited and trained a hospitality team leader.', 'template: standard  2017-06-07 content updated --pb  2018-11-16 content updated to match Greg Curtis'' content in our strategy template; moved to child task of "Issue Written Assimilation Strategy" from parent ID #776& --pb  2012-12-02 content updated --pb  2020-12-16 changed Due in # Days from 137& to 155 --pb&  ', 0, 'todo', 212, 14, '{}'::jsonb),
  ('1f4dda8e-79f6-5664-ac73-ae004c90ce26', '02d259d8-601d-582d-94eb-ed60825537f8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train greeters', 'Train a team of greeters who will create a warm and friendly atmosphere for everyone attending the worship gathering.', 'The Lobby Has Moved  The greeters out front and in the lobby used to be the first impression guests would have of your church. But by and large, guests who come have been stalking your church online for weeks or months. By the time the show up, the have heard sermons, seen social media posts, read the staff bios, etc.  But they still need a friendly face when they show up. And that face sets the tone for their whole experience while they''re there.  Train in Emotional Intelligence (EQ)  IQ is fixed from birth. But someone his is book smart doesn''t necessarily make the best greeter. Any warm body out front won''t do the trick.  The good news is that EQ can be learned, and people who seem to have it naturally can get even better. Search online for blogs, podcasts and videos for your team.  Effective greeter training will include:  a basic outline of what to say and/or a few low-threat conversation starters  underscoring the importance of eye contact and body language (as much as <a href="https://en.wikipedia.org/wiki/Nonverbal_communication">89% of what we communicate is nonverbal</a>)  basic information about the church (location of restrooms, children''s ministry classrooms) and whom to find if they don''t know the answer  escorting guests to places they''re trying to find, never pointing  making conversations with kids while escorting new families to the children''s ministry area, introducing them to the teacher', 'Find training material for your greeters, especially covering EQ.  Schedule a greeter training time, even if it is on a Sunday morning before the worship gathering.  Train the greeters.  This action is complete when you have trained the greeters.', 'template: standard  2017-06-07 content updated --pb  2020-01-20 content updated --pb  2020-12-14 changed Due in # Days from 238& to 228& & Duration from 21& to 28& --pb&  ', 1, 'todo', 227, 14, '{}'::jsonb),
  ('f54fc862-0cc7-56f8-a84b-f32f86f03820', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Research current events in the community', 'Investigate local events, festivals and causes that you may be able to partner with.', 'Western Christianity has a reputation for having a savior complex. You can minimize the "We''re here to save the day!" effect when you partner with the good that''s already happening in your community. There are major and minor events already happening all over your community that provide ample opportunity to jump in and help.  To choose the best events to reach your target community, first understand what events are already happening in the community, and which are successful. This will help you determine which events best meet real needs in your community.  Look for opportunities to participate in and even partner with local events. Participating might look like:  renting a booth for a hydration or diaper changing  staffing a children''s bounce house or play area  recruiting a team to clean up after the event  etc.  Many events have local sponsors who receive lots of publicity for sponsoring the event. Check into the cost of sponsorship to see if it''s affordable.  Sites for researching community events:  <a href="https://www.meetup.com">meetup.com</a>  <a href="https://nextdoor.com">nextdoor.com</a>  <a href="https://www.eventbrite.com/">eventbrite.com</a>  <a href="https://www.facebook.com/groups/explore/">facebook.com</a> - look for community groups  <a href="https://craigslist.org">craigslist.org</a>  <a href="https://patch.com">patch.com</a>  your local online newspaper  your local <a href="https://www.chamberofcommerce.com/chambers">chamber of commerce</a>  your city''s website  Also do some offline research: check out local HOAs and community associations. And ask your friends and neighbors about events they know of, especially ones they usually attend.  Don''t try to compete with local events. They''re usually done on a larger scale and with more excellence than a new church has the resources to pull off. Rather than investing all of your time in creating your own events from scratch, partner up.', 'Using the sites & ideas above, compile a list of your community''s events.  Determine which events to partner with and add these events to your outreach strategy document.  This action is complete once you have compiled a list of current community events and determined which events can be partnered with.', 'template: standard  2018-02-16 content updated --pb  2012-12-02 content updated --pb  2020-12-14 changed Due in # Days from 119& to 121& & Duration from 14& to 7& --pb&  ', 0, 'todo', 120, 30, '{}'::jsonb),
  ('4e2d4c39-9f90-58b4-bb4c-b86c4040132b', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Identify opportunities to partner with existing community leaders', 'Investigate other organizations and churches in your community that are already addressing the need(s) you''ve identified.', 'As you talk to individual community leaders, you''ll probably start to notice recurring themes and patterns of community needs. When that''s the case, you''re not the only one to have noticed. Chances are there''s already at least one organization in the community that is addressing that need(s).  Ask around. Who are those groups? Who leads them? What are their events and programs? Who else can each of them introduce you to?  Also dig around online. Do general searches based on the need and the name of your city. You can also look for directories of nonprofits in your area:  <a href="https://www.guidestar.org/NonprofitDirectory.aspx">GuideStarg.org</a>  <a href="https://www.melissa.com/v2/lookups/">MelissaData.com</a>  <a href="https://apps.irs.gov/app/eos/">Exempt Organization Select Check</a> on IRS.gov  When you partner with existing groups, it often results in your launch team serving side by side with pre-Christians who share a passion for meeting a specific need. That creates opportunities for your launch team not only to meet needs, but to build bridges with pre-Christians as they serve alongside them.', 'Strategically evaluate the community need(s) God is calling you to address.  Investigate who is already meeting these needs in the community.  Evaluate and document the opportunities for partnerships with various community leaders and groups.  This action is complete when you have developed a list of partnership opportunities.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2018-02-16 content updated --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 132& to 128& --pb ', 1, 'todo', 120, 30, '{}'::jsonb),
  ('ad2013ad-a7d2-570c-8f7c-f2bd1ca758c6', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Assess passions and resources of launch team', 'Lay the groundwork for successful outreach by discovering the common heartbeat of your people.', 'Once you''ve identified community needs, assess not only your own passions, but also the passions of the team of people God has gathered to start the new church. Where their needs intersect with your team''s passions will be the heart of missional ministry.  Review the results of your own community needs research with them. See which needs resonate with the team. Ask the team how they would begin to meet the needs and what resources would be needed.  Also consider your team''s skills, professions and life experiences. It''s not unusual to find a common thread that wasn''t initially apparent. For instance, you may discover that half of your team works in the medical field. Or most of the team already volunteers for various nonprofits that protect the environment.  Also re/visit the <a href="/resources/item/356">Collective Potential worksheet</a> provided by Auxano previously addressed in the Philosophy of Ministry milestone.  Pray that the Spirit reveals what He had in mind when He called your initial team together.', 'Review your community''s needs/assets with the launch team.  Re/visit the <a href="/resources/item/356">Collective Potential worksheet</a> provided by Auxano.  Determine which needs the team is most passionate about.  This action is complete when you have assessed the passions and resources of the launch team.', 'template: standard  2018-02-16 content updated --pb  2012-12-02 content validated --pb  2020-12-14 changed Due in # Days from 119& to 121& & Duration from 21& to 30& --pb&  ', 2, 'todo', 113, 7, '{}'::jsonb),
  ('f75ae4be-79b0-5244-a58f-a5236f270c75', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine your outreach philosophy', 'Articulate an outreach philosophy that will inspire your people to action.', 'Your brief outreach philosophy will answer the  why . Serving in the community won''t be sustainable without a Jesus-centered reason.  Why should the church do outreach?  Why should your people participate in outreach?  What should outreach accomplish?  How does outreach help make disciple-makers?  Given your limited resources, what category/cause will you focus on?  Cross-Check  You developed your Vision Frame in a previous PlanterPlan milestone. Make sure your outreach philosophy fits within your  Strategies  and is consistent with your  Values .  Measuring Success  Decide now how you''re going to measure success. That might be:  Number of marketing touch-points associated with an event  Number of events joined or hosted  Event attendance totals  Number of conversations started with people at events  Number of friends inviting friends to events', 'Review your Vision Frame, especially looking at how your values affect outreach.  Using the principles above, write out a philosophy summary in your Outreach Strategy document.  This action is complete when you have considered and prayed about these options and developed an outreach philosophy for the new church.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2018-02-16 content updated --pb  2012-12-02 content updated --pb  2020-12-14 changed Due in # Days from 119& to 121 --pb&  ', 3, 'todo', 120, 7, '{}'::jsonb),
  ('88975f92-1310-57a7-b43f-89ca16fcd45f', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set a goal for number and type of outreach events', 'Set a challenging but reasonable expectation for how many and what kind of outreach events you''ll execute prior to launching worship gatherings.', 'Too many planters get to opening day and wish they had done more outreach events.  Types of Events  There are at least 3 different categories of events:  With Your Community  - These events focus on partnering with the good that''s already being done in your community  In Your Community  - These events focus on providing fun activities to build trust, create community and provide inviting opportunities for your team; these can be large-scale event you host collectively or smaller-scale events you encourage your team members to host  For Your Community  - These events are focused on community service and meeting real needs around you  A solid outreach strategy has a mix of the different types of events. One approach is to try and partner with other organizations for big, regional events, and to focus most your time and money on smaller, relational events.  Set a Goal  Things that get measured get done. If you schedule 10 events, you''re more likely to actually execute on 7 events than a planter who doesn''t schedule any events but hopes to hit 7. Hope is not a strategy. Set a goal for the number of events you''ll host or participate in.  Passion for Planting  strongly recommends  that the you participate in or host at least  one major event per month  in the 4 months leading up to your launch.  Also consider setting an expectation that every staff person or every family on the launch team will host at least one smaller event (block party, cookout, open house).  At the very least, determine the total number of events you''ll participate in during the 6 months leading up to launch, even if you don''t specify the breakdown of large and small events.  Remember that at this point, you''re setting expectations, not selecting the exact events and dates. Establish the number and type, but be flexible to allow the specific events to change with time--simply hold yourself accountable to the number you set as an expectation.', 'Prayerfully determine how many events you should conduct in the 6 months leading up to launch.  Identify a specific number goal for each of the three major types of events listed above.  This action is complete when you have set a goal for the number of each type of event to be conducted prior to launch.', 'template: standard  2018-02-16 content updated --pb  2012-12-02 content updated --pb  2020-12-14 changed Due in # Days from 119& to 121 --pb ', 4, 'todo', 120, 7, '{}'::jsonb),
  ('e57f7353-98ed-575b-b12b-e39d1015daa0', '079b13eb-7edf-56b1-aaa7-de97eab549b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop a strategy for connecting with people at events', 'Decide in advance how you''ll empower your Launch Team members to build relationships during outreach events.', 'At least one of the purposes of outreach should be starting conversations with strangers and making friends. But that doesn''t come naturally for everyone on your team.  Help them out by laying down some simple guidelines for making connections.  Types of Events  Keep in mind that the strategies will probably be different depending on the category of event:  With Your Community  - These events focus on partnering with the good that''s already being done in your community  In Your Community  - These events focus on providing fun activities to build trust, create community and provide inviting opportunities for your team; these can be large-scale event you host collectively or smaller-scale events you encourage your team members to host  For Your Community  - These events are focused on community service and meeting real needs around you  For example, if you''re partnering  with your community  to clean up the trash after the local festival, your people may have less opportunity to engage strangers. A neighborhood block party hosted  in your community  by a Launch Team family should provide a different level of opportunity. Help your people think through the ''win'' for each type of event.  Simple Tools  There are some simple things you can give to your people that will make connecting easier. Some ideas are:  Have them memorize 2 stock questions for starting a conversation with complete strangers  At a Launch Team meeting, get them to role-play starting conversations  Order professionally-printed handouts like info business cards, bookmarks, or small postcards  Order branded t-shirts for them to wear at the event  Get a banded vinyl banner to hang from the booth you rent at the festival  Order branded promo items like pens or helium balloons  Create a 3-question community needs survey for people to fill out', 'For each type of event, hammer out a simple strategy to empower your people to start conversations.  Order any tools you''ll need for each event.  Train the launch team on how to connect with people; consider some role play so they can practice getting the words out before the event.  This action is complete when you have identified strategies for connecting with people at each outreach event.', 'template: standard  2017-06-02 resource links updated --pb  2018-02-16 content updated --pb  2019-12-10 content updated --pb  2020-12-14 changed Due in # Days from 119& to 135& & Duration from 7 to 14& --pb&  ', 5, 'todo', 120, 7, '{}'::jsonb),
  ('6b00898a-b4a3-5f48-b6aa-9fa872991268', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get several demographic report(s)', 'Collect demographic information to do your missionary homework and become an expert on both your community and the people God is calling you to reach there.', 'As you read these reports, ask the Holy Spirit to identify important variables (ages, incomes, single parents, race, etc.). There will be so many to choose from, it could get overwhelming. Read the reports with intentionality and allow for surprise inspiration.  Paid Demographic Reports  America''s Big Data now tracks virtually everything about each household''s spending habits. They cross reference that against US Census data and other sources to know a startling amount about us. The paid reports below will contain both hard demographics (age, income, race) and soft demographics (for example: how ''green'' they are, how tech-savvy they are, their preferred brands, etc.).  These vendors specialize in providing demographics to churches:  Percept''s <a href="https://www.ministryarea.com/">Ministry Area & First View Reports</a>  MissionInsite''s <a href="https://www.acstechnologies.com/missioninsite/tools/surveys-reports/">Demographic Surveys & Reports</a> and <a href="https://www.acstechnologies.com/missioninsite/solutions/local-churches/">Radius Reports</a>  Barna''s <a href="https://access.barna.com/faithview/#options">FaithView</a> database of spiritual profiles of Americans  Free Demographic Reports  Though sometimes you get what you pay for, these sites still offer a surprising amount of information that will help you understand your community better.  Hard Demographics:  Passion for Planting''s <a href="https://church-planting.net/free-demographic-report/">Free Demographics Report</a>  Data USA''s <a href="https://datausa.io">Community Profiles</a>  <a href="https://data.census.gov/cedsci/profile?g=0100000US">US Census Bureau</a>  City-Data <a href="https://www.city-data.com/">Demographic Reports</a>  US Small Business Administration''s <a href="https://www.sba.gov/business-guide/plan-your-business/market-research-competitive-analysis">various demographic reports</a>  Soft Demographics:  Experian''s <a href="https://www.segmentationportal.com/mosaic7/">Mosaic&reg; segmentation portal</a>  Maps:  Data USA''s <a href="https://datausa.io/map">Demographics Maps</a>  Barna''s <a href="https://www.barna.com/research/2017-bible-minded-cities/">2017 Most Bible-Minded Cities</a>  Barna''s <a href="https://www.barna.com/research/post-christian-cities-2019/">2019 Most Post-Christian Cities</a>  US Census Bureau''s <a href="https://www.census.gov/quickfacts/fact/map/washingtoncitydistrictofcolumbia,US/PST045221">QuickFacts Maps</a>  MelissaData''s <a href="https://www.melissa.com/v2/lookups/mapzip/zipcode/">Zip Code Maps</a> and <a href="https://www.melissa.com/v2/lookups/mapcart/zipcode/">USPS Carrier Maps</a>  Theographics:  Pew Research Center''s <a href="https://www.pewresearch.org/religion/religious-landscape-study/">Religious Landscape Study</a>  ARDA''s <a href="https://www.thearda.com/data-archive/browse-categories">various US Surveys</a>  Wikipedia''s data-packed article on <a href="https://en.wikipedia.org/wiki/Religion_in_the_United_States#ARIS_findings">Religions in the United States</a>  Hartford Institute for Religion Research''s <a href="http://hirr.hartsem.edu/">various theographic reports</a>  Pew Research Center''s <a href="https://www.pewresearch.org/fact-tank/2016/02/29/how-religious-is-your-state/?state=alabama">How Religious Is Your State?</a>  Specialty:  MelissaData''s <a href="https://www.melissa.com/v2/lookups/mapschool/name/">School District Maps</a> and <a href="https://www.melissa.com/v2/lookups/school/name/">Public Schools Lookup</a> (reaching families with kids?)  GreatSchools'' <a href="https://www.greatschools.org/">Demographics by School</a>  Corroborate the Data  Statisticians in offices on the other side of the county can only get so much right. You need to test the data against the real world.  Network in the Community:  Come to local leaders and influencers with the posture of a student and be genuinely interested in learning about the history, strengths & weaknesses of your community.  Use Passion for Planting''s  Networking Strategy Template  (<a href="/resources/item/182">MS Word</a> or <a href="/resources/item/358">Google Doc</a>) to craft an approach to meeting the most strategic people in your community.  Psychographics:  People are funny. There are factors that won''t show up on any demographics reports. These become important when narrowing your target area, and specifically in the location of your facility. Consider:  Which way do people "face" in their attitudes and affinities?  It is often toward the biggest city in the region - they work & shop in that direction and rarely venture in the opposite direction  What boundaries won''t they cross?  Things like rivers, railroads and interstate freeways can be boundaries, but sometimes it''s an invisible line marking a certain neighborhood', 'Pull various demographic report(s).  Review the data to spot trends and insight into the people living within the area.  Summarize your findings in your  Target Area Report Template  (<a href="/resources/item/345">MS Word</a> or <a href="/resources/item/380">Google Doc</a>).  Be prepared to summarize the data for the  Average Target Family  exercise (a subsequent PlanterPlan task).  This action is complete when you have reviewed the demographic reports.', 'template: standard  2017-09-14 content completely overhauled based on free download "Demographic Information for Your Church Plant" --pb  2017-09-14 all hyperlinks verified --pb  2018-05-07 added google doc template version --pb  2019-11-15 links verified & content updated --pb  2020-12-11 changed Due in # Days from 42& to 29& --pb  2020-08-17 links updated --pb  2022-11-21 updated links --sc ', 0, 'todo', 28, 14, '{}'::jsonb),
  ('1be6510a-72ea-51cc-ac16-6d006f288857', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Research local community information and history', 'Understand how your community''s history and heritage shapes its values.', 'To really say you know your area, you need to understand:  What are the values of a specific geographic area?  What history, heritage, and other local factors shape these values?  Are there any ''hot topics'' that either divide or unify the people living in the area?  What is the predominant worldview?  Discover and understand social forces shaping your community. This is your chance to do an old fashioned essay/book report. You''ll go through a data-gathering phase and a report phase.  To collect data, consider doing the following:  Find community history and links to local government, businesses, media etc.  Most cities & towns have some history documented on <a href="https://en.wikipedia.org/">wikipedia.org</a>  Contact the local Chamber of Commerce. Obtain any information they have available. Ask if any local books or literature have been written about the area.  Many communities have historians. Ask around and contact him/her to request an interview.  Check the county/city web site. Often they have a history section.  Contact the local library and ask if they are aware of any local history books or resources.  Find long-term residents in the area and interview them. Seek them out - they are a wealth of information.  After gathering the data/information, turn your findings/conclusions into a written biography of the local area. Consider turning this action into a family action. Have members of your immediate family help with the research and writing.', 'Make a list of sources to pursue and get go after them.  Summarize the history and heritage of the local area in your  Target Area Report .  Include a discussion of how this history shapes the community and whether there are any ''hot topics'' rooted in this history that affect the community today.  This action is complete when you have included your findings in your  Target Area Report .', 'template: standard  2017-10-24 content validated --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 42& to 29& --pb ', 1, 'todo', 28, 14, '{}'::jsonb),
  ('fb9ca576-50fd-5a37-ab08-636446f803fd', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Subscribe to local newspaper, blogs and user groups', 'Sign up for local news & content to become an expert on what is happening in your community and what social forces are shaping it.', 'Become a ongoing student of your community. There are some simple ways to do this regularly:  Read the local newspaper (or community section of a larger paper) religiously. Even better, also get to know the editor and/or any reporter who covers community events.  Subscribe to your newspaper''s blog or online version  Subscribe to the blog of the self-proclaimed expert on your community (there''s usually somebody)  Get on <a href="https://nextdoor.com/">www.nextdoor.com</a>  Join <a href="https://www.facebook.com/groups/explore/">Facebook user groups</a> about your community  Follow community groups on <a href="https://www.tumblr.com">www.tumblr.com</a>  Whenever possible, sign up for push notifications so that you remember to stay current by at least skimming their updates.', 'Subscribe to at least one of the local resources described above.  This action is complete when you have subscribed to local news and updates.', 'template: standard  2017-10-24 content udpated --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 42& to 36& --pb ', 2, 'todo', 35, 7, '{}'::jsonb),
  ('8ab9b906-50ea-5f27-b981-4de1fdfaefd4', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get copies of community growth and land use studies', 'Research where recent growth has occurred in your community and where new growth is planned.', 'Your community is headed somewhere. Growth doesn''t just ''happen''. Someone has been planning for years, conducting studies, issuing reports and proposing plans.  Cities and/or counties create and maintain a  Comprehensive Plan  (also called a  General Plan ,  Land Use Study  or  Master Plan ). This study shows the long-range plan for development of your area. They show future roads, schools, developments, malls, industry, etc. It will answer questions like:  What does the local county/city Comprehensive Plan show are the key growth areas over the coming years?  Where has the most growth occurred during the past 5-10 years?  Where is the most growth expected to occur over the coming years?  Are there any special projects that will affect traffic patterns or growth projections (e.g. new Town Center, etc)?', 'Do an internet search on "[name of my city] comprehensive plan". Alternately, search using its synonyms (above) and/or the name of your county.  Review the land use plans for your area, noting where recent growth has been and where projected growth will be.  This action is complete when you have obtained the studies and reviewed them.', 'template: standard  2017-10-24 content validated --pb  &  ', 3, 'todo', 42, 14, '{}'::jsonb),
  ('b59292f3-7ed0-5282-bcb0-03283755195f', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get initial carrier route maps / information', 'Discover how many "front doors" (dwellings) are within your target area.', 'What are carrier route maps? A carrier route is the group of addresses to which an individual postal carrier (mailman) delivers mail. There are usually multiple carrier routes (and therefore mail carriers) in a ZIP code. They will show you how many residences (both single- and multi-family dwellings) are in your target area.  Why are carrier route maps important? It''s for more than just mail. Carrier route maps offer several benefits:  Budgeting for outreach and marketing.  You can make better plans if your know how many front doors are in your target area. You''ll know, for example:  how many event invitations you''ll need to print  how many door hangers you''ll need to order  what it costs to send a postcard to every home  Discovering natural geographic boundaries.  Carrier routes are often broken down by natural geographic boundaries (e.g. subdivisions, roads, rivers, interstates, etc). These are the same barriers that many people are hesitant (or unable) to cross to attend church.  Concentrating outreach events.  Carrier routes are a great tool to help define the boundaries for outreach. You don''t have unlimited resources, so participating in or hosting events in the same area you''ll eventually market to will help you maximize both.  Getting lowest postage rates .  To get the lowest postage rates, you have to put a postcard in every mailbox on a carrier''s route (a  saturation mailing ), but you don''t have to hit an entire zip code. Knowing the routes in your area will help you define a tight strategic area for your marketing.  How do I get carrier route maps?  <a href="https://www.melissa.com/v2/lookups/cartzip/zipcode/">Melissa Data</a> offers free carrier route information at their site. They also provide a map of each route.  Or you can work with a direct mail vendor that specializes in serving churches (there are several). This is a great way to do an initial interview to see if you''d want to work with them later on marketing.', 'Identify the most important information of interest.  Use one of the means above to get carrier route information and maps.  Review the reports and strategize your target area.  This action is complete when you have received and reviewed carrier route maps for your target area.', 'template: standard  2017-10-24 content & links validated --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 42& to 50& --pb  2022-11-21 updated link --sc ', 4, 'todo', 49, 14, '{}'::jsonb),
  ('5cf6e5c9-1ffb-5a93-abd3-58d661ca7a77', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Research commuting and major traffic patterns', 'Investigate factors that influence which direction(s) people are likely to drive to a worship gathering.', 'Simply targeting people in a 5 mile radius around your worship facility does not take into consideration barriers that may exist that hinder people from traveling to your worship gatherings. You have to understand these commuting and traffic patterns when considering where to hold your worship gatherings, as well as where to do your outreach.  People in your target community have commuting habits and preferences. There are both physical and psychological barriers that keep people traveling to certain areas within a geographic area.  Psychological Barriers:  Familiarity: What is their normal commuting pattern to work, stores, the movie theatre, etc? Often the direction people commute to work is the same direction they''ll go to do their shopping and recreation.  Traffic/Congestion: People often avoid certain roads and parts of town simply because of the traffic.  Distance: People will only travel so far to a destination place (e.g. church, movie, store).  Crime, Safety & Cleanliness: What reputation does a given area have? Do people feel safe there?  Physical Barriers:  Bridges  Lakes/rivers  Train tracks  Parks  Interstate highways/Toll roads  Divided highways  Understanding existing commuting habits and traffic patterns will help you define the best:  Worship gathering facility options  Office locations  Outreach event locations  Placement of street signage  Facilities that are located along major commuting routes and near high population density centers are often the best worship gathering locations.  Useful tools to help:  <a href="https://datausa.io/">DataUSA</a> demographics include average commute statistics for your community  <a href="https://www.freemaptools.com/how-far-can-i-travel.htm">FreeMapTools</a> will show you a drive time map around a potential facility', 'Use a map to:  Identify the key destination locations (e.g. shopping centers, movie theatres, etc) in a given geographic area.  Identify major commuting routes in the geographic area.  Identify key population centers (place circles on the map) ranking them from highest population density (households per square mile) to lowest population density.  Identify any natural physical barriers (lakes, bridges, train tracks, etc).  This action is complete when you understand and can articulate the commuting patterns of your community.', 'template: standard  2017-10-24 data validated & new links added --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 90& to 70& --pb ', 5, 'todo', 69, 14, '{}'::jsonb),
  ('a2863044-6397-5ace-83c8-cff8fbb62bca', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Learn where the major neighborhoods are and what makes them different', 'Create a list or map of neighborhoods to understand your community and better plan events.', 'Most cities are made up of neighborhoods - boroughs, builder''s subdivisions, etc. Each neighborhood will have different characteristics. For instance, real estate prices alone will significantly influence the community makeup.  Some neighborhoods will have very active home owners'' associations that regularly plan events for the community. Maybe that gives the neighborhood a more friendly feel. Other neighborhoods may feel very aloof.  In addition to creating a map, take some basic notes on each neighborhood such as:  Its reputation in the area  Average price of homes  Regular community events  <a href="https://www.greatschools.org/school-district-boundaries-map/">Schools</a> (their quality/caliber)  Knowing your neighborhoods well helps with:  Discovering concentrations of your average target family  Strategizing your events  Strategizing marketing efforts  Bringing new staff up to speed quickly  Real estate agents are a wealth of information when it comes to learning about the key distinctives of each neighborhood.', 'Purchase a poster-sized map of your city, or create a <a href="https://www.churchplantingtactics.com/church-plant-target-area-map/">custom Google map</a> for online collaboration.  Draw a polygon around the boundaries of each neighborhood. Write in the name of the neighborhood.  Note the key distinctives for each neighborhood.  This action is complete when you have a completed map of each neighborhood in your target area with key distinctives noted.', 'template: standard  2017-10-24 content updated --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 77& to 70& --pb ', 6, 'todo', 69, 14, '{}'::jsonb),
  ('097a7cd1-a19c-58a6-8026-9d9bdcbfbbc6', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Conduct a prayer walk', 'Perceive the spiritual dynamics of your community through on-site prayer.', 'The last level of demographics you need to understand in your community is its spiritual dynamic. Church planting is a spiritual undertaking, after all, and going in blind to the spiritual forces at work could spell disaster.  Walking through your community and listening to the Spirit will give you spiritual insight that no demographics company can provide. Praying through the various neighborhoods and interceding for people will help you gain God''s heart for your community.', 'Using the map you''ve developed, plan a route for a prayer walk.  Put on a pair of good shoes and go walking.  Spend time listening to what the Spirit has to say.  Spend time praying for the people that you are passing by.  Journal or record your thoughts and impressions as soon as you are done.  This action is complete when you have recorded the results of your prayer walk.', 'template: standard  2017-10-24 content validated --pb  2019-11-25 content updated --pb  2020-12-11 changed Duration from 7& to 21& --pb ', 7, 'todo', 76, 21, '{}'::jsonb),
  ('6cf26ca3-36bd-576f-8f6c-670fd0947210', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Research other churches in the area', 'Investigate existing churches in your community and whether any other new churches are about to be launched.', 'Every congregation has its own personality, and every church will reach different types of people. You need to know the personalities of nearby churches and be able to articulate how God is uniquely crafting your congregation''s personality.  Networking with other churches will usually reveal:  opportunities for Kingdom collaboration on community service projects  facilities that may be available  and new friends in ministry.  Set up a meeting with each Senior Pastor to establish a relationship, discover who they''re reaching, and share your vision/plans for reaching the lost in the area.  This exercise is also a great initial test of which churches show up on the first page of search engine results. Search online and make a list of churches in your area. In most cases, you can get a good sense of who the churches are reaching by visiting their websites.  Getting to know other church planters in the area will also be invaluable in coordinating launch timing, facilities, community service events, etc.', 'Make a list of all the large and/or active churches in your target area. Obtain contact information at each church (name of Senior Pastor and phone number).  For each church on the list, identify the following:  Whom are they targeting (via advertising, programs, etc.)?  Who are they reaching (as measured by who attends)?  What unique/special programs are offered to reach their target?  What music style and culture does the church have?  Write a short summary of the people groups already being reached in your community and how they''re being reached.  Now write a short list of the people groups that are  not  being reached.  This action is complete when you''ve included the summaries described above in your  Target Area Report .', 'template: standard  2017-10-24 content updated --pb  2019-11-25 content updated --pb  2020-12-11 changed Due in # Days from 90& to 86& --pb ', 8, 'todo', 85, 30, '{}'::jsonb),
  ('5ea37d30-9dc9-504e-b516-bf7795365e53', '0c04f5fc-2aca-5f9a-a65b-0fd18991526b', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Define your Average Target Family', 'Develop a profile of the average family in your target area to articulate your understanding of the people you are beginning to reach.', 'You have to have a clear understanding of who lives in the target area or you''re not going to be able to reach them well. There are 3 key things to keep in mind:  The makeup of the community is what it is. You can''t change it; you must understand it. The previous series of actions leading up to this got you to really learn who lives in the area.  You tend to reach those most like yourself. Understand and candidly consider who you will most naturally reach. Consider how you compare with the average person living in the area. Discern whether you will be targeting a subculture within the culture.  Plant the church your community needs. Is the church you''ve been envisioning the kind  you like , or will it fit the people who live in your area?  When a missionary is sent overseas, one of the first expectations is that they learn the language and culture of those they will be reaching. In the same way, you have to understand the language and culture of those you are reaching.  People in urban situations are different than those in rural. Those in California have a different culture than those in the South. You need to understand what makes your target unique and how you can best reach them.  After getting some demographic data and proving it out with your own research, define as specifically as possible the characteristics of the ''average'' family in your target area. Write a description of the typical person and/or family you are beginning to reach. This process will help you better understand how to reach your community.  What is an ''average target family''?  A qualitative description of the average family you are trying to reach in specific terms. The description should be as detailed as possible, including age, marital status, family size, income, hobbies, likes/dislikes, employment, etc.  Why is defining an average target family important?  With a clear understanding and description of the average family, you''ll be able to focus on how best to reach the people in your community. Marketing, outreach, music, staffing, and a host of other strategies will be shaped by the definition of who you are trying to reach. With your new-found focus, you''ll be able to allocate resources based on which opportunities/strategies will be most effective.  Of course you''re not going to close the door on people that don''t match up with your Average Target Family! But understanding who the target really is will allow you to better form effective strategies.', 'Review all the data you''ve compiled so far about your target area.  Seek counsel from trusted people who live in the target area.  Download Passion for Planting''s  Average Target Family Worksheet  (<a href="/resources/item/11">MS Word</a> or <a href="/resources/item/379">Google Doc</a>).  Fill in the blanks to describe your own Average Target Family.  This action is complete you have written out a concise description of your average target family.', 'template: standard  2017-10-26 content updated --pb  2018-06-01 additional resources subsection added,& gdoc& template added --pb  2019-11-25 content updated --pb  2020-12-11 changed Duration from 7& to 21& --pb ', 9, 'todo', 91, 21, '{}'::jsonb),
  ('9be8476c-2a74-5328-bd1a-70d4e2108afb', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set intended launch date', 'Select a target launch date for your worship gatherings so you can set expectations for supporters, team members and the community at large.', 'Setting a date for the launch of regular worship gatherings will help you lots of ways. Most of the strategies and actions in your  Launch Strategy  document are dependent on the launch date. You''ll need to know  at least  6 months in advance just so you can take care of the basic details like facility & equipment.  If it''s really early in the planning process, you might choose to set a tentative date and then finalize the date at a later time. That''s fine as long as you consistently communicate clear expectations to your launch team. Launch team members can get frustrated when they don''t know when the new worship gatherings will officially begin.  Defining a launch date (the date of the first public worship gatherings) is important for several reasons:  Launch team morale  People are inspired by a clear and compelling vision of the future. A launch date brings clarity to the launch process and helps people see that milestone in the future. Launch team members look forward to launch and are anxious to ''become a real church''. After all, the purpose of a launch team is to launch. You must constantly cast vision for what Launch Sunday is going to look like and give a reasonable time estimate.  Strategic planning  All the teams and team members need to have a target for when their piece of the planning and preparation need to be complete. People work best with a deadline and tend to procrastinate without one.  Financial support  Prior to launch, the church has expenses. Your financial supporters want to know when the launch is going to happen for lots of reasons. Communicated poorly, having no launch date can give the impression that you don''t know what you''re doing. That could be a real barrier for supporters.  There are lots of factors you need to consider when selecting a launch date:  Natural back-to-church times  It''s no secret that church attendance typically drops during summer months. Launching in June will all but guarantee letting the air out your tires at the starting line. Late winter (Feb/Mar) and back-to-school time (Sep/Oct) are the two proven windows.  Beware of Easter  Easter seems like an obvious choice. It might get you the biggest turnout. But that attendance will be triply inflated: you''ll have well-wishers, people that only come on Easter and all of your launch team there together. Attending church once or twice a month is the new normal even for dedicated Christians, so the very next Sunday, you may have only 2/3 of your team and all the well-wishers and Easter-onlys will have vanished. Your Sunday-after-Easter attendance could be less than half. What would that do to your team''s excitement and momentum? Passion for Planting has observed it may be better to launch 3-4 weeks prior to Easter so that you can build on the momentum of the launch into the Easter boost.  Be mindful of holidays  Both national holidays, like Labor Day, and local holidays can significantly impact church attendance.  Watch out for school breaks!  Does the local district have a modified traditional schedule with a week off in October? Are they a year-round district?  Local sporting events  If the first home game of a professional sports team is 11am on Sunday, that could pose a significant barrier to prospects.  Regional weather  In the far north, launching in January or February would be very risky if snow is likely. Being delayed a week due to snow can significantly hinder people''s likelihood of attending. But how hot is it still in September in Phoenix?  Super Bowl Sunday and Spring Daylight Savings Time Change  These two happen one right after the other, which always creates a challenge for spring launch timing.  Other things to watch out for  Keep your heads up for hunting season, major festivals (ex: Mardi Gras), and other similar events in your local culture.  A Whole Launch Month?  Many planters are finding planning for a month of Grand Opening, as opposed to a single launch Sunday, to be a good strategy:  You may gain more momentum than from a single launch Sunday  People who have to be out of town on the first Sunday haven''t missed it  It''s culturally normative: new stores have their grand openings for extended periods of time  People who come the first Sunday and get excited have the extended ''excuse'' to invite their friends & family to come back with them  If you decide to take this approach, make the ''whole month'' concept extra clear on all your marketing.', 'Check for holidays, local events and other calendar conflicts.  Check the local school calendars.  Seek advice from other planters, a coach and other church leaders.  Prayerfully consider the options.  Select a date, or at least a month.  This action is complete when you have selected a launch month or launch date.', 'template: standard  2017-05-31 content validated --pb  2018-11-02 content updated --pb  2019-12-03 content updated --pb ', 0, 'todo', 45, 7, '{}'::jsonb),
  ('78a5eae2-68de-59ca-833b-39b1ac8ebcfb', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Summarize vision, mission and values', 'Create a short and sweet version of your  Vision Frame  (philosophy of ministry) for inclusion in the Launch Strategy.', 'At this stage of the plant, you may be working on your church''s  Vision Frame  (philosophy of ministry) at roughly the same time as creating your Launch Strategy. Summarize what you''ve created in  <a href="/projects/project-tasks/[[project_id]]/all-tasks/268">Milestone: Define Church Vision</a> :  Your mission statement answers the irreducible question: what are we supposed to be doing?  Your short list of values answer the irreducible question: why do we bother?  Your strategies answer the irreducible question: how do we ''do'' the mission?  And your measures describe what a mature disciple looks like, answering the irreducible question: when are we successful on an individual level?  The vision should be living language, a colorful narrative that paints a picture of what the future will hold if we follow God in carrying out these things. It will be less of a rigid  statement  and more of a story or inspirational speech.', 'Summarize the key components of your  Vision Frame .  Include that summary in your Launch Strategy document.  This task is complete when you''ve included your vision, mission, values, etc. in your  Launch Strategy Template  (<a href="/resources/item/144">MS Word</a> or <a href="/resources/item/365">Google Doc</a>).', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2019-12-03 content validated --pb ', 1, 'todo', 55, 14, '{}'::jsonb),
  ('f1c0d51f-b942-5098-a50b-fff52f7752b6', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Summarize target area', 'Create a compelling overview of your target community for inclusion in the Launch Strategy.', 'Doing the missionary homework of  really  getting to know your community is a critical step in the church planting process. It should inform almost everything about how you ''do church''. Here it also helps you make a case for why it''s important to plant a new church in your community at this point in time.  You need to include a more in-depth look at your community than you did in your Launch Vision booklet, but don''t go into the weeds too much. Find the handful of stats that will make it obvious why we need another church, or will highlight the strategic timing of planting now. Use rounded figures when you include numbers.', 'Review all of your demographic reports and research.  Draft at least a page''s worth of compelling stats about your community.  Include that summary in your Launch Strategy document.  This task is complete when you''ve included your target area summary in your Launch Strategy template.', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2018-05-07 added& google& doc template version --pb  2019-12-03 content updated --pb ', 2, 'todo', 55, 14, '{}'::jsonb),
  ('0f0640ce-50e5-55f7-918d-18befc1ff3a2', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Summarize Opening Day Expectations', 'Create a condensed version of your Opening Day Expectations document for inclusion in the Launch Strategy.', 'Your Opening Day Expectations document quantifies the near-term target you''re shooting at. It''s a facilitated daydreaming exercise to help you envision the launch of regular worship gatherings. Extract the highlights from your  Opening Day Expectations  document and include it in your Launch Strategy document so your audience can catch a glimpse of the dream.', 'Summarize your Opening Day Expectations.  Include that summary in your Launch Strategy document.  This task is complete when you''ve included your vision, mission, values, etc. in your  Launch Strategy Template  (<a href="/resources/item/144">MS Word</a> or <a href="/resources/item/365">Google Doc</a>).', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2019-12-03 content updated --pb ', 3, 'todo', 55, 14, '{}'::jsonb),
  ('5552a315-c4c4-51d4-a3ed-6add490e628d', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Articulate planting timeline', 'Create a planting timeline for inclusion in the Launch Strategy.', 'No Launch Strategy is complete without a clear timeline of your church planting process. Depending on your model, that may be a fixed date or a series of checkpoints/milestones. But you need to demonstrate that you''re not just flying by the seat of your pants.  Don''t include too little or too much detail. Aim at filling a page with your timeline, whether it''s list-style or designed with graphics. Hit the major milestones and seasons. Demonstrate that you''ve thought through timing and have a solid plan.', 'Create a list timeline or visual timeline of your church plant.  Include that timeline in your Launch Strategy document.  This task is complete when you''ve included your planting timeline in your Launch Strategy template.', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2019-12-03 content validated --pb ', 4, 'todo', 55, 14, '{}'::jsonb),
  ('f906919e-2362-5e52-8496-bd64848a52ea', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a summary budget', 'Create a medium-level-detail budget summary for inclusion in the Launch Strategy.', 'Every new ministry and business venture requires resources. Ones that survive have a financial plan for the near and mid-term future. For your Launch Strategy, you need to include about a page''s worth of budget data - both where the money''s coming from and what you''ll spend it on. Don''t go into too much detail, but don''t gloss over the finances.  If you''ve used Passion for Planting''s  Church Plant Budget Worksheet Template , you can simply use the  Summary  page/tab. All the math is already done for you!', 'Copy the  Summary  page from your  Church Plant Budget Worksheet Template  (<a href="/resources/item/25">MS Excel</a> or <a href="/resources/item/366">Google Sheet</a>) or otherwise summarize 3+ years of budgetary figures.  Include that summary in your Launch Strategy document.  This task is complete when you''ve included your budget summary in your <a href="/resources/item/144">Launch Strategy template</a>.', 'template:  New Milestone  2018-01-15 changed to child task of #1138 --pb  2019-12-03 content updated --pb ', 5, 'todo', 55, 14, '{}'::jsonb),
  ('c6c1f684-ce1c-5d62-905c-35889c8f6f75', '0e219cb1-e0b0-5f19-995b-556254711a18', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Draft key strategies to launch worship gatherings', 'Create summary versions of several key strategies you''ll employ so you can include them in the Launch Strategy.', 'Ultimately, you''ll work up entire strategy documents for each of the following (with PlanterPlan''s help):  Prayer Team Strategy  Fundraising Strategy  Disciple-Making Strategy  Launch Team Development Strategy  Church Groups Strategy  Leadership Multiplication Strategy  Community Networking Strategy  Staffing Strategy  Outreach Strategy  Church Multiplication Strategy  Facility & Equipment Strategy  Marketing Strategy  Ministry Teams Strategy  Assimilation Strategy  Right now you just need the short versions of each of these. If you''ve already completed one of the full strategy templates, then just hit its highlights as you fill in the Launch Strategy template. Most of the strategies you won''t have fully hammered out yet, so just take a quick stab at a summary. Those summaries will become the seeds of your full-blown strategies down the line.', 'Using the Launch Strategy Template, fill in the boxes to summarize the key components of each of the strategies.  This task is complete when you''ve filled in all the fields in the  How We''re Going to Do This  section of your Launch Strategy template.', 'template:  New Milestone  2019-12-03 content updated --pb  2020-12-11 changed Due in # Days from 58& to 63& --pb ', 6, 'todo', 55, 14, '{}'::jsonb),
  ('64ab943d-f3c9-521c-b890-22dfdd4087e9', '148e0b6e-bc1f-5cd5-b8d5-2e0ba25e00dd', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Design the "One Place" for guest connections', 'Create a central location for guests to turn in connection cards and get more information about next steps.', 'Through the announcements, handouts, your greeters and the connection card itself, there should be exactly  One Place  you direct guests to go so they can turn in their connection card and get information about the "One Program" (see subsequent task).  Consider what kind of gift you might hand out as people turn in their connection cards. Make it desirable and something that connects with your church''s values.  When designing the "One Place", take aesthetics into consideration. You will want it to communicate a welcoming environment that people feel comfortable approaching. Have a table with a huge banner or a pop-up tent (or the like) and use signage to clearly communicate the location of the One Place. It should be obvious to newcomers where to go for getting connected.  Choose your best greeters (people with a smile who enjoy other people) to staff the One Place. Train them to explain the One Program and warmly invite guests to attend to get information and ask their big questions. Challenge them to have a super-high collection rate for the connection cards - if the cards don''t get turned in, following becomes nearly impossible.', 'Design a welcoming environment and give it a name (ex: connection tent, info table, etc).  Strategize what signs you''ll need to draw attention to the One Place.  Choose and/or prepare the gifts that will be provided to guests.  Determine how you''ll train your best greeters to staff the One Place.  This action is complete when the One Place has been designed.', 'template: standard  2017-06-07 content updated; generational/cultural reference to Seinfeld removed --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 224& to 228& --pb&  2021-03-26 additional resources subsection added --pb ', 0, 'todo', 154, 14, '{}'::jsonb),
  ('7efcc0be-b7d8-5c15-811c-a6c8550f26e7', '148e0b6e-bc1f-5cd5-b8d5-2e0ba25e00dd', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create the "One Program" event for guest connections', 'Brand your "One Program" guest connections event and craft a plan for what to say and do at the event.', 'Even though you''ve posted mission & vision on your website and share it from the platform, people still benefit from interacting with the story and details of the church in a relational environment.  And people will have questions about theology or practice or all kinds of things. A group event allows you to lead through all of that  and  get the newest people to meet each other.  It''s been called different things over the years:  Welcome to ChurchName  ChurchName 101  Making ChurchName My Home  Pizza with the Pastor  Next Steps with Steve  ...and the list goes on  And it has taken lots of formats, too:  a 1-hour seminar with Q&A  a catered half-day event  a structured but casual group conversation over a meal  a 15-minute high-energy ''party'' immediately following the worship gathering  ...and again, the list goes on  Now is the time to make those decisions, develop the content and get the first one on the calendar.  Most of all, you want to have clear ways for the attenders to get further connected to the church. These will be the "Two Placements" in your  Assimilation Strategy , typically somewhere they can find community and somewhere to serve and use their gifts.', 'Determine the aim and desired outcomes of the event.  Decide on a format.  Choose a name for the event.  Include this "One Program" in your  Assimilation Strategy Template .  Put the first event on the church calendar and publish it to where it can be found.  Create speaker''s notes, slides, handouts, workbooks, and/or anything you''ll use at the event.  This action is complete when the content and resources for the event have been finalized.', 'template: standard  2017-12-29 content updated --pb  2019-12-03 content updated --pb  2020-12-14 changed Due in # Days from 161& to 74& & Duration from 7 to 14& --pb&  ', 1, 'todo', 154, 14, '{}'::jsonb),
  ('3682937b-fe8c-567c-ad17-ff23f1abd117', '148e0b6e-bc1f-5cd5-b8d5-2e0ba25e00dd', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine the "Two Processes" for connecting guests', 'Create a clear step-by-step plan for moving guests from showing up at the "One Program" to both community and Christian service.', 'Once guests to your church have participated in the "One Program", you''ll want to quickly move them into community and service environments which will relationally connect them to your congregation.  People are wired up differently and have different life circumstances, so they might do not pursue both initially. Ultimately, you want dual placement for every guest, but getting them connected to one of the two is a huge step in the right direction.  So, you need one process that will help people get plugged in to whatever your group structure is (see PlanterPlan task  <a href="/projects/project-tasks/[[project_id]]/all-tasks/670">Issue Written Groups Strategy</a>  for more). Your process might include emails, phone calls, texts and/or handwritten notes, etc.  You also need one process that will help people get plugged in to a serving team (see PlanterPlan task  <a href="/projects/project-tasks/[[project_id]]/all-tasks/740">Develop a Leadership Matrix for Opening Day</a>  for more). Again, your process must include specific followup steps your teams take to invite people to explore and participate.  For both processes, you need to include every step your team(s) will take, from data entry to communicating with the guests.  All communications need to make it abundantly clear what simple next step you''re asking the reader/listener to take. If it''s confusing, they''ll be much less likely to take any step.  Err on the side of too much follow-up. It can take people hearing the call to action several times before it really registers and they take that simple next step. Don''t assume because you''ve emailed them once that they ''get it''. Your plan should be politely and lovingly persistent.', 'Review your church  Strategies , developed in a prior PlanterPlan task, to make sure your "Two Placements" agree with your Vision Frame.  Hammer out a process for each of the "Two Placements" and include the details in your  Assimilation Strategy Template .  This task is complete when you have detailed processes that include specific steps with deadlines and who''s doing each step.', 'template:  2018-11-19 new task --pb  2019-12-05 content updated --pb ', 2, 'todo', 154, 14, '{}'::jsonb),
  ('2a8f0a53-08b0-5ab3-bafb-ed0699bc15ff', '148e0b6e-bc1f-5cd5-b8d5-2e0ba25e00dd', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set assimilation benchmarks', 'Choose measures that will reveal the effectiveness of your Assimilation Strategy and set numeric expectations.', 'You need an easy way to track assimilation at your church. It''s imperative that you have your finger on the pulse of how things are working because it affects people. And you need to be able to spot breakdowns so that they can be fixed.  What percentage of your guests next year will get placed into a group or serving team? Both? How would you even know?  You''ll need to record guests in your church management software. You''ll also need to keep track of who participates in each small group and serves on each ministry team. Then you''ll be able to pull reports that reveal your single and dual placement rates over any given time period.  What percentages will you strive for? How will you communicate that to your Followup Team and inspire them toward it?  Something else worth measuring is how many new believers stay connected. If half of people who say ''yes'' to Jesus have left your church within 6 months, you''ve got an urgent opportunity to fix something.', 'Set numeric goals for the percentages of single and dual placement of guests.  Figure out how to use your ChMS to track and report your placement percentages.  Make someone the owner of collecting the data and creating regular reports.  Include these details in your written assimilation strategy.  This action is complete when you have set assimilation benchmarks.', 'template: standard  2018-11-19 content updated to match Greg Curtis'' assimilation content and our new strategy template& --pb  2012-12-02 content updated --pb  2020-12-16 changed Due in # Days from 150& to 162 --pb&  ', 3, 'todo', 154, 14, '{}'::jsonb),
  ('1f6cddb0-8119-5370-8f21-a5f277043857', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Solicit donations through online gift registry', 'List items you need in an online gift registry and invite everyone you know to purchase something off the list.', 'If you''ve ever done a baby registry or bridal/wedding registry, you know how this works. All of the major retailers provide this functionality, so all you have to do is build your list and then get it out there.  As you build your registry, be sure to include both big-ticket items as well as $10 and $20 items. Your donors will self-select what they''re passionate about and what they can afford.  Be sure to put the list especially in front of your contacts at churches that declined to financially support you. Often, they wanted to support you but just didn''t have the resources. And just as often, they figure out a way to spring for a portable crib or a subwoofer.  Also be sure to put the list in front of your contacts at churches that  have  already supported you. They have skin in the game and want to see this new church started well.  Lastly, include your Launch Team members on your distribution list. It''s a great way for them to participate and increase their ownership.  Email it out. Put it on social media. Text and call. And pray.', 'Create a registry or wish list at your favorite online retailer.  Add an array of items from the finalized equipment list to the registry.  Publish and promote the list.  This task is complete when your first registry item is delivered to your home or office.', 'template: standard  2017-05-19 content & hyperlinks updated --pb&  2020-01-20 content updated --pb  2020-12-16 changed Due in # Days from 180& to 183 --pb&  ', 0, 'todo', 165, 30, '{}'::jsonb),
  ('6741f983-ff4f-5c3b-b8f6-f633a86eb158', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase AVL equipment', 'Order the AVL equipment earlier than you think you need to so that you get it all in time for the dry run/training event.', 'Contact your AVL equipment vendor(s) and officially place your orders. You will have to pay some or all of the invoice up front.', 'Order the AVL equipment from your finalized list to arrive before the dry run/practice service (see subsequent PlanterPlan task).  Pay the required portion of the invoice up front.  Confirm delivery dates and address.  This action is complete when the AVL equipment is in hand.', 'template: standard  2017-05-19 content updated --pb  &  2020-01-20 content updated --pb  ', 1, 'todo', 182, 30, '{}'::jsonb),
  ('f120440c-5bb1-53b7-b1c6-09fe1fdbb1db', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase non-AVL equipment', 'Purchase everything else from the finalized equipment not already donate through the registry or ordered from a vendor.', 'If you''ve contracted with an all-in-one equipment package vendor, these items will have been included in your quote.  If you''re going DIY, review your finalized equipment list and cross off everything that has already been purchased or donated.  Now is the time to order everything that''s left so you get it in time.', 'Figure out what''s left to purchase on the finalized equipment list.  Delegate items to team leads, launch team members and/or staff.  This action is complete when you have submitted the reimbursement requests with receipts for each outstanding item on the equipment list.', 'template: standard  2017-05-19 content updated --pb&  2020-01-21 content updated --pb  2020-12-16 changed Due in # Days from 224& to 196& & Duration from 14& to 7& --pb  2021-01-18 changed Due in # Days from 196 to 212 & Duration from 7 back to 14 --pb ', 2, 'todo', 182, 30, '{}'::jsonb),
  ('d2a9eb36-63a2-512c-8ba6-6aa4ea0867e2', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase presentation computer and software', 'Get the hardware and software you need to project lyrics, announcement, sermon slides, etc.', 'Hardware  If you can swing it, buy a laptop that will be devoted to Sunday projection. If it needs to be a staff computer, be sure to create another user account so that the projectionist doesn''t have accidental access to sensitive church files. Whichever you use, disable screen savers, pop-up notifications, and software auto-updates which can interfere with a smooth worship gathering.  Portability is key. It''s going to be traveling quite a bit whether it''s between the worship facility and a staff member''s home or packed into the equipment trailer. Setting up a whole desktop computer station each week isn''t realistic.  Be sure the computer you use has enough power to run the software you choose. You can go to each vendor''s site and find their hardware requirements. Also consider the computer''s output: if your projector is VGA but the computer only has an HDMI out port, you''re going to need some kind of adapter.  Software  Here are common apps designed specifically for church projection:  Up-front Purchase:  <a href="https://renewedvision.com/propresenter/">ProPresenter</a>  <a href="https://mediashout.com/">Mediashout</a>  <a href="https://www.easyworship.com/">EasyWorship</a>  Subscription-based:  <a href="https://faithlife.com/products/proclaim">Proclaim</a>  Involve your worship leader and/or tech team in choosing the software. This is a great place to honor your volunteers by letting them use what they are familiar with (as long as it can handle what you need from a production standpoint).', 'Pick your presentation software.  Purchase a computer to run the presentation software.  Load the presentation software on the computer.  This action is complete when you have purchased the presentation software and loaded it on the presentation computer.', 'template: standard  2017-12-27 contents & links updated --pb  2019-07-15 contents updated --pb&  2020-01-21 content & links validated --pb  2020-12-16 changed Due in # Days from 198& to 198 --pb  ', 3, 'todo', 182, 30, '{}'::jsonb),
  ('4e065695-2baa-5806-95f1-357affe4ede9', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase outdoor signs', 'Design and order signage that will direct motorist to your parking lot and pedestrians from your parking lot to your main entrance.', 'Outdoor signage accomplishes many important things:  it helps people find your worship gathering location  it communicates that you are expecting guests and have thought of them  your branding sets a tone for what the worship gathering will be like  Design  Common options for outdoor signs are:  flag-style banners  A-frames  vinyl banners  yard signs  Be strategic about how they''ll be designed. Some sign shops will provide free or paid design services, but you may want the designer who created your branding to design them for a consistent look and feel.  Important things to consider when designing the signs:  the faster the speed limit of the road, the larger the font must be  don''t put too much on the sign: consider including only the location, directional arrow, web address, and logo  be double careful which way the arrows point; double-sided signs will have left-pointing arrow on one side and a right-pointing arrow on the other  Ordering  Also be strategic about how many you''ll order. Usually the price per sign gets cheaper when you order several of the same. And signs have a relatively short lifespan (breakage and theft), so consider ordering an extra sign or two for backup.  Keep in mind what kind of base(s) you''ll need for the signs:  For flag-style banners, grass stakes are convenient, but the property owner may not allow them; and if you live where the ground freezes hard in the winter, you''ll have a challenge  For flag-style banners, cross bases are multi-purpose but provide less stability, especially in windy conditions; get sandbags or similar weights to keep the signs where you want them  spinning bases for either of the above helps with breezes, but may also turn the banner in the wrong direction  A-frames are a highly effective, low-cost option, but also prove to be stolen the most; high winds may still knock these over', 'Watch the Passion for Planting training video "<a href="/resources/item/238">Utilize Signage</a>" featuring Ed Stetzer.  Decide which and how many signs to put outside your facility.  Compare sign company pricing.  Order and design the signs.  Follow up, follow up, follow up. Make sure the signs will arrive before they are needed. The sign industry is notorious for missing deadlines.  This action is complete when you have approved the final designs and the signs are in production.', 'template: standard  2017-05-23 updated content --pb&  2020-01-13 content updated --pb  2020-12-16 changed Due in # Days from 196& to 186 --pb&  ', 4, 'todo', 185, 14, '{}'::jsonb),
  ('197f3fe2-47b2-5b79-b0e6-caaf7e40b087', '344a35ba-a4f7-5728-a31f-35f60691a6d8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase interior signs', 'Design and order indoor signage that will give people directions and make them feel like less of an outsider.', 'Remember the last time you walked through an airport under construction or had to follow a driving detour and you got lost because the signage was vague, missing or misleading? How did that make you feel?  You can''t overlook interior signage. We get so familiar with our own facilities, we think it''s obvious where everything is.  Always look at your signage from the perspective of the first-time guest. Remember what it''s like to feel like an outsider. Good interior signage puts guests at ease.  At a minimum, you''ll need signs that:  point to the children''s area (if you have one)  mark the welcome/information table (or similar)  point to the main service  provide directions to the restrooms  Put out enough signs that at least one sign can be seen from any given spot in your usable common areas.', 'Become familiar with the flow of your facility:  Where do/would people tend to go first naturally?  Which rooms are hard to find?  What hallway is long enough to create ambiguity as to where the room at the other end is?  Is the facility''s native restroom signage large enough to be clear & effective?  Decide which and how many signs to put out inside your facility.  Compare sign company pricing.  Order and design the signs.  Follow up, follow up, follow up. Make sure the signs will arrive before they are needed. The sign industry is notorious for missing deadlines.  This action is complete when you have your indoor signage in hand.', 'template: standard  2017-06-05 content & links validated --pb  2020-12-16 changed Due in # Days from 238& to 235& & Duration from 150& to 114& --pb&  ', 5, 'todo', 185, 14, '{}'::jsonb),
  ('a48f392e-f15c-507a-b1e7-b2737479b8fa', '38210c4a-c634-5944-8964-d46ea8e58681', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit a children''s ministry team leader', 'Identify and empower a relational, reliable leader for the children''s ministry team who can work through adults to get children''s ministry done.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has both leadership potential and is a natural recruiter.  Your children''s ministry team leader needs to quickly embrace the values of the church; they''ll be responsible to live them out and communicate those values to team members.  Consider writing out a job description and basic expectations you''d have of any children''s ministry team leader. Go over those with your candidate and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  recruiting team members  choosing curriculum  purchasing ministry equipment  running background checks  scheduling volunteers so that there are no gaping holes in the schedule  You may be inclined to pick a team leader that is great with kids. While that is a plus, a children''s ministry team leader needs to spend more time building teams and working with adult volunteers than they do working with the kids.', 'Subtasks that follow will walk you through each of these important steps:  Recruit a team leader for the children''s ministry.  Purchase or develop children''s curriculum/programming.  Develop children''s ministry safety procedures.  Determine process for conducting background checks.  Get a commitment from the leader to own the processes and leadership of the team.  This action is complete when the team leader has completed each of the subtasks that follow this task.', 'template: standard  2017-06-06 content updated --pb  2018-04-02 additional resources subsection added --pb  2020-01-17 content updated --pb  2020-06-24 Orange curriculum&  additional resource  added (points to P4P blog post) --pb  2020-12-14 changed Due in # Days from 201& to 204 --pb&  ', 0, 'todo', 189, 30, '{}'::jsonb),
  ('617460ab-779f-5995-920b-2f803c7816e2', '38210c4a-c634-5944-8964-d46ea8e58681', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Purchase or develop children''s programming materials', 'Create a children''s program at the worship gathering that supports the overall vision of the children''s ministry.', 'The children''s ministry team comes to life when the kids arrive! Lots of planning, preparation and training goes into making that happen.  It''s important that your church does children''s ministry well for the children''s sake. And doing it well doesn''t have to mean flashy. It should be about fostering relationships with adults leaders they can trust, and helping them find and follow Jesus.  Programming vs Curriculum  There are several great models for children''s ministry programming that will help you accomplish relationship. Which one you pick should be based on your philosophy for children''s ministry and, ultimately, the church''s  Vision Frame .  The curriculum is the tool you will choose will drive that style of programming.  Resources and volunteers are limited in a new church. Don''t choose a model or curriculum that stretches your volunteer base too thin. Do choose one that is scalable and allows for rapid growth. The children''s ministry needs to grow with the congregation.  Singing  Worship music can also be a key part of Sunday morning children''s programming. Many curriculae now incorporate worship into the lessons.  Worship can be a challenge, particularly for older elementary children. Will you use live worship or recorded worship? Will you have interactive worship? Will you project lyrics? The answers to these questions will also impact what equipment you will need to purchase.', 'Review the demographics of your area as well as the  Average Target Family  document. Determine what the context of the average child in your area is like:  are they from single or dual parent homes?  is it common to be on reduced lunches at school?  etc.  Determine style of programming appropriate to your context.  Determine the number of classes and what ages are in each class.  Keep your volunteer staff in mind. Do not choose a model that stretches them to thin.  Determine how Music will be used in each class or the ministry overall.  This action is complete when the planter and the team leader have created a children''s programming structure.', 'template: standard  2017-06-06 content validated& & links updated --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 201& to 204& --pb&  ', 1, 'todo', 203, 14, '{}'::jsonb),
  ('07c7d033-6aea-5204-a013-da9832bd199d', '38210c4a-c634-5944-8964-d46ea8e58681', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop children''s ministry safety procedures', 'Develop a well-thought-out safety plan to ensure the safety of the kids in the care of your church.', 'Developing the safety procedures is an essential step in having a high-quality children''s ministry. It only takes one incident to seriously damage a child. That incident will seriously damage the reputation and witness of your church, too.  Take the facility in to consideration. Many rented facilities are not ideal for security. They require unique accommodations to ensure the safety of kids. The safety procedures must include a custom plan for ensuring the safety of kids in your location. This means thinking through:  how kids are kept corralled in their rooms  how to keep unauthorized adults out of the rooms (including parents)  how to secure any exits or potential hiding places  The plan should also include an application to volunteer to work with kids in any way. An application is an important first line of defense against would-be predators.  Once you''ve created the safety plan, train volunteers to practice the procedures put in place.  Do not take any shortcuts implementing this plan!', 'Develop an application process for volunteers.  Watch <a href="https://www.youtube.com/watch?v=L2VsSgwbqlI">Church Safety for Kids 18 & Under</a> by Waypoint Church Partners  Run background checks on all children''s ministry volunteers (see subtask following).  Adopt a "no volunteer alone with kids" policy, including a bathroom policy.  Decide whether to adopt a policy for ratios of volunteers to kids. Example: the nursery will have a ratio of 4 kids to 1 volunteer. Decide if you will you close a room if you exceed those ratios.  Train volunteers on safety procedures.  Develop a system for sign-in and sign-out to ensure that all kids are returned to the right adults.  As a part of the sign-in and sign-out process, create a plan for how to contact parents during the worship gathering in case of emergency.  Determine safety procedures such as a  Fire Escape and Disaster Plan .  Create a way for everyone to easily identify children''s ministry workers (ex: name tags with the volunteer''s photo, t-shirts, or something similar).  Write down all of these safety procedures. Include a brief summary of that plan in a  Parent and Volunteer Handbook  and training manuals. Add the detailed plan to the church''s Policy Book.  This action is complete when you have implemented safety procedures to protect the health and well-being of children in the church''s care.', 'template: standard  2017-06-06 content & links updated --pb  2018-03-28 additional resources subsection added --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 201& to 204& --pb&  ', 2, 'todo', 203, 7, '{}'::jsonb),
  ('83af3116-c3e7-58ea-9d8c-631a5a5a3f79', '38210c4a-c634-5944-8964-d46ea8e58681', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine process for conducting background checks', 'Pick a vendor and create a background check process to avoid preventable incidents and demonstrate that your church takes steps to prevent misconduct with children.', 'Jesus is serious about protecting children from harm.  "If anyone causes one of these little ones&mdash;those who believe in me&mdash;to stumble, it would be better for them if a large millstone were hung around their neck and they were thrown into the sea." - Jesus (see Matt 18:6, Mark 9:42, Luke 17:2)  It may be impossible to prevent every single case of physical and sexual abuse in our churches, but that shouldn''t stop us from trying. The children are counting on us.  Background Checks  Child predators will appear to be very nice and normal &mdash; you won''t be able to spot them. An important line of defense is running background checks on every adult who works with youth and children.  Don''t skip this step. Covenant to make it a non-negotiable for your church.  Choose an All-Inclusive Search  In the US, our levels of government aren''t freely sharing criminal data yet. That may be good for the public''s privacy rights, but it makes running background checks a little more complicated.  Most providers will offer you a low-cost background check option that only checks the federal database.  This is an inadequate background check  . Don''t be tempted to save a few bucks. Run an all-inclusive search that includes:  federal  state  local/county  registered offenders database  The background check process is not perfect. An all-inclusive search gives you the best chance of preventing abuse in your church.  Keep Good Records  Modern background check vendors will email a link to the applicant where they will input all of their own sensitive information so you don''t have it laying around on some paper form. Background check results will be accessible on the app''s dashboard. Many will interface with the most popular church management software apps.  Make sure only a very few trusted people have access to those records on a need-to-know basis.  Foreign Nationals  Running background checks on people who have recently immigrated to the United States presents a particular challenge. Other countries may or may not have effective background record keeping. Records sometimes do not travel across borders.  Work with your background check vendor to navigate this if it comes up.', 'Choose a background check vendor; consider first the one(s) that integrate with your church management software.  Sign up for their service and learn their system.  Do the initial round of background checks for volunteers.  This task is complete when you have run the initial round of background checks.', 'template: standard  2017-06-06 content and links updated --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 231& to 235& --pb&  ', 3, 'todo', 203, 7, '{}'::jsonb),
  ('a2da2bb1-5f16-50f1-b303-cf67171e77e3', '38210c4a-c634-5944-8964-d46ea8e58681', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train children''s ministry leaders and team members', 'Equip volunteers with the knowledge, skills, resources and tools they need to live out their God-given calling to serve kids.', 'Training and equipping volunteers is an essential part of any children''s ministry. Many volunteers will have a willing heart, but will need a leader to equip them so that they can succeed.  It would be easy to let training slip through the cracks because of your busy schedule. Trust that making time will save you time in the long run. A well-trained volunteer staff will take on more ownership in the ministry and be more committed over the long haul.  Training provides cohesiveness and stability, and it results in a well-balanced ministry.  Really, Another Meeting?  You may run into the perception among the volunteers that the training is "not necessary" or "just another meeting". Nothing could be further from the truth.  So, create an environment of fun at your training events. Rather than just lecturing, considering leading the training as you would lead a children''s class. This will give you the opportunity to demonstrate teaching principles as well as make it fun for everyone involved.  Keep in mind people''s busy schedules when deciding how often to do training events. Maybe break up the events into individual classroom/age-groups as well as one large group training. An effective way to provide decentralized training is through sending out a weekly e-mail that includes a training tip, video and/or upcoming events.  Feedback Loop  Evaluation is a crucial part of the training process. The ministry leader can''t be in every classroom with the kids, nor will they be able to interact with every parent.  You''re going to need feedback from your workers to make improvements in the ministry. Let the volunteer staff to evaluate the team leader, too, so that the leader can grow and better serve the workers.  Trainer, Train Thyself  Training doesn''t end with the volunteers. You have to be intentional about seeking out training as well.  Consider these training avenues:  find a local children''s ministry coach/mentor  read books, magazines and blogs to stay up to date with children''s ministry  attend a children''s ministry conference or training each year', 'Decide what types of training you''ll require and how often.  Plan the initial training event. Include:  how to use the curriculum  what the safety procedures are  policies for discipline  how to create a welcoming environment  Create feedback mechanisms to improve the ministry.  Make a plan for volunteer appreciation.  Create a training plan for the ministry leader to stay fresh.  This action is complete when you have trained other leaders and team members in the children''s ministry.', 'template: standard  2017-06-07 content updated --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 231 to 235& & Duration from 21& to 28& --pb&  ', 4, 'todo', 234, 14, '{}'::jsonb),
  ('263b196e-5ebd-5583-bf9e-2285739b5f53', '3cc1f2da-c0df-5b01-af2c-315c9f2b9f53', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit a tech team leader', 'Identify and empower a skilled, reliable leader for the tech team so that the AVL will run smoothly during the worship gatherings.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has both leadership potential and AVL experience.  Your tech team leader needs to quickly embrace the values of the church; they''ll be responsible to live them out and communicate those values to team members.  Consider writing out a job description and basic expectations you''d have of any tech team leader. Go over those with your candidate and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  recruiting team members  choosing and/or learning how to operate the AVL equipment  coordinating with the worship leader  scheduling volunteers so that there are no gaping holes in the schedule  The leader of the Tech Team needs to have specialized skills in audio, video and lighting. But more important is their ability to build their team.', 'Spend time in prayer asking God to raise up leaders.  Identify a person to lead the tech team.  Communicate expectations to the leader.  Get a commitment from the leader to own the processes and leadership of the team.  This action is complete when you have recruited and empowered a team leader.', 'template: standard  2017-06-06 content updated --pb  2020-12-14 changed Due in # Days from 231& to 235& --pb&  ', 0, 'todo', 219, 14, '{}'::jsonb),
  ('560d22c5-3314-5938-98a6-88d14731ff7f', '3cc1f2da-c0df-5b01-af2c-315c9f2b9f53', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train Tech Team on Equipment Setup and Operation', 'Train volunteers to setup and operate the AVL equipment so that tech enhances the worship gatherings.', 'The best equipment and processes are meaningless if the workers aren''t trained. Ensure that everyone involved in the Tech Team understands their role.  Practice the processes at least once prior to the first preview service to ensure the process works and everyone is clear on their roles. All volunteers should be cross-trained to be able to fill in for other people who may be sick.  Often tech people from other churches will be willing to come out, help you set everything up, and train your team on basic sound, lighting and video techniques. The vendor you purchase the AVL equipment from may also do on-site training for a fee &mdash; usually money well spent.', 'Train team on the set up and operation of the AVL equipment.  Practice the processes at least once before the preview service.  This action is complete when the Tech Team has been trained and is ready to set up and operate everything for the preview services and Opening Day.', 'template: standard  2017-06-06 content updated --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 231& to 235& & Duration from 21& to 75& --pb&  ', 1, 'todo', 234, 14, '{}'::jsonb),
  ('9e4efbd0-5303-500a-8975-d98dde967160', '3d312559-47cb-5eba-bc26-3aa401ef5e62', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Finalize communion and offering processes', 'Develop processes for communion and offering that are appropriate for your context and consistent with the beliefs and values of the church.', 'After thinking through how to communicate communion and offering to your target audience, finalize a process. It makes training volunteers easier to have the process in writing.  As you consider finalizing the processes, be sure you can answer the following questions:  Communion:  Who will purchase communion supplies and ensure that they are brought to the worship gathering location?  Who will prepare communion before the gathering?  How will communion be communicated to your target audience?  How will communion be distributed? Who will communicate this to the people in attendance? Don''t forget to let people know what to do with communion cups if you use them.  Who will schedule volunteers and how will the schedule be communicated?  Offering:  How will you communicate offering to the target audience? Is offering only for those who consider the church home? Will you exempt first-time guests?  What will you use to collect offering?  How will offering be collected?  What is done with the offering after it is collected?  Who will schedule volunteers and how will the schedule be communicated?', 'This action is complete when you have written out the processes for communion and offering to be ready to train the team.', 'template: standard  2017-06-06 content validated --pb  2020-01-14 content updated --pb  2020-12-14 changed Due in # Days from 231& to 235& --pb&  ', 0, 'todo', 227, 7, '{}'::jsonb),
  ('ba949d94-2ad6-54a1-8f5f-0c44d0e1c01d', '3d312559-47cb-5eba-bc26-3aa401ef5e62', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train team on communion and offering processes', 'Ensure that volunteers understand the communion and offering processes so that they can take charge and run with it.', 'The best processes are meaningless without proper training. Everyone involved in the communion and offering processes needs to understand their role. The processes needs to be practiced at least once prior to the first worship gathering preview service to ensure it works and everyone is clear on their roles.  Scalability  You cannot know fully how many people to expect for opening Sunday. Be sure that the team is trained on what to do in case a larger than expected crowd arrives. Will your process break if you have double the amount of people you expected?  Have your team think through a scalability plan for just such an eventuality.', 'Train team on communion and offering processes.  Have a plan for scalability.  Practice the processes at least once before the first worship gathering preview service.  This action is complete when the team is trained and ready to implement communion and offering processes on the Opening Day of worship gatherings.', 'template: standard  2017-06-06 content updated --pb  2018-12-12 additional resources subsection added --pb  2020-01-17 content updated --pb  2020-12-14 changed Due in # Days from 231& to 235& & Duration from 7 to 28& --pb&  ', 1, 'todo', 234, 7, '{}'::jsonb),
  ('a5810175-38fa-517c-8759-4748f5fcc80f', '46e493a3-08d5-5bbc-bcdf-2df47d94a4f6', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop process for receiving, tracking and reporting donations', 'Set up a process for receiving, tracking and reporting tithes and other gifts so your donors can benefit from the tax deductibility of their gift.', 'Donations to the church are tax deductible for the donor. But only if they can prove they made the donation.  Now that you''ve made your software decision, it''s time to set up repeatable processes so that everyone involved can know what needs to get done, how it gets done, and who is responsible to do each part of the process.  The basic processes you''ll need to develop are:  Receive donations (check PO Box, log in to online giving, etc.)  Record donation amount, date, donor, etc. (see below)  Get physical donations to the bank (walk it in, scan with app, etc.)  Send donation receipts and thank you''s  Send mid-year and/or end of year giving statements  Here is an excerpt from <a href="https://www.irs.gov/pub/irs-pdf/p1828.pdf">IRS Publication 1828</a> regarding tax deductible donations:  Substantiation Rules  A donor cannot claim a tax deduction for any single contribution of $250 or more unless the donor obtains a contemporaneous, written acknowledgment of the contribution from the recipient church or religious organization. A church or religious organization that does not acknowledge a contribution incurs no penalty; but without a written acknowledgment the donor cannot claim a tax deduction. Although it is a donor''s responsibility to obtain a written acknowledgment, a church or religious organization can assist a donor by providing a timely, written statement containing the following information:  Name of the church or religious organization,  Date of the contribution,  Amount of any cash contribution,  Description (but not the value) of non-cash contributions,  Statement that no goods or services were provided by the church or religious organization in return for the contribution, if that is the case,  Description and good faith estimate of the value of goods or services, if any, that the church or religious organization provided in return for the contribution, and  Statement that goods or services, if any, that a church or religious organization provided in return for the contribution consisted entirely of intangible religious benefits, if that was the case.  The church or religious organization may either provide separate acknowledgments for each single contribution of $250 or more or one acknowledgment to substantiate several single contributions of $250 or more. Separate contributions are not aggregated for purposes of measuring the $250 threshold.', 'Decide how to use your chosen software to keep track of tax-deductible donations.  Document how you''re going to receive, track and report charitable contributions.  This action is complete when you have tested your system by  processing the first donation.', 'template: standard  2017-05-26 content update& --pb  2019-12-12 content updated --pb ', 0, 'todo', 68, 7, '{}'::jsonb),
  ('5adb5b2e-d5a6-5f1e-b1ad-dd03a2630318', '46e493a3-08d5-5bbc-bcdf-2df47d94a4f6', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Put financial checks and balances in place', 'Develop expectations for financial checks/balances, including money counting policies, to ensure finances are properly handled.', 'As noted in a previous PlanterPlan action, financial controls in the church are aimed at preventing two types of problems:  Actual loss of proper control of finances  The  perceived  loss of adequate control of finances  Avoiding both of these types of problems is very important. The easiest way to get audited/investigated by the IRS is a public scandal involving money. In the extreme, a church can lose its 501c3 status, be fined, and prosecuted.  These specific areas need defined expectations:  Processing of Weekly offerings (counting cash)  Will the money be counted immediately after church and put in the bank''s after hour depository on Sunday? Who will count? Who will record the check information to keep track of charitable contributions? Does the money always have to be controlled by two people? What will the money be stored in from the time it''s collected until it is deposited?  Independence  Does the same person who counts or handles deposits also write the checks and maintain the check book or are these different people? Can one person sign checks or are two independent people required to sign checks?  Financial Audits  How often will independent audits be conducted? Who will conduct them? How will they be reported?  Oversight  Who will be responsible for overseeing the financial systems? Who oversees this person?  Financial Reporting  What financial reports will be required? How often? Who gets them? How do you verify that only budgeted and authorized expenses are being made?  Credit Cards  Who is authorized to use credit cards? How do you ensure only authorized expenses are being charged (i.e. how do you substantiate the expenses after the fact since this bypasses the normal process of having a treasurer write a check).  Compensation Process  Who determines compensation packages? Are they fair and equitable? Are appropriate forms being maintained? Are applicable taxes being paid in a timely manner?  Reimbursement Accounting System  Is the system being maintained as approved by the Board? Are appropriate records being maintained? Are expenses being substantiated?  Petty Cash  Does the church allow a cash fund to be maintained in the office for minor expenses (e.g. stamps, etc)? If so, how is it maintained? How are each expenditure substantiated? Who is authorized to use it? What permissions are required?', 'Using the list above as a guide, determine which specific areas require checks and balances.  Write down expectations for each area.  Write down policies/procedures for each of the above areas based on your defined expectations.  This action is complete when all of the questions above have been answered and there are healthy, functioning checks and balances in practice.', 'template: standard  2017-05-26 content validated --pb  2019-12-12 content validated --pb ', 1, 'todo', 68, 14, '{}'::jsonb),
  ('7f32e2d6-766a-5295-91dd-671b63886879', '46e493a3-08d5-5bbc-bcdf-2df47d94a4f6', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Implement IRS-compliant reimbursement process', 'Establish a formal and disciplined process for reimbursing individuals and organizations to comply with IRS regulations.', 'The IRS permits organizations to maintain  accountable reimbursement plans  so that employees can be reimbursed for normal business expenses without being taxed on the income. The plan must be approved and formally implemented.  If you don''t get this right, your employees may have to count the reimbursements as income and pay taxes on it! And if you get it really wrong, the church could potentially lose its 501c3 nonprofit status.  Here is the excerpt from <a href="https://www.irs.gov/pub/irs-pdf/p1828.pdf">IRS Publication 1828</a>, Tax Guide for Churches and Religious Organizations:  "Payment of Employee Business Expenses  A church or religious organization is treated like any other employer as far as the tax rules regarding employee business expenses. The rules differ depending upon whether the expenses are paid through an accountable or non-accountable plan, and these plans determine whether the payment for these expenses is included in the employee''s income.  Accountable Reimbursement Plan  An arrangement that an employer establishes to reimburse or advance employee business expenses will be an accountable plan if it meets three requirements: (1) involves a business connection, (2) requires the employee to substantiate expenses incurred, and (3) requires the employee to return any excess amounts.  Employees must provide the organization with sufficient information to identify the specific business nature of each expense and to substantiate each element of an expenditure. It is not sufficient for an employee to aggregate expenses into broad categories such as travel or to report expenses through the use of non-descriptive terms such as miscellaneous business expenses. Both the substantiation and the return of excess amounts must occur within a reasonable period of time.  Employee business expenses reimbursed under an accountable plan are (a) excluded from an employee''s gross income, (b) not required to be reported on the employee''s IRS Form W-2, Wage and Tax Statement, and (c) exempt from the withholding and payment of wages subject to FICA taxes and income tax withholdings."  In summary, expenses must be for church business (ideally budgeted items) and must be "accounted for" and substantiated within a reasonable period of time, with any excess payments being returned to the church. Substantiation is required to be very specific and not lumped into broad categories.  The church Board should approve the reimbursable accounting plan in writing.', 'Develop a customized reimbursement process.  Obtain approval of the process by the church board or leadership team.  This action is complete when the Management Team has approved the reimbursement process.', 'template: standard  2017-05-26 content reformatted & resource link updated --pb  2019-12-12 content updated --pb ', 2, 'todo', 68, 14, '{}'::jsonb),
  ('2a7fb250-4ef7-5880-8aa0-d273978412b0', '46e493a3-08d5-5bbc-bcdf-2df47d94a4f6', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Implement financial records filing system', 'Develop a disciplined process to store historic financial records that meets IRS requirements.', 'The IRS is clear on the requirement to keep records to justify your tax-exempt status. The IRS gives considerable latitude in how to maintain the files. Virtually no direction is given other than advice on the types of records to keep. The IRS specifically cites the following types of records:  Organizing documents (e.g., charter, constitution, articles of incorporation and bylaws)  Meeting minutes  Property records  Financial records (general ledgers, receipts and disbursements journals, banking records, and invoices)  Payroll records  Be smart and set up systems to store records for each of these areas.  Good Records are the Law  Per <a href="https://www.irs.gov/pub/irs-pdf/p1828.pdf">IRS Publication 1828</a>,  Tax Guide for Churches and Religious Organizations :  Recordkeeping Requirements  All tax-exempt organizations, including churches and religious organizations (regardless of whether tax-exempt status has been officially recognized by the IRS), are required to maintain books of accounting and other records necessary to justify their claim for exemption in the event of an audit. (See Special Rules Limiting IRS Authority to Audit a Church below). Tax-exempt organizations are also required to maintain books and records that are necessary to accurately file any Federal tax and information returns that may be required.  There is no specific format for keeping records. However, the types of required records frequently include organizing documents (charter, constitution, articles of incorporation) and bylaws, minute books, property records, general ledgers, receipts and disbursements journals, payroll records, banking records, and invoices. The extent of the records necessary generally varies according to the type, size, and complexity of the organization''s activities.  The law does not specify a length of time that records must be retained; however, the following guidelines should be applied in the event that the records may be material to the administration of any Internal Revenue law.  Type of Record Length of Time to Retain  Records of revenue & expenses: Retain for at least four years after filing including payroll records return(s) to which they relate.  Records relating to acquisition: Retain for at least four years after the filing of and disposition of property (the return for the year in which disposition occurs including real, personal, and investments)', 'Decide which records to keep and to set up files for.  Purchase a file cabinet or similar.  Set up the initial files.  Define written expectations for the upkeep and maintenance of the files.  This action is complete when you have put a filing system or record book to use.', 'template: standard  2017-05-26 content reformated& --pb  2019-12-12 content updated --pb ', 3, 'todo', 68, 7, '{}'::jsonb),
  ('b5733928-63a6-5fa4-9af1-60c506f609da', '49e3b758-4630-5736-84ec-bf015921b6cc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set up Facebook Pixel tracking code', 'Install the Facebook Pixel code on your website to maximize your social media opportunities.', 'Facebook Pixel is an analytics tool that associates your website visitors with their Facebook account. It tracks when they visited your website, which pages, etc. Facebook won''t tell you exactly who those users are, but when you later place a Facebook ad, you can create custom ads for people that have already visited your church website.', 'Create a Business Manager account on Facebook.  Add to that a Facebook Ad Account.  Create your Facebook Pixel.  Install the Pixel code on your website (find help below).  This action is complete when you have fully installed the Pixel tracking code on your website.', 'template:  ', 0, 'todo', 115, 7, '{}'::jsonb),
  ('739dcf11-4723-55fd-a541-fb952ee56218', '49e3b758-4630-5736-84ec-bf015921b6cc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Initiate first boosted post', 'Create a social media post and pay to boost it to a custom audience you''ll specify.', '[content pending]', NULL, 'template:  ', 1, 'todo', 119, 29, '{}'::jsonb),
  ('2868577e-95e7-5000-a923-45410ff60050', '49e3b758-4630-5736-84ec-bf015921b6cc', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Initiate first paid social media ad', 'Create an ad campaign on Facebook or other app to reach users in your area.', 'Your organic content on social media isn''t being seen by very many.  Pay to Play  There was a time when Facebook users would see your church''s content in their feeds. Now, even if they''ve liked your page and followed it, chances are very small they''ll see anything that you post on the church''s page. It has become a pay-to-play environment. Other platforms are following suit.  Since you already installed the Facebook Pixel tracking code on your website (see previous PlanterPlan task), you can now use retargeting ads that will be specific to users that have already visited your church website.', 'This action is complete when you have published your first paid social media ad.', NULL, 2, 'todo', 180, 29, '{}'::jsonb),
  ('4701f297-cb76-559d-a52b-30936b284e3c', '4de0d2cb-f344-5fa4-940b-de3843b74ee9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop a church planting philosophy', 'Articulate in writing a short summary of the unique church planting DNA that will undergird the church you are planting.', 'You are planting this church as a result of 2,000 years of church planting. Don''t be the last link of the chain.  You can''t just hope that planting another church will happen. Now is the time to set church planting in the new church''s DNA and put teeth to your decisions.  Paint a picture of what your church planting efforts have accomplished by your 5th anniversary. Be specific.  Now determine the very practical things you''ll need to do to make that vision a reality:  How will you embed church multiplication in every level and system in your church?  How will you fund church planting?  How will you build a church planter pipeline?  What will your church planting scorecard be?  How will you create a culture of sending?  Which church planting network or group will you associate with?', 'Write out a vision for your church''s church planting.  Record all of your answers to the questions above in your  Church Multiplication Strategy  document.  Set SMART goals for each element.  This action is complete when you have hammered out these elements of your church planting philosophy.', 'template: standard  2017-06-02 content updated --pb  2018-04-24 outdented& from child to task, set Parent ID to #268 --pb  2018-11-20 indented from task to child, changed parent ID from #268 --pb  2019-12-05 content updated --pb  2020-12-11 changed Due in # Days from 52& to 159 --pb&  ', 0, 'todo', 158, 14, '{}'::jsonb),
  ('e1d95b53-853c-5899-beac-6d965a1567ab', '4de0d2cb-f344-5fa4-940b-de3843b74ee9', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine global missions involvement', 'Decide how your church will be involved in carrying out the Great Commission on a global scale.', 'Churches in North America have a great history of being involved in global missions. Sometimes it''s difficult to convince established congregations to get involved in domestic church planting because they''re so focused on global missions.  Don''t let the pendulum swing so far toward domestic church planting that global missions are ignored. Connecting your congregation to another people group or country can be a very healthy thing.', 'Decide now how you will lead your church to participate in global missions and at what point.  Include that commitment in your  Church Multiplication Strategy  document (download as <a href="/resources/item/323">MS Word</a> or <a href="/resources/item/360">Google Doc</a>).  This action is complete when you have included a statement on global missions involvement in the Church Multiplication Strategy document.', 'template: standard  2017-06-02 new content written (previously blank) --pb  2018-04-24 outdented& from child to task, set Parent ID to #268 --pb  2018-11-20 indented from task to child, changed parent ID from #268 --pb  2019-02-12 changed "include in Philosophy of Ministry document" to "include in Church Multiplication Strategy document" --pb  2019-12-05 content validated --pb  2020-12-11 changed Due in # Days from 52& to 159 --pb&  ', 1, 'todo', 158, 14, '{}'::jsonb),
  ('5e590fd6-787c-54f3-a035-8a6949d0a639', '5e481cbc-1ac7-525c-889d-bfdf1749d088', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit set up and tear down team leader(s)', 'Identify and empower a resourceful, reliable leader for the set up and tear down team(s) so that all equipment gets set up properly and on time for the worship gatherings.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has both leadership potential and can recruit people to the team.  Your set up and tear down team leader(s) should be more of a recruiter, people organizer and cheerleader than a skilled doer. Set up and tear down don''t happen without a full team.  Consider writing out a job description and basic expectations you''d have of any set up or tear down team leader. Go over those with your candidate(s) and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  recruiting team members  scheduling a training event  scheduling volunteers so that there are no gaping holes in the schedule', 'Spend time in prayer asking God to raise up leaders.  Develop a leader and empower them to build the team.  Communicate expectations to the leader.  Get a commitment from the leader to own the processes and leadership of the team.  This action is complete when you have recruited and trained set up and tear down team leader(s).', 'template: standard  2017-06-09 content validated --pb  2020-12-14 changed Due in # Days from 238& to 228& --pb&  ', 0, 'todo', 212, 14, '{}'::jsonb),
  ('19cae3a0-44b0-5d59-a37d-52b389a0ac4b', '5e481cbc-1ac7-525c-889d-bfdf1749d088', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train team on set up and tear down', 'Train the set up and tear down team(s) to efficiently and safely unload, set up and reload equipment.', 'The first few times the team(s) sets up and tears down the equipment, it will take a long time. Over time, the team becomes more efficient and gets faster. This is why you have to train the team prior to the launch of worship gatherings.  Preview services provide a great environment for this. Make sure that you have practiced setting up and tearing down once at a dry run/training event (see subsequent PlanterPlan task). Then work with team to execute the set up and tear down at all of the preview worship gatherings you have scheduled prior to the Opening Day of worship gatherings.  Have your team create set up and tear down manuals that show what goes where and how things get loaded back into the truck/trailer. This makes training new volunteers easy and intentional.', 'Schedule a time to train the team (a dry run or practice gathering before the previews).  Conduct the training.  This action is complete when you have recruited and trained the initial set up and tear down team(s).', 'template: standard  2017-05-19 content updated --pb&  2020-01-20 content updated --pb  2020-12-16 changed Due in # Days from 224& to 219& & Duration from 121& to 98& --pb&  ', 1, 'todo', 227, 14, '{}'::jsonb),
  ('0ce378c5-6879-515a-820e-937d52dd94a6', '62709b20-dc98-5b4d-82d8-2c39df25fc8e', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Complete self and pre-assessments', 'Complete several personality profiles to understand how you can best use your natural wiring & gifts to lead a church planting team.', 'Church planting is hard work. It requires a special person to be able to succeed. Several personality traits have been shown to be helpful to planters. The following list is adapted from a research project completed by Dr. Charles Ridely for 13 denominations on success factors for planters. (<a href="https://churchleaders.com/outreach-missions/outreach-missions-blogs/141404-10_church_planter_qualities.html">read more</a>)  A good planter candidate:  Can envision a desired future and sell the vision to others  Is self-motivated  Is able to create buy-in from others  Is a successful evangelist  Is a relationship builder  Is more interested in health than quick growth  Is an observer of the culture  Is an equipper  Is flexible and adaptable  Is able to develop and empower teams  Is resilient  Has strong faith  Complete several personality profiles to determine if you have the leadership skills required to launch a church. These profiles can be used as a tool to confirm God''s calling. One excellent place to start is <a href="https://www.churchplanterprofiles.com">Church Planter Profiles</a> by Gateway Leaders. There you can complete several online personality profiles to determine suitability to church planting.  Other helpful sites are:  <a href="https://asburychurchplanting.com/eq-assessment/">Church Planter Self Assessment</a> (Asbury Seminary)  <a href="https://www.namb.net/send-network/church-planting/assessment/">NAMB Assessment Process</a>  <a href="https://courses.pathwaylearning.org/library/calling-course-33243/477427/about/">Pathway Learning</a>', 'Complete at least one of the planter-targeted personality profiles.  This action is complete when the planter prospect has completed at least one personality profile. "', 'template: standard  2017-07-28 content & external links updated --pb  2018-12-12 additional resources subsection added --pb  2020-12-11 changed Duration from 14 to 7 --pb  2021-03-12 added Ephisiology& URL --pb  2022-11-21 Replaced EFCA& Church Planter Skill (Broken Link) and ACT 29 Assessment (used in later task) with Asbury& Self Assessment and updated Alan Hirsch Ephesiology& class --sc ', 0, 'todo', 6, 7, '{}'::jsonb),
  ('8d511c81-86f5-5598-a5d3-10cc71c71c24', '62709b20-dc98-5b4d-82d8-2c39df25fc8e', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Assess your own passion for reaching people far from God', 'Conduct a personal assessment to determine your own passion for reaching people far from God.', 'Creating an evangelistic DNA begins with the planter. You will have difficulty establishing an evangelistic DNA in the church if you don''t have a personal passion for reaching people far from God yourself.  Ask yourself the following questions to help assess your passion:  How many people have you led to Christ in the last year?  How many non-Christian friends do you have?  How often do you spend time with them?  Are non-Christians comfortable around you? Are you comfortable around them?  Does it make you uncomfortable to be around non-Christians with obviously immoral lifestyles?  How often do you pray for people far from God?  Do you know your neighbors?  Where do you spend time in the community to connect with people far from God?  Also ask others to assess your passion for reaching people far from God - ask your coach, your spouse, former co-workers, etc. If you find yourself lacking in this area, start praying about it. Pray for God to give you a passion for people far from God. Pray for opportunities to talk with people and build relationships.  Often a passion for people far from God develops out of relationships with those people. If others have identified this as a weakness in you, ask your someone to hold you accountable for developing this passion.', 'Ask yourself the above questions.  Ask others to assess your passion for reaching lost people.  Spend time in prayer asking God to burden you with a passion for people far from God.  This action is complete when you have committed to being passionate about reaching people far from God.', 'template: standard  2017-06-02 content updated --pb  2019-05-01 additional resources subsection added --pb  2019-11-22 content updated --pb  2020-12-11 changed Due in # Days from 52 to 7 ', 1, 'todo', 6, 7, '{}'::jsonb),
  ('b6a3d53c-a58e-5960-876f-ba8639a22939', '62709b20-dc98-5b4d-82d8-2c39df25fc8e', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Undergo a formal assessment', 'Complete an assessment by an independent organization that specializes in discerning a leader''s suitability for planting.', 'Placing enthusiastic people in posts for which they are unprepared or unqualified is extremely counterproductive. It often ends up even damaging them and their families.  Assessment is the process of discerning two important factors in church planting:  Qualification  Readiness  We''re all wired up differently. Certain personality types do really well as lead planters. Some types are a bad match and attempting to plant will cause untold anxiety, stress and even emotional damage.  And even those that have the natural temperament to plant may not have the life and ministry experience necessary to start a new church.  A formal assessment will let you know where you stand on both of these counts. The assessment can be as short as one day, but is commonly 3-5 days in length. It''s often done in a group setting with other potential planters and includes a combination of:  interviews  group exercises  essays  assignments  The evaluation team observes you in a number of different situations.  You will usually get a detailed report and an individual formal debrief. The report will include your strengths as well as developmental suggestions. It will make a clear recommendation as to your readiness to plant a church within the next 2 years.  Assessment History  For two decades, assessment has been used by church planting strategists across North America. Borrowing from experts like Dr. Thomas Graham and Dr. Charles Ridley, a process has been developed to help interested candidates determine their giftedness and readiness for church planting, either as the leader of a team, a member of a team, or as a ''solo'' church planting pastor. Church planting assessment integrates several lenses of evaluation to help a couple or individual discover as much about healthy placement in church planting as possible. These lenses include:  Written expression, in the form of an extensive questionnaire, a professional resume, exercises, and projects, are evaluated by the assessment staff  Psychological instruments that are employed to identify any potential issues which impact individual wholeness, marital adjustment, and professional interaction  Experienced practitioners observing candidates in simulation modules, team activities, and personal interviews to provide real-life perspective for potential church planting scenarios  Peer assessments that provide each candidate with invaluable input from others with whom he/she works during the assessment  Self assessment - perhaps the most important directional outcome of all. Processing all input available, the candidate (and spouse where applicable) is able to make a highly informed conclusion about placement and timing in church planting ministry.  You have many options for attending an assessment center. <a href="https://church-planting.net/church-planter-assessment/">Passion for Planting</a> has an Assessment Center that holds assessments several times each year. Learn more about the Passion for Planting Assessment Center and check out upcoming dates:  <a href="https://church-planting.net/church-planter-assessment/"> </a>  Other assessment centers include:  <a href="https://www.converge.org/church-planting/assessment">Converge Assessment Center</a>  <a href="https://stadiachurchplanting.org/services/discoverycenter/">Church Planting Assessment Center (CPAC)</a> by Stadia Church Planting  <a href="https://www.acts29.com/who-should-apply/">ACTS 29 Assessment</a>  <a href="https://resources.pcamna.org/categories/assessment/">PCA - Mission to North America</a>', 'Choose an assessment event to attend.  Register and complete assigned pre-work.  Arrange for travel and childcare as appropriate.  Participate in the event.  This action is complete when the planter has undergone a formal assessment.', 'template: standard  2017-08-29 content update --pb  2019-11-22 content updated & links verified --pb  2020-01-13 replaced broken gdurl& link to image --pb  2020-12-11 changed Due in # Days from 7 to 14  2020-12-11 changed Duration from 60 to 14  2022-11-21 deleted Church Planter Assessment Center by Lifeway& and Northwest Church Planting& and updated PCA& Assessment link--sc ', 2, 'todo', 13, 14, '{}'::jsonb),
  ('577bdf35-15f1-5a15-8356-3f7bc8033ec1', '62709b20-dc98-5b4d-82d8-2c39df25fc8e', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a copy of your church planter assessment report', 'Get a copy of your assessment report for forwarding to church planting groups and drafting your own personal development plan.', 'Your assessment was an intense multi-day experience which combined interviews, presentations, and written evaluations by peers, assessors, and even yourself. The experience culminated in a written report with recommendations on your suitability to lead or participate in a church plant. Most planters find the feedback invaluable in preparing them for the challenges ahead.  A subsequent PlanterPlan task will guide you through drafting a personal development plan to maximize the strengths identified in the report and select books & courses to compliment your training.  If you are courting church planting agencies for collaboration and support, the assessment report may prove invaluable in establishing your readiness to plant with them.', 'Thank you assessors for their time & wisdom.  Make sure you are clear on how and when you''ll get a copy of your report.  Save the report to your device and back it up in the cloud.  This action is complete when you have received your assessment report.', 'template:  2017-08-29 content updated --pb  2019-11-22 content updated --pb ', 3, 'todo', 27, 7, '{}'::jsonb),
  ('3509301c-4244-568f-a023-202de0cd711c', '6799a515-efe8-5a86-9f5e-0f0b7496b756', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Craft your mission statement', 'Translate the mission Christ gave His church into a short phrase that is memorable and meaningful to your community.', 'You don''t get to determine the church''s mission. Jesus did that while he was still bodily walking the earth 2,000 years ago.  What you absolutely must do is restate the mission in a way that makes sense to people in your community.  At the heart of most evangelical church mission statements is the intersection of the Great Commandment and the Great Commission.  Here are some useful questions to get you going:  What does it mean for your church to win?  What does it mean for your church to be faithful?  What does hitting the bullseye look like?  What makes God smile?  Why did Jesus establish his Church?  Caution: The mission statement is one of the first things you will do that affects what the church will become. If you craft a mission statement filled with "churchy" words, you can expect to create a churchy culture.  Also note that the mission statement will be inward-facing language. Another PlanterPlan task will walk you through crafting a  tag line  that will be the outward-facing communication of your church''s brand and mission.', 'Read  Church Unique  chapters 11 & <a href="4 Kinds of Church Members and How They Relate to Your Church''s Mission by Will Mancini">12</a>.  Meditate on passages where Jesus describes why he came and what he sent his church to do.  Download and use the <a href="/resources/item/349">Mission Development Exercise</a> (instructions are on page 126 of  Church Unique ).  Draft several initial versions of your mission statement each using 12 words or less.  Run them through the <a href="https://www.visionroom.com/tag/5-cs/">Five C''s</a>.  Ask for input from friends and peers.  Get input from friends and neighbors who are not Christians.  Finalize a written mission statement.  This action is complete when you have finalized a written mission statement.', 'template: standard  2017-06-01 content updated, resource link removed --pb  2017-11-27 content updated to align with Church Unique --pb  2019-11-26 content updated --pb&  2020-12-11 changed Due in # Days from 45& to 39 --pb&  2022-11-21 updated link ', 0, 'todo', 38, 14, '{}'::jsonb),
  ('5c9ab902-5931-5ba3-a3ee-b95c18f3a952', '6799a515-efe8-5a86-9f5e-0f0b7496b756', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Discover values', 'Describe what is important to your church by crafting a short list of church values.', 'The values of the church are the things that define why you do things and what you honor. Your values will play a significant role in shaping the culture of your church.  Values are not something you can simply proclaim. You have to live them out, demonstrating them by your actions. Values become a guide for defining normal behavior.  They need to become so deeply ingrained in the church''s culture that the actual words rarely need to be spoken.  Too many churches post a list of values, but then live out a different set of values. Values are caught more than they''re taught.  Your list should never be longer than 5 values - any more and even your staff won''t be able to recite them, let alone live them out intentionally. If your initial list has more than 5, prayerfully consider how to merge or consolidate similar values into broader concepts.  NOTE: these are  organizational  values that become decision-making filters. They''re not individual spiritual growth measures - those will be developed in a subsequent PlanterPlan subtask.  For each value ask: "Why is this value important?"', 'Read the brief post <a href="https://www.visionroom.com/the-starting-point-for-discovering-vision-and-values/">The Starting Point for Discovering Vision and Values</a> from Auxano''s Vision Room.  Read  Church Unique  chapter 13.  Make an initial list of as many possible values that you can think of. Each value should flow from the question, "Why are we on mission?"  Many of your listed values will be closely related to each other. Attempt to group similar values together to reduce the list to no more than 4 or 5 values.  Download Auxano''s <a href="/resources/item/350">Value Statement Worksheet</a> and write out several sentences for each value that starts "As demonstrated by&hellip;"  Run your list of values through the <a href="https://www.visionroom.com/tag/5-cs/">Five C''s</a>.  Get feedback from others.  Finalize your values.  This action is complete when you''ve finalized the church values.', 'template: standard  2017-06-02 Purpose & Description updated; Actions and resource not --pb  2017-11-27 content updated to align with Church Unique --pb  2018-02-15 tweaked language based on feedback from Will Heath @& Auxano& --pb  2018-10-19 additional resources subsection added --pb  2019-11-26 content validated --pb ', 1, 'todo', 45, 14, '{}'::jsonb),
  ('b85af3b0-314f-525d-9179-5df55e995f33', '6799a515-efe8-5a86-9f5e-0f0b7496b756', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Define strategies', 'Write a short list of strategies that define how you will ''do church''.', 'Strategies answer the question, "How do we carry out the mission?"  Using the metaphor of a factory, the strategies are the machines or stations along the assembly line. Your strategies are the pathway by which you makes disciples and carry out the mission.  You need to be able to sketch your strategies on the back of a napkin as a diagram or simple mnemonic device.  Strategies should be  venue  language (where to go), not imperative language (what to do). Your guests'' fundamental question when they show up is, "Where do I go to [park, drop off kids, etc.]?" Your strategies should sound like the environments or gatherings that you will create to foster values and disciple-making.  The few strategies you settle on will become  buckets  for how you''ll communicate different groupings of teams, groups, etc.', 'Read  Church Unique  <a href="https://www.willmancini.com/wp-content/uploads/2012/08/Ch14_Strategy.pdf">chapter 14</a>.  Scour the Gospels for principles you can learn from Jesus'' earthly ministry.  Draft several versions of your church strategies.  Download Auxano''s <a href="/resources/item/351">Our Strategy Picture Worksheet</a> for help creating your back-of-the-napkin version.  Consider how your strategies mirror your values and clarify your mission statement.  Run your strategies through the <a href="https://www.visionroom.com/tag/5-cs/">Five C''s</a>.  Get feedback from others.  Finalize your strategies.  This action is complete when you''ve finalized the church''s strategies. "', 'template: standard  2017-06-02 content validated --pb  2017-11-27 content swapped (was Measures, now Strategies); content updated to align with Church Unique --pb  2018-02-15 tweaked language based on feedback from Will Heath @& Auxano& --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 52& to 46& & Duration from 14 to 7& --pb&  2022-11-21 updated link --sc ', 2, 'todo', 45, 7, '{}'::jsonb),
  ('2528e922-39a3-5f1f-aab2-91557d32b343', '6799a515-efe8-5a86-9f5e-0f0b7496b756', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recognize marks of a mature disciple', 'Describe what a mature disciple looks like so that everyone can know what the  win  is.', 'You measure what you value. Most American churches primarily measure attendance, offerings and buildings. We train people that those things define success. This is part of why so many American Christians believe that church attendance equals faithfulness and spirituality. Whether intentional or not, these measures define the culture and priorities of the church.  A better way is to determine what a disciple of Jesus looks like. Missional measures answer the question, "What are the marks of someone following Jesus?" or, "What fruit does a disciple produce?"  Many of these missional measures will come directly from Scripture. For instance, Galatians 5:22-23 tell us the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness, gentleness and self-control. Also, the Great Commission teaches us that the job of each Christian is to make disciples. Other measures will come out of your strategy. For instance, in a small-groups-centric church, a missional measure may be involvement in a small group.  Once missional measures are defined, you''ll have a clear filter for determining if ministries and programs are effective. If the ministry is producing disciples as defined by the measures, it''s worth doing. If not, the ministry either needs to be adjusted or ended.', 'Read the <a href="/resources/item/352">The Difference Between Strategy and Measures</a> provided by Auxano.  Read  Church Unique  chapter 15.  Investigate scripture to re/learn how disciples of Jesus live and what fruit they produce.  Make a list of the characteristics you desire to see people in the church grow into. See <a href="https://www.willmancini.com/wp-content/uploads/2013/06/Measures-as-the-Portrait-of-Discipleship_CU.pdf">sample</a> list provided by Auxano  Boil the list down to no more than 3-5 key marks (or risk recreating a pharisaic checklist).  Review your measures to make sure they aren''t  corporate  measures, but individual marks.  Now review these marks against your ''Strategies''. Be brutally honest - will the strategies you''ve proposed  really  produce the kind of disciple you''ve just described? Adjust your measures and/or your strategies as necessary.  This action is complete when you have defined the missional measures for the new church.', 'template: standard  2017-11-27 content swapped (was Priorities/Strategy, now Measures); content updated to align with Church Unique --pb  2019-11-26 content validated --pb  2022-11-21 updated links --sc ', 3, 'todo', 52, 14, '{}'::jsonb),
  ('b75e2ea1-53db-52a9-9bfb-5df859e64763', '6799a515-efe8-5a86-9f5e-0f0b7496b756', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Paint a vision picture', 'Sketch basic language, metaphors and milestones that capture the picture of the future God is calling your church to co-create.', 'Vision is different that Mission  There are so many different approaches to vision & mission. Every book you read on the subject comes at it a little differently, and even uses the same words differently. For clarity on the difference, re/read ''Mission and Vision: Clarifying the Difference'' in  Church Unique  (page 179).  There are two aspects of the vision that you should be able to articulate:  Subjective or Qualitative vision (story)  Objective or Quantitative vision (numbers)  Qualitative Vision  Rather than write another concrete statement that competes with your mission statement, begin to build a bullpen of phrases, stories, images and metaphors you will pull from each time you describe the vision of the church. You will cast vision with living language, narrative that is painted within the bounds of the 4 sides of your Vision Frame. God''s vision for your church''s future is so multi-faceted, you couldn''t really put it into a sentence anyway.  Quantitative Vision  There is also a part of the picture of the preferred future that should be measurable. This is the scorecard of your congregation as a whole. Think beyond attendance & offerings; what are the milestones or measures of success that God is inspiring you to strive for?  Purchase  God Dreams  by Will Mancini  The sequel to  Church Unique  is  God Dreams , written to more fully flesh out the Vision Proper. While the sides of the Vision Frame help you define culture,  God Dreams  will help you paint a more compelling picture of God''s preferred future for your church. It''s more process, direction and strategic road map.', 'Download and read <a href="https://www.willmancini.com/wp-content/uploads/2012/05/Articulating-Vision-Proper_CU.pdf">Articulating Vision Proper: the Spider Diagram</a> provided by Auxano.  Read  Church Unique  chapter 17.  Draft a qualitative narrative of the preferred future God is calling you to co-create.  Draft a few quantitative measures that God is challenging you to accomplish.  Review both of these in the light of the 4 sides of your Vision Frame. Ask yourself if they work together and whether the mission & strategies you''ve articulated are likely to bring about the future you''ve described.  Cast the vision to your coach and get feedback.  Adopt vision language that you will use to inspire and lead your church.  This task is complete when you have a final draft of your Vision Proper.', 'template: standard  2017-06-02 Purpose & Description updated; Actions and resource not --pb  2017-11-27 content overwritten (was Decision-Making, now Paint a Vision); content inserted& to align with Church Unique --pb  2018-02-15 tweaked language based on feedback from Will Heath @& Auxano& --pb  2019-11-26 content validated --pb ', 4, 'todo', 52, 14, '{}'::jsonb),
  ('2c9e6938-6ea0-5ebc-8c65-ebfd57e51ba1', '699ba2b6-3497-514e-adc0-a85dc04f8ae8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Clarify church planting approach and model', 'Clarify which church planting approach and model God is calling you to use so you can communicate it clearly and partner with the right organizations.', 'There is no universally agreed upon list of church planting models - ask ten different organizations for a list of the different models and you will get ten different lists. Instead of providing a comprehensive list of all possible models, we will attempt to highlight the high-level considerations that distinguish different models.  Note:  Often people confuse "models," "strategies" and "approaches." For example, the decision to host a worship gathering in a small coffee shop venue with candles to reach Gen-X''ers is a strategy and not a model. However, starting churches that meet exclusively in coffee shops would be a model. An approach would be the way in which the leader(s) goes about starting these new environments or churches.  ### Approach  Church planting  approaches  typically fall into three major categories:  Parachute  A planter and their family move into a new location to start a church from scratch. The planter begins with little support and few connections within this new area. The planter and their family are "pioneering" new territory. Where there is great risk, there is great reward, but this approach is not for the faint of heart.  Sponsoring Church  An existing church provides the initial leadership and resources (dollars and/or people) to get a new church started including the selection of the church planter. Often the church planter is selected from within the church and has already bought into its vision, values and beliefs. The existing relationship allows for a close working relationship between the "mother" and "daughter" churches.  Although the new church is autonomous, the sponsoring church often has significant influence in the new church (including decision making during the pre-launch phase). Advantages often include increased financial resources and the ability to draw core team/launch team members from the mother church.  Collaborative Network/Partnership  This is a rapidly growing trend where churches work together to plant churches. These alliances are referred to as collaborative, partnership or planting networks. The participating organizations often share common beliefs and a passion for starting new churches. Planters often get many of the benefits of the "sponsoring church" model but with increased autonomy in decision making.  The approach doesn''t dictate the model. All of these approaches can and do employ various models in order to accomplish their mission of planting healthy churches. Therefore, the question becomes which  approach  works best for you based on your situation and calling?  ### Model  Along with determining your  approach , you have to determine which  model  best positions you to accomplish the vision God has placed in your heart and mind. Work through these questions to gain some clarity on models:  What is your strategy for disciple-making?  Will you build a core team one person at a time through relationships with the lead planter? Will you draw a crowd through marketing and outreach? Will you develop fully devoted followers through one-on-one discipleship in small groups? Will you focus on reaching seekers and establishing easy "next steps" for them to get connected at their own pace through a range of felt-needs-based ministries and programs? Will you use a formalized class/curriculum based approach (like 101, 201, 301, 401)? Will you hold regular Sunday worship gatherings? What will the role of your small groups be? Will teaching be primarily done through Sunday sermons, through classes, or through small groups? Do you anticipate having a public launch or functioning on a more informal, relational basis?  What will your staffing philosophy be?  Will the new church be able to financially support a full-time paid minister? Will you be the only staff initially or will the plant have the funding for a staff team? If bi-vocational or co-vocational, how much time will you have to dedicate to the church? Is the plan to eventually become paid by the new church or to continue in a co-vocational capacity?  What size Launch/Core Team will you build?  How large do you expect the launch team/core team to be when public worship gatherings are started? How do you intend to build and add to the launch team? Will the team primarily come from a single existing church, multiple existing churches, or from non-believers?  How will you build community awareness about the church?  Will you grow exclusively through friends inviting friends - relationships? Will you use outreach activities to build awareness and start conversations in the community? Will you use marketing activities to build awareness and start conversations in the community? Will you attempt to establish a broad "brand" awareness and reputation in the community? If so, how?  What is the purpose for starting the new church?  Is the new church being founded to reach more lost people in a new geographic area/location? Is the new church being formed as a result of a church split? Is the church being started to revitalize a dying church? Is the church being started to allow a new campus or site of an existing church to be started? If so, for what purpose (e.g. alleviate overcrowding at the main campus, for the convenience of existing members, to reach new people, etc.)?  Are there models to which you already have an affinity or bias?  Most of us have a hard time breaking past paradigms. Are you coming out of an experience that will bias you to a particular model? Have you seen a specific model in practice that you feel God may be calling you to? What model best fits your experience and gifting? Are there specific models that will best fit the geographic area to which you are called or to the people group you will be reaching?  Take some time to answer these questions as you consider which model fits your vision.  Most models fit into one or more of the following categories:  House/Micro Church Network  Small (5-20 people) groups/cells form and multiply via a network of people meeting in homes. In some cases, the individual cells are connected in a larger network that meets together periodically in a large group setting. This relational model focuses on personal obedience, care and teaching through one-on-one and small group disciple-making. Groups are birthed through multiplication. This model requires very little funding.  Launch Large  This model is focused on gathering a large group of people for a worship gathering. It starts with a vocational lead planter, and possibly a staff team, gathering a launch team of 40-60 people. This launch team will commit to spreading the word about the church, serve on ministry teams to create worship environments, and support the church financially. These launch team members can come from sending/sponsor churches or through personal contact by the planter or staff team. In order to accomplish the goal of launching large, the new church will invest a significant amount of money and energy into staffing, marketing, equipment, facilities, etc, so it must be well-funded. This model is typical for suburban settings.  Missional/Incarnational  If church plants could be compared to kitchen appliances, the launch large model would be a microwave and this model would be the slow cooker. They both gather for public gatherings (although sometimes not every week), but instead of trying to launch large, this model launches slow. It focuses on building relationships and getting people into smaller groups where they can study God''s word together and serve each other and their community. It''s not focused on calling the community to their worship gathering, but infiltrating their community through service. Since this model takes a longer time to gather enough people to support any full-time staff members, the leaders need to start bi-vocationally.  Satellite Campus (Multisite)  An existing church opens new locations.  The idea is for one church to have many meeting locations. Motives range from reaching more lost people to making more room at an existing location. The evolving multisite model is proving important in creating an entrepreneurial spirit of multiplication/replication within existing churches.  Restart/Re-launch  An existing struggling church decides to bury the old and plant a fresh new church. The restart may or may not be at a new location and may or may not be with the same leadership. The resources of many older, stagnant churches are a good way to bring new life to the community being served.  Church Split  Unfortunately, this model of "church planting" most often results from disunity.  As a result, it is the most dangerous form of planting. A split typically occurs when competing groups conclude there is less energy required to split or "divorce" than to resolve differences and reconcile.  The underlying factors causing the split often develop over years, only to explode in what seems like a spontaneous act. In many cases, the dysfunctional character traits of the old church carry forward to the new churches.  Each of these models is unique, but they all have something to offer to the next model (perhaps with the exception of the church split). The decision of which model to employ should take into consideration the community context of the new church, the people it seeks to reach, and the wiring of the planter. It must also be bathed in prayer.', 'Clarify which church planting approach you will use.  Clarify which church planting model you will use.  This action is complete when the planter is able to clearly articulate his church planting approach and model.', 'template: standard  2017-05-31 content reformatted and validated --pb  2019-11-19 content updated --pb  2019-12-03 additional resources subsection added --pb  2021-03-08 hyperlink updated --pb ', 0, 'todo', 45, 14, '{}'::jsonb),
  ('5813391c-3957-5d55-a284-e9e0964d36e2', '699ba2b6-3497-514e-adc0-a85dc04f8ae8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop a preliminary budget for fundraising purposes', 'Identify fundraising requirements for recruiting prospective financial supporters.', 'You''ll work up a formal budget in a subsequent PlanterPlan task. For now, you need to identify a very basic budget to determine a fundraising goal that you''ll use with potential supporters. The budget should be simple, including only the major expense categories.  In the launch large model, each of the following categories represent roughly 25% of the total expenses through launch:  staffing  marketing/outreach  equipment  administration/operations  Percentage vary widely in other models.  Expenses  Where does all the money go? This is the question you have to ask. And soon have an answer for curious prospective donors.  Money follows vision, so the type of church you plan to start significantly influences the money required to start. In a previous task, we discussed church planting models. As you might expect, micro churches require far less funding than launch large.  In general, expenses through launch (pre-launch phase) can be grouped into the following categories:  Staffing  How much will you spend on staffing? It depends on how many staff will be hired, how much they will be paid, when they will be hired, and whether they are expected to raise any outside support. In a micro church, staffing expenses may be zero. In a multi-staff, launch large plant, staffing expenses could be well over $100,000 annually.  Equipment  Most new churches have a number of one-time expenses for equipment purchases. These include but are not limited to: a sound system, lighting, projectors, storage cabinets, children''s supplies, Bibles, a trailer, etc. Depending on the quality and size, total equipment costs can range from zero to $80,000 or more. Unlike staffing expenses which are ongoing, most equipment purchases are one-time expenses up front.  Marketing and Outreach  Marketing and outreach are all about starting conversations with people in the community.You can no longer rely on one big marketing campaign just prior to launch to establish name recognition. You have to take a more balanced approach between outreach and marketing activities. A new church is ready for a big direct mail campaign only AFTER establishing broad name recognition in the community.  Facilities  Most new churches cannot afford to purchase a building (nor should they). Instead, they rent schools, movie theatres, or community centers. Sunday rent typically ranges from $12,000 to $60,000 per year for Sunday mornings. Additional facility costs could include rented office space. During the pre-launch phase, when the new church has not yet started weekly gatherings, facility costs will be much lower. Costs will be driven by the timing of when you start weekly worship gatherings.  Operations  Ongoing operations including ministry expenses, printing, copying, website, email, software, office supplies, insurance, phones, etc.', 'Develop an initial preliminary budget for fundraising purposes using the guidelines above.  Use the total budget number as your goal for fundraising.  This action is complete when you haves developed an initial budget to support your fundraising.', 'template: standard  2017-05-31 content reformatted --pb  2019-11-19 content updated --pb ', 1, 'todo', 45, 14, '{}'::jsonb),
  ('bf6a01ac-ed4b-58e2-b0a5-145b79750b45', '79aed685-16bd-5ce6-b75a-ad54e629c8f8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Take a fresh look at disciple making in the Bible', 'Examine with fresh eyes what God''s word shares with us about making disciples and carrying out the Great Commission.', 'Jesus didn''t leave any doubt as to what the mission of His church is: make disciples. That''s our number one mandate. What''s less clear is how do we do it? How do we obey Jesus'' last command?  Are disciples made through attending worship gatherings? Are they produced by attending a small group or serving on a ministry team? Are they developed by practicing spiritual disciplines like praying and reading God''s word?  What will your church do to help people take next steps in their relationship with God and live on mission for him? That''s what you''ll need to be clear about and the best place to find the answer to that question is the Bible.  Revisit the gospels to see what Jesus did to make disciples. Then look in the book of Acts and Paul''s epistles for clues about how Jesus'' first disciples took what they learned from him and then imparted to others in their efforts to make more disciples.  From this investigation you''ll want to articulate the following:  How you see the Bible defining discipleship  What a disciple looks like in the Bible  The disciple-making process you see in scripture  The major stages of spiritual development in the life of a disciple', 'This action is complete when you''ve investigated Jesus'' method for making disciples and can articulate what discipleship looks like in the Bible.', 'template:  2022-11-21 updated resources --sc ', 0, 'todo', 35, 14, '{}'::jsonb),
  ('90ba0375-6b8f-5da9-94cf-acfccfbd9eda', '79aed685-16bd-5ce6-b75a-ad54e629c8f8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a contextual definition of ''disciple''', 'Develop a concise definition for what a disciple is in your church.', 'Many churches talk about making disciples, but what is a disciple of Jesus? As a church planter you may have an idea in your head as to what a disciple is, but how can you communicate that in a way so everyone in your church knows what a disciple is and share that truth with others?  The easy way to complete this task is to define a disciple as a follower of Jesus. That definition passes the concise test, but it''s also vague and uninspiring. Think about developing a definition of a disciples like developing a mission statement for your church. Your mission as a church is to make disciples, but that''s probably not your mission statement, right? Why? Because it''s not compelling or contextual, unique to what God''s doing in you and around you.  Review your notes from the previous task and spend time in prayer asking God to reveal to you what a disciple is in your context. Here are some examples:  A disciple is someone who hears God''s voice and follows  A disciple is someone who trusts and follows Jesus  A disciple is someone who lives to obey the commands of Jesus  A disciple surrenders everything they have to obey Jesus'' call on their lives  A disciple is someone who yields the God''s spirit and produces His fruit  A disciple imitates daily the grace and generosity of Jesus  A disciple lives and loves like Jesus daily and helps others do the same', 'This action is complete when you have defined what a disciple is in your context.', 'template:  2022-11-21 updated link --sc ', 1, 'todo', 35, 14, '{}'::jsonb),
  ('7cf62948-c07c-54e1-87ba-0d2c4ec6ca83', '79aed685-16bd-5ce6-b75a-ad54e629c8f8', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Identify tools and training resources for disciple making', 'Develop a list of tools your church will have at its disposal to help produce and multiply disciples.', 'For over two thousand years Jesus'' church has been making disciples. They used many different tools to help them accomplish this mission. Before the New Testament was written church leaders develop simple creeds which helped believers understand basic truths about Jesus and share it with others. In that way they served as discipleship tools. They helped the early church make disciples who made disciples.  We see some of these creeds in the Bible (Philippians 2:6-11; 1 Corinthians 15:3-10; 1 Timothy 3:16). Notice how short these creeds were. It''s not until hundreds of years later that we get the much longer Ecumenical creeds like the Apostle''s Creed and the Nicene Creed. While these creeds are packed with theological truth and meaning, they aren''t the most effective tools when attempting to make disciples who make disciples.  Think about these disciple-making tools as resources you''ll offer believers to help them grow in their relationship with God and invite others to follow Jesus. Just as the tools of a carpenter have specific purposes for specific jobs, so too disciple making tools should be tailored to help believers based where they are on their spiritual walk.  Most likely a brand-new believer will need different tools and training resources to help them take next steps in their faith journey than someone who''s been following Jesus for years.  As you think about disciple-making tools and resources, you may find it helpful to break them into two different categories: short-term discipleship resources and long-term discipleship resources. Short-term resources should include a simple list of commands every believer should learn to obey after coming to faith.  Examples of these commands are:  Share your story  Pray  Read God''s Word  Live in community  Give and serve  Share the gospel  Once you have a short list of commands you see God''s word calling us to obey, develop simple ways to train new believers to obey them. Make sure the process is simple and reproducible, so ordinary, everyday believers can train new believers to obey these commands and the process can be passed along to multiple generations of disciples.  Long-term discipleship (or ongoing discipleship) tools and training resources will be what your church offers disciples to help them continue to grow in their faith and surrender in obedience after they''ve been trained in the short-term tools. Long-term discipleship is focused on helping disciples stay connected to Jesus for a lifetime and grow in their love for Jesus after the initial spiritual high runs dry. For more on the difference between short-term and long-term discipleship read <a href="https://www.everywhere2everywhere.org/articles/short-term-discipleship-plan">Short Term Discipleship Plan</a> by Everywhere 2 Everywhere.', 'Research discipleship tools and resources.  Consider which ones make most sense for your context and align with your vision.  If you can''t find any tools that fit your context or vision, adapt existing tools to meet your church''s needs.  This action is complete once you''ve developed a list of tools and resources your church will utilize to help you make disciple who make disciples.', 'template:  ', 2, 'todo', 35, 14, '{}'::jsonb),
  ('41b22645-c2d8-560f-84fd-72a353471b8c', '7c01a9d6-1d68-5322-ba50-d8042eed0743', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Address your personal objections to fundraising', 'Name and overcome your own personal objections to inviting others to join you financially.', 'You have assumptions and preconceived notions about fundraising. You may even have faulty theology around finances. Whatever your baggage is, own it. And prayerfully begin working on overcoming it.  Because if you don''t, your hesitation will keep you from doing the work. And your insecurity will come across clearly when you make an ''ask''. And your results will be predictably insufficient.  Common Objections  You may find yourself thinking any of these things:  I don''t like asking people for money  It feels weird asking people to pay for my salary  I don''t come from money, or don''t know people of means  The Church shouldn''t be about money  Jesus didn''t need to raise funds  Fundraising is a secular idea  I''m just not naturally good at fundraising  Money is the root of all evil (which is a misquote BTW)  I don''t want this to hurt my relationships  Fundraising is embarrassing  I can''t handle the rejection of people saying no  My extended family aren''t Christians (so no one will want to give)  These are all misconceptions, excuses, or outright lies. If you resonate with any of them, you''ve got some work to do!', 'Spend time in prayer and ask Jesus to reveal your objections and misconceptions.  Process that list with your coach and your mentor or discipler.  Write down the truths from scripture that counter each one of your objections.  Pray for grace to overcome and/or heal from any fears, insecurities or doubts you have.  This action is complete when you have begun prayerfully overcoming your personal objections to fundraising. "', 'template:  2019-12-10 date fields found empty  2019-12-11 date fields re-entered manually --pb  2020-12-16 changed Due in # Days from 181& to 167& & Duration from 142& to 128& --pb&  ', 0, 'todo', 35, 7, '{}'::jsonb),
  ('1aa8bf20-41f1-5e95-8ab8-c9c1bbc1a761', '7c01a9d6-1d68-5322-ba50-d8042eed0743', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Make a list of potential fundraising partners', 'Brainstorm a list of every possible fundraising support partner including friends, family, churches, and organizations.', 'Pursue every partnership opportunity possible. God often works through unsuspected relationships.  While brainstorming, think about every person you''ve had a positive relationship with (both past and present):  friends  family  neighbors  pre-ministry jobs  ministry connections  college buddies  etc.  Don''t forget to include your spouse''s friends, family and coworkers as well.  And really include  everybody  -  don''t say no for them  by excluding them from your list.', 'Download Passion for Planting''s  Fundraising Worksheet Template  (<a href="/resources/item/324">MS Excel</a> or <a href="/resources/item/364">Google Sheet</a>).  Use it to create an exhaustive list of potential fundraising support partners.  This action is complete when the list of potential fundraising support partners is created.', 'template: standard  2017-05-31 content & resource links updated --pb  2018-05-07 added& google& doc template version --pb  2019-12-10 content validated --pb ', 1, 'todo', 35, 7, '{}'::jsonb),
  ('0efae4c9-580b-5ef3-9c4a-5a7d69b8f54e', '7c01a9d6-1d68-5322-ba50-d8042eed0743', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop partner expectations', 'Be prepared to answer the question, "So what do you want?" when you talk to potential partners about any type of support.', 'Demonstrating preparedness and being able to call people to commit will be powerful tools in your fundraising effort.  There are different types of support that you can raise as you start the fundraising effort. For instance, someone on your list may not be able to give financially, but maybe they have an extensive network of friends, colleagues, and acquaintances that might give if he referred and endorsed the you.  You''ll have different expectations for the different types of donors:  individuals  churches  church planting networks  It will be easier for your supporter to buy in if you have provided clear expectations and open communication. Agreeing on expectations in advance gives each party something to hold the other accountable to, and it forms a strong foundation of trust.  The greater the commitment (whether in dollars or other resources), the more specific the expectations should be. For example, if a church is giving you $25,000, they may be expecting a seat on your Management Team.  Also, having clear expectations for when and how you will receive that donation is crucial for budgeting purposes. There is a huge difference between $1,000 per month for 25 months and one $25,000 check written now.', 'Write out supporter expectations, answering "who, what when, where, why and how?" Make sure you are asking the right thing from the right person or group.  Write out what supporters can expect from you. Put yourself in the shoes of the supporter and ask yourself what you would expect.  Optional: put expectations for both sides in a pamphlet or on a commitment card to be able to hand to potential supporters.  This action is complete when you have jotted down partner expectations and you''re able to explain all of them from memory.', 'template: standard  2017-05-31 content validated --pb  2018-11-02 content updated --pb  2019-11-19 content updated --pb ', 2, 'todo', 35, 7, '{}'::jsonb),
  ('794564ef-99e5-5873-8185-0481643eb487', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Establish contact with management at prospective facilities', 'Establish a point of contact with each facility you are considering.', 'Meet in person with as many different facility contacts as possible. The purpose of the meeting is to establish a relationship with the facility management and to ask about whether they might rent it to a church for worship gatherings.  The relationship with the management will be key to the success of the church for years to come. Starting on the right foot will pay dividends. Do everything in your power to make friends, not enemies.  Your secondary purpose is to scout the facility to see if it might fit your needs.  Get Contact Information  This is a great networking opportunity completely independent of whether you contract their facility or not. Consider this your first major networking goal: to meet with every potential facility contact in your area.  At a minimum, you need to get your contact''s name and a phone number. If you''re able, get an email address, too.  The Decision-Maker  Your local point of contact may or may not be the ultimate decision-making on renting the facility to you. But either way, it''s their house you''d be renting.  For example, if you''re renting a public school, you''ll initially build a relationship with the office manager or principal. It may be the district office or even school board that decides whether or not to rent to you. Even though your local contact isn''t making the decision, you want them on your side! Going over their head to force them to rent you is very dangerous.  Sometimes that local contact becomes your advocate. More than one planter has been denied by elsewhere decision-maker only to have the local contact fight for you and ultimately win over the decision-maker.', 'Call or drop by each facility to make a local point of contact.  Get their contact information and save it.  This action is complete when you have contact information for the management at your top facility prospects.', 'template: standard  2017-05-22 content updated --pb  2019-12-17 content updated --pb  2020-12-14 changed Due in # Days from 108& to 110& --pb&  ', 0, 'todo', 109, 49, '{}'::jsonb),
  ('975b0d8f-a741-59ef-acd0-99c9c644d134', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get on waiting list at each prospective location', 'Get on waiting lists to secure your interest and place in line for potential worship gathering facilities.', 'As church planting grows in popularity, so do to waiting lists for facilities best-suited for worship gatherings. Get on the waiting list at as many possible meeting locations as possible.  Don''t wait too long to get this done. You risk having to settle for your last choice or even creating a crisis right before Opening Day.  It is never too early to start looking for facilities and getting on the waiting list. In Fairfax County, VA, every middle school and high school currently has a church meeting in it (at the time of this writing). To have any chance of renting one of these facilities, you''d have to get on the list as soon as you even  think  you might want to meet there.  Send a Letter?  Some planters have landed their facility by sending an introductory letter to the decision-maker at the prospective facility (remember that your local contact may or may not be the decision-maker).  Be sure to include the following in that letter:  a gracious introduction  a mention of your previous interactions (request to rent the facility, request to be on the waiting list, etc)  basic information about the church (target Opening Day, contact information, etc)  a formal request to rent the facility', 'Contact each facility to find out its availability.  Ask to be put on any waiting lists as necessary.  This action is complete after you have checked the availability of each prospective meeting location and have been added to applicable waiting lists.  Additional Resources  <a href="/resources/item/86">Sample Facility Request Letter</a> from Passion for Planting', 'template: standard  2017-05-23 updated content & resource links --pb&  2019-12-20 content updated --pb  2020-12-14 changed Due in # Days from 120& to 122& --pb&  ', 1, 'todo', 109, 30, '{}'::jsonb),
  ('3807f339-91fa-527e-bd44-81399cb0cab7', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Tour top facilities', 'Collect important information about each potential worship gathering facility so that you can make an objective, informed decision about which one to lease.', 'After you narrow down the list of facilities to no more than the top 3, it is time to conduct a thorough tour of each facility.  Before visiting, review your  Opening Day Expectations  document. Keep in mind the target goals. Determine how many rooms will be needed for children''s ministry, etc. Also consider how many rooms you will want a year or two  after  launch. The facility should have adequate room to grow.  Download and print off Passion for Planting''s <a href="/resources/item/88">Facility Tour Checklist</a> to take with you to each facility. While on site, use it to take notes on:  What entrance will be used? Where is the entrance in relation to worship space, kids rooms and restrooms?  Are the restrooms clean and presentable?  Is there space available to store equipment?  How much furniture are in the rooms that will need to be removed and replaced each Sunday?  Is there adequate lighting for the stage or will additional lighting need to be purchased? Will the church be allowed to use existing lighting and/or sound?  Are the children''s rooms easy to secure?  Is there space for a caf&eacute;?  Is this a facility unchurched people would feel comfortable coming into?', 'Call each facility to arrange a time for a tour.  Review your  Opening Day Expectations  document.  Print and review the <a href="/resources/item/88">Facility Tour Checklist</a>  Write down any other questions to ask the facility director.  Take dozens of pictures of the facility to review later.  This action is complete when you have toured each of the top facility choices.', 'template: standard  2017-05-23 content &  Due in # of Days & updated --pb  2019-12-20 content updated --pb  2020-12-14 changed Due in # Days from 119& to 122& --pb&  ', 2, 'todo', 121, 14, '{}'::jsonb),
  ('7c77d402-040a-5ed0-b9b6-0504ab6a009e', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Narrow your list of promising worship locations', 'Boil the list of potential worship gathering locations down to the top 3 facilities to pursue more seriously.', 'After you make initial contact with the broader list of potential facilities, complete an initial assessment of each of the locations. Rule out the obvious no''s and rank the remaining facilities in order of desirability.  Based on preliminary findings, narrow the list down to no more than 3 of the most promising locations. You won''t have time, attention and resources to seriously pursue more than 3 worship gathering facilities.', 'Review the prior list of facilities and add any additional facilities you have identified.  Remove the facilities that obviously will not work.  Narrow down the remaining list to the 3 best facilities.  This action is complete when you can name the 3 most promising facility options.', 'template: standard  2019-12-20 content updated --pb  2020-12-14 changed Due in # Days from 120& to 122& --pb&  ', 3, 'todo', 121, 7, '{}'::jsonb),
  ('fe484c15-97f0-5dcf-8997-023167f9a55a', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Rank your top 3 facilities objectively', 'Use a proven method to score each of your top 3 facilities and rank them in order of which one would serve the church best.', 'By this point, there may be a clear winner on your list of facility options. Depending on your community, you may be left with only one  actual  option, so your decision is made for you.  But often it comes down to picking between 2 or 3 reasonably good options. If there''s not a clear winner, now is the time to use the <a href="/resources/item/87">Facility Selection Worksheet</a> you prepped in the previous PlanterPlan task  Read/Review Facility Selection Worksheet .  With the <a href="/resources/item/88">Facility Tour Checklists</a> you''ve completed for each facility, you''ll be able to finalize the <a href="/resources/item/87">Facility Selection Worksheet</a> to objectively determine which facility is the best choice for your church.  Follow the instructions included in the Worksheet and assign scores to each of your top facilities. The worksheet does all the math for you in a user-friendly layout! It will show you which is the better facility for your situation.', 'Consider how each of your top 3 facilities will enable the new church to reach lost people.  Finalize the <a href="/resources/item/87">Facility Selection Worksheet</a>.  Prayerfully consider the results and present the rankings to your Management Team, Coach and/or anyone who may need to be involved in the decision.  This action is complete when you have calculated which is your best facility option and which is your runner up.', 'template: standard  2017-05-22 content && resource links updated & --pb&  2019-12-20 content updated & link verified --pb  2020-12-14 changed Due in # Days from 120& to 122 & Duration from 14 to 7--pb&  ', 4, 'todo', 121, 7, '{}'::jsonb),
  ('7036c1f2-05a4-59ee-a454-ae5444992a28', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Run demographics near your top facility option', 'Make sure the area immediately surrounding the worship facility  doesn''t contradict your choice.', 'Here''s one last test before you finalize your worship facility choice: make sure the demographics confirm your choice.  First, the facility should be near where the people you''re reaching live. If they are concentrated on the west side of town, for instance, is the facility in that same area?  And if you''re reaching different socio-economic segments or different races, is the facility in a blended area that both groups feel comfortable with? Will the facility build bridges or put up barriers?  Get updated demographic information for a 3-, 5- and 7-mile radius around your top facility. Assess your top facility choice in relation to the people God is calling you to reach.', 'Obtain demographic information for the area around your top facility choice.  Review the demographics to confirm the facility is a fit for your target demographic  This action is complete when you have determined that the demographics don''t contradict your facility choice.', 'template: standard  2019-12-20 content rewritten; title changed from "Make Final Facility Decision" --pb  2020-12-14 changed Due in # Days from 127& to 129& --pb&  ', 5, 'todo', 121, 7, '{}'::jsonb),
  ('86bdcfa1-2ae2-5def-b720-b1764e736d27', '7d330165-eec8-5d0d-9423-596395a21873', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Negotiate terms for the facility', 'Work with the manager or owner of the facility to agree on the terms of the church renting the facility.', 'You''ve decided on a worship facility through prayer and due diligence. And you''ve already been communicating with at least the local management about its availability, getting a tour, etc.  Now its time to negotiate the terms. Almost everything is negotiable, from the price to the hours to what''s included.  Schools  If you''re renting from a public school, the price is probably fixed, though probably on a per-hour basis. Other things you might negotiate for are:  Access to a storage closet or other on-site storage  Setting up on Saturday night, at least at the beginning while you''re learning the setup routine  Donating and permanently installing a high-powered projector that both the church and school could use  Donating more folding chairs to the school (so there''s enough for the church to use)  Access to the school''s wi-fi  Having the custodian clean the rooms you''re renting Friday evening rather than Sunday evening  In lieu of towing a trailer every week, purchasing an ocean freight container and keeping it behind the building; it could be donated to school upon your departure for their own storage needs  Leaving your equipment set up all summer  Theaters  You may have more room to negotiate on price at a movie theater, though some are rented by a national chain that sets fixed pricing. Other things you might negotiate for are:  Access to a storage closet, unused behind-screen space or other on-site storage  Access to the theater''s wi-fi  Reduced-cost popcorn and/or soda after services  Their donating or offering reduced-cost tickets; you could give them away at events or for volunteer appreciation  Having the custodians clean your theaters late Saturday night instead of Sunday morning while you''re there trying to set up  Cordoning off the extra-wide hallway into classroom space  Using the back fire doors to load equipment in and out  Hotel  If you''re renting a hotel meeting room or banquet room, things you might negotiate for are:  How much and where you can put signage  Whether you can bring in your own coffee and snacks  Be friendly make it a win for them. And if you don''t ask, the answer is already no.', 'Arrange to meet with the decision-maker.  Negotiate the terms, everything from price to access to length of contract.  Make sure those terms get put in writing.  This action is complete when you have agreed upon written terms with the decision-maker for the facility.', 'template: standard  2017-05-23 updated content --pb  2019-05-16 additional resources subsection added --pb  2019-12-20 content validated --pb  2020-12-14 changed Due in # Days from 127& to 135& --pb&  &  2019-12-20 content updated --pb  ', 6, 'todo', 128, 7, '{}'::jsonb),
  ('a5550570-bbed-509b-8194-da695577ab0a', '848afa6b-66d8-5652-afe9-884785cd1a72', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Identify which staff positions to pursue', 'Make strategic decisions about which staff roles should be filled first.', 'The order that you fill staff positions should come straight out of your Vision Frame. Decide which positions are most strategic to hire first. List out the first 5, regardless of when they might be hired:  Does it make sense to hire a children''s director before a worship leader?  How about hiring a communications director before either of those?  Does your hiring order support or contradict your strategy, mission and values?', 'Identify positions that are essential to implementing the vision.  Note which could be full-time and which could be part-time hires.  Identify positions that could initially be filled by key volunteer leaders.  Based on all the above, rank the positions from highest to lowest priority.  Incorporate the results into your Staffing Strategy document.  This action is complete after you have identified the specific order of staff positions to pursue.', 'template: standard  2017-11-10 content validated --pb&  2019-12-20 content updated --pb  2020-12-14 changed Due in # Days from 70 to 64 --pb&  ', 0, 'todo', 63, 7, '{}'::jsonb),
  ('30f4818f-b10d-51d4-b85e-ac06236f5213', '848afa6b-66d8-5652-afe9-884785cd1a72', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set a hiring timeline', 'Set target hiring dates for each staff role.', 'Finding the right staff can take time. Set some timing goals for bringing new staff on board since it could take months to find the right people.  Consider these factors that are in tension with each other:  Hiring early allows more pre-launch tasks to be completed, more relationships to be established, and a healthier foundation for growth. In some cases, you need the staff on board early enough to prepare critical areas for the Opening Day of worship gatherings. For example, a worship leader needs several months to recruit, train and prepare a worship team for the Opening Day of worship gatherings.  However, early hiring costs more money (unless new staff will raise their own support). Money may drive the timing of staff hires.  Think in terms of both dates and trigger points. For example, you''ll hire an administrator next Spring or when we get to average attendance over 200.', 'Contact at least one other church planter and ask them when they recommend hiring for various positions.  Prayerfully consider the cost/benefit of when to hire each position.  Set target dates and trigger points for hire for each staff position.  Incorporate the results of this task into the written Staffing Strategy document.  This action is complete after you have written down a target date and trigger point for hiring each new staff position in your Staffing Strategy.', 'template: standard  2017-11-10 content updated --pb  2018-10-12 task rename from ''determine contents of compensation package'' --pb  2019-02-08 added health insurance options subsection -pb&  2019-12-20 content updated and links verified --pb  2020-12-14 changed Duration from 21& to 14& --pb&  ', 1, 'todo', 63, 7, '{}'::jsonb),
  ('be8cdb2f-a226-5cdf-b769-cd16211a7788', '848afa6b-66d8-5652-afe9-884785cd1a72', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Decide on staff fundraising expectations', 'Decide whether or not you''ll ask secondary staff to raise funds in order to come on payroll.', 'Church planters who start as paid staff almost universally have to raise funds for the church. They''re not ''raising money for their salary'', but the funds they raise do lessen the financial strain of the salary on the new church.  If you''re hiring secondary staff, will they have to raise funds, too?  Some Things to Consider  Your secondary staff may have less fundraising capacity than you:  If they haven''t been in ministry as long, they''ll have smaller relational networks  They probably won''t have as much experience in raising funds as you  If they''re the first to come to Christ in their family, they may not have as much success getting commitments from their extended family  If they grew up in an under-resourced community, the commitments they get may be smaller  If you''re hiring them part-time, they have less time to devote to fundraising than you do  They may need to raise some funds  before  they come on staff. How else will you pay for their first month''s salary? It''s wise to set a commitment goal and/or a cash-in-hand goal as a prerequisite to going the paid staff. For example, the employee can start payroll when they have 75% of your goal in commitments and the equivalent 3 months'' salary is on deposit in the church''s account.  One of the biggest decisions is what to do if their fundraising comes up short once they''re on payroll:  pay them anyway (and strain the church)?  pay them according to their results (and strain their family finances)?  something between those two?  If their pay is tied to their performance, be sure to communicate a  ceiling , too - if they raise $10,000 one month you''re not going to pay them $10,000.  Fundraising Requirement Options  Here are common fundraising requirement constructs for secondary staff. These are conceptual - you may not want to use this as the exact legal language to put in writing. Pick a construct and over-communicate it to the candidate  before they''re hired :  No requirement - secondary staff will not be required to raise funds  Full support - secondary staff raise their full salary  Half support with guarantee - staff raise the other half of their salary but are paid full salary regardless of their performance  Half support with no guarantee - staff raise the other half their salary but may get paid as little as the church''s half depending on their fundraising performance  Other...? You''ll need to be  very  specific', 'Decide whether or not to require secondary staff to raise funds.  Decide what kind of progress, if any, they''ll need to make before coming on payroll.  Decide which fundraising requirement construct (above) you''ll use.  Include your decisions in your  Staffing Strategy  document.  This action is complete when you have made decisions about staff fundraising requirements and will be able to articulate them clearly to all staff candidates.', 'template:  2018-11-12 new task --pb  2019-12-10 date fields found empty  &  2019-12-23 content updated --pb  &  2019-12-11 date fields re-entered manually --pb ', 2, 'todo', 63, 7, '{}'::jsonb),
  ('2e1c1ea7-b536-57f6-b6e9-ff635b1fff29', '848afa6b-66d8-5652-afe9-884785cd1a72', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Decide which benefits to offer', 'Decide what will and will  not  be included in compensation packages for staff.', 'Compensation  How you set appropriate pay? The amount should always be based on the responsibilities/demands of the position and the experience of the applicant. The IRS is also watching for the compensation to be no more than about what other churches of similar size or paying for those same staff positions, so do some comparison.  Here are some useful tools for comparison:  <a href="https://ministrypay.com">MinistryPay.com</a>  <a href="https://www.xpastor.org/courses/church-compensation/">Compensation Survey</a> by XPastor.com  <a href="https://www.churchsalary.com/">ChurchSalary</a> from Church Law & Tax  <a href="https://www.amazon.com/dp/0917463765/ref=cm_sw_r_tw_dp_U_x_J6w.DbPX3RC5G">Compensation Handbook for Church Staff</a> by Richard Hammar  <a href="https://compstudy.lifeway.com/homepage.do">SBC Compensation Study</a>  Keep compensation levels "fair" between positions. A great way to do that is decide in advance what the staff position pay range is, based on responsibility and expectations. Then compare the pay range of the new position with what all other current positions are being paid.  Benefits  What should be included in a benefits package? You need to decide whether to include any of the following:  Paid time off - Will the church pay vacation & sick leave, or combined PTO? Paid holidays?  Health Benefits - Will the church pay all, none, or partial benefits? Will there be a group plan or will each employee get their own individual plans? Which health benefits will be included (e.g., major medical, dental, vision)?  Housing Allowances -Ministers are allowed to designate a portion of their income as a non-taxable housing allowance. Will the church provide an actual parsonage or allow the minister to designate a housing allowance?  Life Insurance?  Disability Insurance?  Retirement benefits?  To avoid discrimination claims, don''t decide individual benefit packages with each new hire. Decide in advance on benefits packages based on employment classification. For example:  full-time, credentialed clergy get XYZ  other full-time employees get XY  part-time employees (  Health Care Insurance Options  Popular options include:  <a href="https://www.healthcare.gov/">healthcare.gov</a> (Obamacare for individuals)  <a href="https://www.churchplantingtactics.com/obamacare-for-church-plants/">SHOP</a> (Obamacare employer plans)  <a href="https://www.medishare.com/">Medishare</a>  <a href="https://samaritanministries.org/">Samaritan Ministries</a>  <a href="https://www.guidestone.org/Organization/Insurance">GuideStone</a>', 'Decide what will be included in benefits packages for each employment classification.  Determine your philosophy for setting compensation.  Incorporate these answers into your written Staffing Strategy.  This action is complete when you have recorded your church compensation package details in your Staffing Strategy document.  Additional Resources  <a href="https://www.churchplantingtactics.com/how-much-to-pay-church-plant-staff/">How Much to Pay Church Plant Staff</a> (2 part series) on churchplantingtactics.com  <a href="https://www.executivepastoronline.com/market-comparison/">Market Comparison: A Critical Part Of Any Organization''s Compensation Program</a> on executivepastoronline.com  <a href="https://www.churchplantingtactics.com/church-plant-health-insurance-options/">11 Church Plant Health Insurance Options</a> on churchplantingtactics.com  <a href="https://www.churchplantingtactics.com/2-hidden-costs-in-hiring-church-plant-staff/">2 Hidden Costs of Hiring Church Plant Staff</a> on churchplantingtactics.com  <a href="https://www.clergyfinancial.com/vacation-paid-time-off/">Is it Vacation or Paid Time Off?</a> on clergytaxnet.com  <a href="https://www.churchplantingtactics.com/paying-church-interns-by-stipend/">Paying Church Interns by Stipend</a> on churchplantingtactics.com  <a href="https://www.churchplantingtactics.com/church-plant-staff-fundraising-requirements/">How to Give Your Church Plant Staff Fundraising Requirements</a> on churchplantingtactics.com', 'template: standard  2017-06-20 resource link updated --pb  2017-11-10 content validated; changed Parent ID from 398 (Milestone: Hire Staff) to 401 (Task: Issue Written Staffing Strategy); also changed Task Type to Child --pb  2018-02-21 additional resources subsection added --pb  2020-12-14 changed Due in # Days from 77& to 70& --pb &  2019-12-20 content updated and links verified --pb  2018-06-01& gdoc& template added --pb  2018-11-15 title changed from "Define and Implement Hiring Process", content updated, demoted to child task type --pb  2020-08-28 added LinkedIn& resource --pb  2022-11-21 updated links --sc ', 3, 'todo', 70, 14, '{}'::jsonb),
  ('b0a069b1-8be0-506f-9315-ac236ff9a898', '848afa6b-66d8-5652-afe9-884785cd1a72', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a step-by-step hiring process', 'Create a disciplined and formal step-by-step process for hiring new staff.', 'You need to have a step-by-step process for hiring staff for lots of reasons:  keeps the process consistent from candidate to candidate (so you don''t get sued for discrimination)  makes you do things in the right order so you don''t sued (ex: asking for their date of birth for a background check  before  sending them a job offer letter - that''s grounds for an age discrimination suit)  helps you not accidentally skip steps that might have kept you from hiring the wrong candidate  allows you to communicate clear next steps to candidates  Brain surgeons use checklists because what they''re doing is so important they can''t afford to skip steps or do things in the wrong order. Follow their example as you hire staff for your church. You''ll have a better experience (so will the candidate) and you''ll be much less likely to make a bad hire.  We have provided a starter hiring process in the Staffing Strategy Template for you!', 'Review the process already included in the  Staffing Strategy Template  (<a href="/resources/item/67">MS Word</a> or <a href="/resources/item/377">Google Doc</a>).  Add, remove or reorder steps  with great caution .  This action is complete when you have finalized and committed to using a disciplined hiring process.', 'template: standard  2017-11-10 content validated --pb  2019-12-23 content updated --pb  2020-12-14 changed Due in # Days from 84& to 78 --pb&  ', 4, 'todo', 70, 14, '{}'::jsonb),
  ('b044df81-a102-580e-845f-830ac619ebbb', '87c1ffc5-a07e-59a6-a33f-24e90aada533', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Define what a successful content streaming launch looks like', 'Quantify what a ''win'' looks like for your content streaming launch so you can know if you''ve hit it.', '<a href="https://drive.google.com/file/d/13qAgHIG9mM-FkZmI_WLNBuhTtzK_wq-b/view?usp=sharing"> </a>', 'Watch the video above.  Paint a word picture of what a successful content streaming launch looks like.  Articulate what you''ll measure and prayerfully set a goal for each.  This task is complete when you have written out the narrative and metrics for your content streaming launch.', 'template:  2021-04-19 video content added --pb  2022-01-20 changed "digital launch" to "streaming content" language ', 0, 'todo', 104, 7, '{}'::jsonb),
  ('b5f0aa59-5b74-5c57-a775-321ccc211c01', '87c1ffc5-a07e-59a6-a33f-24e90aada533', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine your approach to reaching non-christians with streaming content', 'Choose ways and means to connect online around your streaming content that is likely to open conversations with those who don''t believe, or are even antagonistic toward church.', '<a href="https://drive.google.com/file/d/1R6pfMbjXWByF9VqOrcOg_VMUqgSIsz91/view?usp=sharing"> </a>', 'Watch the video above.  Interview multiple non-Christians in your community and/or target audience about where they connect with people online, and what would be a way they''d welcome someone starting a spiritual conversation with them.  Choose specific platforms you''ll use to reach your target audience based on where they spend time online.  Describe in writing how you''ll generally open spiritual conversations with people online (prompts, guidelines, etc).  This task is complete when you have a written, actionable approach to reaching non-Christians online.', 'template:  2022-01-20 changed "digital launch" to "streaming content" language ', 1, 'todo', 104, 7, '{}'::jsonb),
  ('3eed49fd-7926-5406-bb1a-42352c9aa7a7', '87c1ffc5-a07e-59a6-a33f-24e90aada533', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine your strategy for creating community online', 'Create an intentional plan for getting those who show up online for your streaming content into an ongoing relationship with each other.', '<a href="https://drive.google.com/file/d/1AfTBdYWT9vpVPx5HaUA1BOgV6vastPr-/view?usp=sharing"> </a>', 'Watch the video above.  Ask several people within your target audience about where they find community online, especially those that are non-Christians.  Write out the several practical steps you will take to get online participants into relationship.  This task is complete when you have written out a practicable strategy for creating community online around your streaming content.', 'template:  ', 2, 'todo', 104, 7, '{}'::jsonb),
  ('db60b290-66af-5d56-8e6a-4e6de7c2bd2e', '98be3e46-e330-55fe-b20c-c269ce5a465a', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Articulate your church''s brand promise', 'Put into words the promise your church is making for its community.', 'Your church''s brand is its promise. It''s a promise about who you are and what you have to offer your community.  Your brand is not your logo. A logo should help you communicate your brand, but it''s not the brand itself. Your brand is not even who you say you are. Your brand is what others think about the church. What people think about when they interact with your church will become your brand whether that interaction is online, in person, or through a marketing piece.  Since branding plays such a big role in what your community associates with the church it''s imperative that your church intentionally shapes its brand. That way your promise to the community accurately represents who the church is and what it values.  Now is the time to develop your brand promise. As you''re laying the foundation for the church it''s time to describe in words the brand of your church, how you want to be perceived by your community. Spend time developing language to describe the promise you''re making to your community about your church. This language should reflect your church''s vision, mission and core values.  Are you a fun church? A friendly church? A hip church? A family-oriented church? A community-focused church? A loving church? You may think, "We''re going to be all those things," but you won''t be. Plus, your brand will be stronger the more focused, unique, and distinctive it is.  Once you''ve decided what your church brand will be, you''ll then need to work to make sure your church reflects that promise. For instance, if you brand yourself as a friendly church, you''ll need to make sure your church makes newcomers feel welcome the moment they begin to interact with your church whether in person or online. If you brand yourself as a fun church, people better not struggle to stay awake during your worship gatherings. If they do, you''ll quickly become the boring church.  So what is your church''s promise to the community? What do you want them to feel and experience at your church? What do you want people to think when they visit your website and review your social media posts? Think about the answers to those questions and then put into words what you want your church to be known as and for by your community.', 'This action is complete once you''ve articulated what people in your community will be sure to experience when they check out the church.', 'template:  ', 0, 'todo', 134, 14, '{}'::jsonb),
  ('34ff554f-71f4-5baa-9385-f65486853e92', '98be3e46-e330-55fe-b20c-c269ce5a465a', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Wordsmith your messaging', 'Craft the message(s) you will use in your various marketing media with the unbeliever in mind.', 'The actual words your marketing delivers is more important than the medium itself. If you use churchy, insider language, you''re only going to reach people that already go to church (or maybe a few that stopped going).  The Unbeliever Filter  Write everything as if you were talking with someone that has zero church background. Overwhelmingly in US culture today, people don''t want to hear about church. And yet, overwhelmingly, people are open to hearing someone''s story about Jesus. How does that reality influence what you say in your marketing?  Also, you need to check your assumptions about what might be important to them in a church if they decided to check it out. It''s not "rockin worship".  Here are some phrases we suggest  not  using in your marketing:  Spirit-filled worship  Contemporary liturgy  We only use the ____ version of the Bible  We''re another church to choose from  On the other hand, it''s easy to bash the established churches in your city in an effort to differentiate yourself. "We''re awesome, and the other churches are old and sucky!" is not a Kingdom win.  Heartstrings & Misconceptions  "We''re a brand new church having a grand opening," is not particularly newsworthy or compelling these days. You need messaging that really connects with people in your community.  One way is to address felt needs in your community. Communicate that you get them and what they go through. Connect on heartstring issues like relationships, money, purpose, self-worth, anxiety, loneliness, etc.  Another way is to lovingly address common misconceptions about the Church. If people in your area think the Church just tells people what to do, your message might be, "A safe place to ask questions." If they think the Church is judgemental, your message might be, "Church for the rest of us."  Test before You Spend  Whether you''re going to spend $1,000 of a Facebook campaign or $10,000 on a direct mail campaign, wouldn''t it be great to know that your message resonates with your audience?  There''s an old marketing trick that will help you refine your message and make sure it connects with the people in your community: the A/B Split Test. Basically, you put 2 different ads out there and see which one performs better. Both Facebook and Google have this functionality built in and will provide you with the analytics to know exactly how much better the one is doing.  At the very least, ask your non-Christian friends for brutally honest feedback. Or ask people at the coffee shop for feedback. Don''t just cross your fingers and hope for the best.', 'Spend quite a bit of time in prayer about the messaging.  Craft several initial messages.  Test those messages to see which one connects better.  Finalize your messaging to include in various marketing media.  This action is complete when you have tested and finalized your marketing message.', 'template:  ', 1, 'todo', 141, 14, '{}'::jsonb),
  ('036f92ef-5ef1-5ddf-b2c6-d118d571550d', '98be3e46-e330-55fe-b20c-c269ce5a465a', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine best ways to get the word out', 'Become a student of your community to determine which forms of communication and marketing will connect with your target families.', 'Just doing  some  marketing won''t produce results. Doing the  right  marketing will.  Certain types of marketing are more effective in specific geographic areas. You need to learn which types of marketing are most effective in your local area. Quickly.  If you''re not sure, talk with neighbors and strangers to get their input on what gets their attention. Also pay attention to what local advertisers are doing, like Realtors, dentists, etc.', 'Brainstorm a bunch of different ways of getting the word out.  Ask locals about what marketing they have received that got their attention.  Observe what marketing methods local businesses use.  This action is complete when you''ve developed a brainstorm list of the marketing methods that will be the most effective in  your  community.  Additional Resources  <a href="/resources/item/167">Sample Church Plant Marketing Ideas</a> by Passion for Planting  <a href="/resources/item/97">Church Plant Guerrilla Marketing</a> by Passion for Planting  <a href="https://churchmarketingsucks.com/2007/11/lessons-in-not-sucking-cheap-marketing-ideas-for-church-planters/">Cheap Marketing Ideas for Church Planters</a> by Brad Abare', 'template: standard  2017-12-15 content updated --pb  2018-07-09 title changed from "determine marketing costs..." to "estimate marketing costs..." --pb&  2019-12-23 content updated --pb  2020-12-14 changed Due in # Days from 125& to 135& & Duration from 14& to 7& --pb&  ', 2, 'todo', 141, 14, '{}'::jsonb),
  ('fbb8df3b-56b7-5cea-9d07-4e60bbb11a6a', '98be3e46-e330-55fe-b20c-c269ce5a465a', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Estimate marketing costs and lead times', 'Do some initial research into how much time and money each of your most effective media options will take.', 'Before you can make informed decisions about your marketing methods, you need to know if you have enough time and money to pull them off.  Traditional media like direct mail, billboards and radio ads can take 60+ days from contract signing to broadcast. It just plain takes time to design, produce and deliver the goods.  Giving yourself enough time will also save your money. For example, promotional giveaway items like pens and Frisbees are generally less expensive the further out they can be ordered. If you wait until the last minute, you might still get the items on time, but you''ll pay rush fees and other versions of the ''stupid tax''.  And don''t forget: your website needs to be live before your marketing hits the streets. Publishing a website always takes longer than expected.', 'For each effective marketing method you brainstormed in the previous task, identify 1 or 2 reputable providers that will provide a quality product or service.  Enlist team members and supporters to contact each provider to find out what their time frame is for production and how much the product or service will cost. Delegate this research out as much as possible.  Compile all of the research into a quick chart or spreadsheet such as P4P''s <a href="/resources/item/391">Church Plant Marketing Plan Template</a>.  This action is complete when you have compiled all of the research.', 'template: standard  2017-03-31 updated from ''plan'' to ''strategy'' --pb  2017-12-15 content update --pb  2018-07-09 title changed from "develop marketing schedule..." to "finalize marketing schedule..." --pb  2020-01-24 content updated --pb  2020-12-14 changed Due in # Days from 126& to 151 --pb&  ', 3, 'todo', 134, 7, '{}'::jsonb),
  ('3f6c2e24-e600-5d27-b329-df09d671f0dc', '98be3e46-e330-55fe-b20c-c269ce5a465a', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop social media goals', 'Develop social media goals to discern if your time invested is effective or better invested elsewhere.', 'In crafting social media goals, you''ll need to decide:  Why are we getting involved in Social Media? What is the motive?  What does the ''win'' look like?  What is the daily or weekly time involvement expectation?  Who can help me do this?  Write down quantifiable goals and communicate them to staff and ministry leaders. Here are some suggestions:  number of posts  follower count  average post reach  number of shares or retweets  number of visitors  from  social media sites to your church website  church website bounce rate for visitors linking from social media sites  number of conversations through social media', 'Consider the questions above.  Write out your goals (monthly growth, year-end goal, etc).  Clearly communicate the goals to your team.  This action is complete when you have distributed written goals to key staff and ministry leaders.', 'template: standard  2017-11-17 content updated --pb  2018-03-21 additional resources subsection added --pb  2020-12-14 changed Due in # Days from 105& to 135& --pb&  2022-11-21 links updated --sc ', 4, 'todo', 141, 7, '{}'::jsonb),
  ('a2f6acac-0e42-58c3-b5b1-021b2d9c1d4a', '9f15a0ec-83bd-52fb-9f8f-75bacf4b46b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit a safety team leader', 'Identify and empower a qualified leader for creating, training and organizing a church safety team.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has leadership potential, experience in security/law enforcement/military and can recruit people to the team.  Your safety team leader should be more of a recruiter, trainer, people organizer and cheerleader than a skilled doer.  Consider writing out a job description and basic expectations you''d have of any safety team leader. Go over those with your candidate and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  developing a church emergency response plan  recruiting team members, especially:  current and former EMTs and firefighters  those with CPR certification  current or former medical professionals  active or former law enforcement  active or former military  current or former security professionals  finding or developing training materials  scheduling a training event  scheduling volunteers so that there are no gaping holes in the schedule', 'Spend time in prayer asking God to raise up leaders.  Develop a leader and empower them to build the team.  Communicate expectations to the leader.  Get a commitment from the leader to own the processes and leadership of the team.  This action is complete when you have recruited and trained a security team leader.', 'template:  2020-10-19 found Due in # Days & Duration fields empty,& repopulated --PB  2021-01-18 found Due in # Days & Duration fields empty, repopulated --PB ', 0, 'todo', 212, 14, '{}'::jsonb),
  ('d1acd81f-313f-55fc-9c21-e2947540b202', '9f15a0ec-83bd-52fb-9f8f-75bacf4b46b4', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Train team members on safety and response', 'Train the safety team how to reduce threats to safety every week and respond to emergencies as they arise.', 'Banks regularly train their branch employees how to respond to robberies. They also take measures to reduce the likelihood they''ll happen. But they also know that the employees have to decide ahead of time how they''re going to react, or they could make some very bad impulsive decision in the heat of a robbery.  The safety team members will require as much training as any other ministry team. The responsibilities of the role are weighty.  Find experts or experienced church security team leaders to help with the training. Do lots of research. Don''t wing it on training.', 'Find church safety training resources and materials.  Find a church safety expert or someone with experience to train you and/or train the entire team.  Schedule a time to train the team.  Conduct the training.  This action is complete when you have trained the initial safety team.', 'template:  2021-01-18 found Due in # Days & Duration fields empty, repopulated --PB ', 1, 'todo', 227, 14, '{}'::jsonb),
  ('4815e697-a3e2-5de2-8e22-ca92eeff7f7b', '9f9dece4-4454-50ae-a0ee-92fb30c8c841', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Complete hiring paperwork for staff', 'Comply with government requirements by completing paperwork for each employee hired.', 'The IRS and other government departments require certain forms to be completed for each employee on staff. These need to be completed  within 48 hours  of the employee''s first day of work .  At a minimum, complete and file the following:  IRS Form I-9  IRS Form W4 withholding election  State withholding election form (as applicable)  You may also want to get from each pastoral employee:  Housing Allowance designation request (be sure to get copies of ordination paperwork)  Medical Allowance designation request  A copy of their Exemption from Social Security approval letter if they''ve opted out', 'Go online to get most recent versions of the 3 government forms identified above.  Complete each with the new employee within 48 hours of their first day of work.  File the withholding forms in the employee''s personnel file.  File the I-9 in the common folder where all employees'' I-9s are filed.  This action is complete when you have completed and filed important government forms for each new employee.', 'template: standard  2017-11-10 content scrubbed of HTML& formatting baggage and validated --pb  2018-08-23 additional resources subsection added --pb&  2019-12-23 content updated and links verified --pb  2020-12-14 changed Due in # Days from 84& to 135& --pb ', 0, 'todo', 57, 7, '{}'::jsonb),
  ('be22b158-66d2-5449-a5fb-1be414d0d119', '9f9dece4-4454-50ae-a0ee-92fb30c8c841', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Sign up for payroll processing', 'Make sure staff get paid and all the taxes are properly withheld and filed.', 'Churches have to be very careful in setting up payroll for their employees since there are four different types of workers. Each type is processed differently. Many churches incorrectly process payroll.  Kinds of Workers  Churches can have four types of workers:  Category 1  Regular non-minister employees subject to all taxes includes FICA (social security and Medicare). Examples include church secretaries and custodians. Employees can be either hourly or salaried.  Category 2  Ministers subject to SEPA ("opted in" to self-employment taxes, the equivalent of social security and Medicare). Ministers are also eligible for a housing allowance. See definition of ministers below. Employees are typically salaried.  Category 3  Ministers exempt from SEPA ("opted out", having filed form 4361 with the IRS and received approval letter to be exempt from these taxes). Also eligible for a housing allowance. See definition of ministers below. Employees are typically salaried.  Category 4  Independent contractor receiving a 1099 tax statement (these self-employed contractors have no taxes withheld as they are responsible for filing their own taxes). Examples include graphic designers, painters, roofers, etc. In general, independent contractors are paid for a finished product. They do not actually work under the management control of the church. Rarely are ministers considered category 4 self-employed employees (not to be confused by the fact that category 2 and 3 ministers are considered by the IRS to be self-employed only for social security purposes).  Payroll Processing Options  You have several options for setting up a payroll system:  Provided by Sponsoring or Supporting Organization  One of your sponsoring or supporting organizations may be willing to process your payroll in their system. Ask around to find out.  Outsourced using an full-service payroll processor.  The advantage is that they take care of all administrative requirements including filing taxes, reporting new employees, etc. Be sure to choose a payroll processor that specializes in church payroll, such as <a href="https://www.ministryworks.com/">MinistryWorks</a>, <a href="https://simplifychurch.com/church-payroll/">Simplify Church</a>, <a href="https://www.ministryadvantage.net/payroll/">Ministry Advantage</a> or similar.  In-house using a manual process.  Your team manages payroll on the church''s computer and administers pay locally. Passion for Planting can help set up the necessary files and show you how to administer pay. Under this option, you''ll have to:  write monthly checks  make monthly federal payroll tax deposits  send monthly state payroll taxes (as applicable)  file quarterly 941 forms  issue year end W2 and W3 forms  and file year end state tax forms.  Although payroll is straightforward once it is understood, it can be a bit intimidating to learn (especially with housing allowance, social security exemptions, etc.). This option saves money but puts all the responsibility on the church.  In-house processing with outsourced administration.  There are some services (e.g. Quicken, Costco Member Services, Gusto, etc), that offer semi-automated payroll processing. You still processes the payroll locally but most of the administration of filing required taxes, etc. is automated.  It is Passion for Planting''s  strong  recommendation that church plants outsource payroll processing using one of the first two options. At the very least, a pastor should  NEVER  process his own payroll.', 'Determine which payroll method you''re going to use.  Set up your payroll processes.  This action is complete when you have processed the first payroll.', 'template: standard  2017-05-26 content updated & resource link pointed to library, though& resource itself has not yet been updated --pb  2018-08-21 tweaked title --pb  2019-01-14 updated payroll vendors --pb  2019-11-20 content updated --pb  2020-12-14 changed Duration from 21& to 14& --pb&  ', 1, 'todo', 57, 14, '{}'::jsonb),
  ('eb491b15-d368-58ae-ad0b-122e1918a59c', '9f9dece4-4454-50ae-a0ee-92fb30c8c841', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get a state employer''s withholding number', 'Establish an employer withholding account with your state.', 'A state tax withholding number is similar to a Federal Employer Identification Number (EIN). Each organization receives a unique number when they register with the state. Most states require that you register for a number. Churches are exempt in some states.  A state tax withholding number is required in many states for any legal entity whether or not they end up paying any taxes. It will be required in any state where clergy are not exempted from state income tax, or if the church hires non-pastoral staff, like an administrative assistant.  Contact your state for specific instructions on registering for a tax withholding number. Try a searching on  [name of state] employer withholding number . In most states, you can register and file online.  If you are working with a Passion for Planting Project Manager, you will be getting significant custom support on this task. If not, follow the instructions below.', 'Obtain a state tax withholding application or go to your state''s online application page.  Complete the form with all required information.  Submit the form.  Record the Tax ID number in your corporate records book (see subsequent PlanterPlan action).  This action is complete when you have filed the state tax withholding number in its corporate records.', 'template: standard  2017-05-24 content updated --pb  2019-12-11 content updated --pb  2020-12-14 changed Due in # Days from 90& to 167 --pb&  ', 2, 'todo', 57, 7, '{}'::jsonb),
  ('5f3870e2-620f-5343-adec-ab50bfb4952c', '9f9dece4-4454-50ae-a0ee-92fb30c8c841', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Obtain Workers Compensation insurance', 'Bind a workers'' comp insurance policy that covers each employee of the church in case they get hurt on the job.', 'Every employer must maintain workers'' compensation insurance. Requirements vary slightly from state to state: most states require it for every employee, some only when you have, for instance, 3 or more employees. Investigate your state''s requirements.  The workers'' compensation system has been around since the 1920s and is basically a trade-off between employers and employees. Employees are entitled to medical treatment for on-the-job injuries or illnesses and, in return, can''t sue employers over those injuries.  You get workers'' comp insurance in one of 2 ways depending on your state:  The state itself is the insurer (OH, ND, WA & WY)  Buy your own insurance (all other states)  For those other 46 states, we recommend shopping your own church insurance provider first. They''ve already written, or will soon write, your liability insurance policy (see PlanterPlan task  Obtain church insurance policy ). It keeps things simple if it''s all in one place.  You can also get workers'' comp insurance from independent agencies and carriers in your state. Try searching on  [name of state] workers comp .', 'Determine if your church is required to carry workers'' comp insurance.  Determine where to purchase the insurance in your state.  Shop two different providers, if available, to compare pricing.  Purchase the insurance.  File the policy in the Corporate Records Binder.  This action is complete when a workers'' compensation insurance policy has been bound and filed in the official corporate records.', 'template: standard  2017-05-25 content updated --pb  2019-12-11 content updated --pb  2020-12-14 changed Due in # Days from 189& to 167& & Duration from 45& to 14& --pb&  2022-11-21 updated links --sc ', 3, 'todo', 57, 7, '{}'::jsonb),
  ('98175d3b-76f3-5a6f-a61e-74313c076df6', 'a5b1d911-2097-5151-b1d4-a419471464eb', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Send initial letter to potential partners', 'Let the people in your life know what God has been up to, what He is calling you to, and ask them to partner with you in this new endeavor.', 'No one wants to be called out of the blue and be asked for money. Open the lines of communication with each of your potential supporters by sending out an engaging letter that tells the story of the plant, casts the vision, and invites them to participate.  The "letter" in this case could be an actual printed letter (old school still works), a direct message on social media, etc.  The goal of the letter should be to set up a phone call, whose goal should be to set up an in-person meeting.  "The biggest checks come from the smallest rooms."  - Phil Ling of <a href="https://thegivingchurch.com">thegivingchurch.com</a>  Print Letter Considerations  Things to be sure to include in or with a printed letter:  A picture of your family and the church logo (if it has already been designed)  The church''s tag line (if it has been developed)  Your phone number, mailing address, and email address so that they can contact you  The expectation that you''ll be following up with them  Passion for Planting has collected <a href="https://church-planting.net/pp_addendums/Fundraising%20Letters.htm">Sample Letters</a> for you to review.  Here are some production & design ideas to consider:  Save the commitment card for after you''ve spoken with them over the phone or in person. You''ll get a much higher commitment rate than the old ''spray and pray'' method.  Keep it to the front of one page. If you absolutely have too much to say, use legal size paper, but constrain yourself to one side.  Use a design template in whatever publishing software you are using. Don''t try to reinvent the wheel; just pick a style that reflects you and/or your plant.  Print in color. It really does make a difference.  Use the mail merge feature of the publishing software you are using to personalize the greeting line of each letter with the recipient''s name.  You can also use mail merge to print right onto the envelopes (preferable), or onto address labels that you can affix to the envelopes (acceptable).  If you don''t want to fold the letters by hand, use a folding machine at a local church or business services store.', 'Draft the support letter or direct message.  Have at least two other people read it for errors and feedback.  Print the letter or send the direct message.  Further for snail mail:  Address the envelopes.  Fold the letters and insert into each outgoing envelope.  Affix proper postage and drop them to the postal service.  This action is complete when you have sent out the first several letters.', 'template: standard  2017-05-31 content updated --pb  2019-12-11 content updated --pb ', 0, 'todo', 63, 14, '{}'::jsonb),
  ('2b6794cf-36c8-58e5-9c0e-445c554a9fc8', 'a5b1d911-2097-5151-b1d4-a419471464eb', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Schedule meetings with potential partners', 'Honor high-capacity donors by meeting with them in person and building your relationship.', 'Financial supporters give when they are excited about a vision and the chance to participate in what God is doing. For many, it is part of their Kingdom ministry and a great joy to provide financially for God''s work.  Meet with people from your potential support partner list that you know have the means to participate financially. Don''t go to them asking for money, but casting your vision and inviting them to join you in this Kingdom effort.  Get Someone Else to Make Your Calls  Seriously. The point of the call is to book a face-to-face meeting. If you make the call yourself, they may tell you, "Just tell me what this is all about." If your spouse, friend or family member calls to book the appointment, you won''t step on this landmine.  If at all possible, have someone else make the calls and schedule your meetings. Don''t forget that your helper will need to have access to your calendar.', 'Call each high-capacity individual or group very shortly after you know they will have received your initial contact.  Schedule an in-person meeting to tell your story and cast the vision God is calling you to.  Put each meeting on the calendar immediately to avoid schedule conflicts and the embarrassment of having to reschedule.  Make travel arrangements well in advance of the trip to get the best airfares, etc...  Show up for the meeting and cast your vision. Remember that money follows vision and relationship, not need.  This action is complete when you have scheduled face-to-face meetings with the high-capacity supporters on your contact list.', 'template: standard  2017-05-31 content validated --pb  2019-11-19 content updated --pb ', 1, 'todo', 70, 14, '{}'::jsonb),
  ('0f291add-c550-5c7a-a78a-076557385882', 'a7440d52-27fb-5791-a9a8-04d6792e46a5', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop your leadership pathway', 'Create a leadership farm system to identify and grow leaders in your church.', 'In healthy churches, reproduction happens at every level of the church, from ministry roles to groups to campuses and congregations. Reproduction does not happen by accident, nor does reproduction happen in isolation from other Christians.  A culture of reproduction is difficult to produce. So why bother?  Many churches are plagued by a chronic shortage of leaders. This problem contributes to burnout for staff and volunteer leaders, and it stagnates growth.  It is also a stewardship issue: if every time a new volunteer takes over a ministry position and has to figure things out from scratch, then tons of time is wasted that could have been focused on growing the ministry. If we truly believe that God has gifted each and every Christian, then it is our responsibility to equip those Christians for works of service (Ephesians 4:12).  A Simple Pathway  You need to outline the levels or progression of leadership. Someone doesn''t go from apprentice to lead pastor in one easy step. What are those levels or stages that they can grow through to stretch and grow their leadership?  Spell out what expectations are for each level of leadership. More is expected and required of leaders the further down the pathway they grow.  A Simple Process  Dave Ferguson of <a href="https://www.communitychristian.org">Community Christian Church</a> suggests this simple process for growing new leaders:  I do. You watch. We talk.  I do. You help. We talk.  You do. I help. We talk.  You do. I watch. We talk.  You do. Someone else watches.  By following this simple method at all levels of leadership in the church, you create a leadership pipeline. The next generation of leaders is always being trained up and released for works of service.  It is important to set this expectation as value for the church. Expect each person to serve. Teach this on Sunday mornings, communicate it in membership classes, discuss it in small groups. If you have a volunteer leader in a certain role, the first step for them is to recruit an apprentice whom they are relationally investing in. The role could be anything from the lead pastor to a setup team member to a children''s ministry volunteer.', 'Create a simple leadership pathway and include that in your  Leadership Multiplication Strategy  document.  Define expectations for each level of leadership.  Determine an apprenticeship policy. Adapt or adopt the process outlined above.  This action is complete when you have written down the basics of your leadership pipeline.', 'template: standard  2017-11-13 content validated --pb  2019-12-05 content updated --pb  2020-12-11 changed Due in # Days from 168& to 62 --pb&  ', 0, 'todo', 61, 14, '{}'::jsonb),
  ('b551529a-f454-5604-9265-ac8195afca1f', 'a7440d52-27fb-5791-a9a8-04d6792e46a5', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create a leadership development map', 'Set expectations for how your leaders will be trained, discipled and coached.', 'A leadership development map is a simple tool to get leaders and apprentices on the same page. It shows leaders what they need to instill in their apprentices and sets expectations for what the apprentice needs to be working on.  Components  The map needs to include the 3-4 things you do to develop leaders. These are the elements of your leadership meetings, training events, and the skills you''ll drill your leaders-in-training on.  For example, your 3 might be  Prepare, Equip, Inspire . Or  Head, Hands, Heart . Or  Vision, Huddle, Skill .  Approaches  For each of those components, decide on the things you''ll do to help people make progress.  In our example, will  Prepare  training be formal classes? On the job apprenticing? Required reading? Some combination thereof?  Some ideas are:  Monthly leadership huddles  One-on-one coaching  Group emails and other forms of written communication  Leadership retreats  Supervised training or apprenticeships  Reading through a book together  Self-study materials and curriculum  Resources  What is the specific content, curriculum and/or events you''ll use for each approach?  Some ideas are:  Books that have been foundational in your own leadership growth  Leadership blogs and eNewsletters  Church or business leadership podcasts  Conferences and seminars  For any of these, be sure to name the  specific  book, podcast, conference, etc. that you''ll use.', 'Name your leadership development map components. Run your list through the 5 C''s test.  Decide which approaches you''ll use for each component.  Decide which  specific  resources you use for each of the approaches.  Include all of the above in the leadership development map table in your  Leadership Multiplication Strategy  document.  This action is complete when you have charted out your leadership development map.', 'template: standard  2017-11-13 content validated --pb  2020-12-11 changed Due in # Days from 168& to 69 --pb&  ', 1, 'todo', 61, 14, '{}'::jsonb),
  ('9cc26ab9-f2ff-550f-85bc-239afbd60b65', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine audience and goals of website', 'Create a filter to guide all of your decisions about your website''s style, tone, lingo, pages names, etc...', 'Your website is for people who aren''t already connected to your church. It''s all too easy to lose focus on that as you build it. If you''re not intentional, you''ll slip into writing for your own people, or some other audience.  And even more specifically, write intentionally for your Average Target Family (see PlanterPlan task  Define Average Target Family ). The site content must flow from who the audience is. It shouldn''t contain any  christianese  terms. The home page and main tabs should be centered around how to get there, what to expect and who the church is. The beliefs page shouldst not contain the Nicene Creed in King James English.  Ruthlessly review each page and the features you''ve chosen through the lens of, "Does this make sense and is it helpful to people who''ve never been to our church?"  But do consider how you''ll communicated with your insiders. What other tool would work best for serving people who are already connected?:  a custom mobile app  a church management software with login  a social media page or group  If you want to build a website that truly reaches those disinterested in church, you''ll have to radically move away from the norm of church websites.', 'Determine who your target audience is for the website.  Don''t settle on a pre-determined template with pages based on churchy terms, structured around a church worldview.  Put yourself in the shoes of your target audience and try to identify the questions and apprehensions they might have about coming to a new church like yours. Address those issues directly.  This action is complete when the website content has been carefully crafted based on the target audience.', 'template: standard  2017-11-15 content updated --pb  2019-12-09 content validated --pb  2020-12-14 changed Due in # Days from 105& to 88& --pb&  ', 0, 'todo', 80, 7, '{}'::jsonb),
  ('4f4dcca6-3e48-5696-a72b-22262c3b4c8f', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Pick a website builder', 'Choose the app you''ll use to build your website.', 'Websites can be built several different ways:  built and coded from scratch (almost no planter should choose this option)  fully custom design built using a website builder like Wordpress or SquareSpace ($$$)  semi-custom design by modifying a template on Wordpress, SquareSpace, etc ($$)  DIY using a website builder ($)  Here''s why you need to hire a designer, even if you have web design experience: the more time you spend on designing the new website, the less time you have with people.  Hire a designer that can do 3 things for you:  design a good looking site  build in the functionality you need (online giving, calendar sync, social media buttons, etc.)  help with the initial SEO (getting found by search engines - see subsequent PlanterPlan task) - a pretty site that can''t be found isn''t super helpful  Designers are stereotypically overworked and unavailable when you need them most; find a designer with a reputation for good communication and on-time delivery.  WARNING  Before you ask your friend or relative to build your site for free, read  <a href="https://www.churchplantingtactics.com/church-plant-website-by-buddy/">Don''t Let Your Buddy Do Your Church Plant Website</a>  [ChurchPlantingTactics.com].', 'Ask for designer recommendations from colleagues.  Review their work. Past performance is the best indicator of future results.  Interview your short list of top picks.  Consider the cost of their services versus their experience and talent.  Enter contract with the best designer.  This task is complete when you have entered contract with a web designer.', 'template: standard  2017-11-15 content update --pb  2019-12-09 content validated --pb  2020-04-15 new template download added --pb  2020-12-14 changed Due in # Days from 126& to 95& & Duration from 7 to 21& --pb&  ', 1, 'todo', 87, 14, '{}'::jsonb),
  ('3f4f1968-8b11-523f-a92e-0201d0f53dc3', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Write your website content', 'Do the hard work of composing content for each page of your website.', 'We strongly recommend writing the content  outside of your website builder  so you don''t get sucked in and distracted by other tools and functions.  But even before you begin writing, decide on your menu structure and page names. Keep your audience firmly in mind.  Now start writing the actual content for the site. It should flow right out of your work on your Vision Frame and demographics (see previous PlanterPlan Milestones). Again, all of the content should be written through the lens of your target audience. Always avoid churchy language.  WARNING  When church plants miss website launch deadlines, our overwhelming experience is that it''s because the planter hasn''t written the content. It''s almost never a matter of waiting on the designer to finish building the site.  So set aside a realistic amount of time and discipline yourself to get it done on schedule.', 'Download Passion for Planting''s <a href="/resources/item/393">Website Structure and Content Worksheet</a>.  Draft your site map (menu and page structure).  Draft content for each page.  Keep it short - paragraphs should be no longer than 3 or 4 sentences.  Go back and read your content through the eyes of your Average Target Family.  Have at least 2 other people read it for typos and errors before it is published.  This action is complete once you''ve written the content and has had it reviewed by at least 2 other people prior to being published.', 'template: standard  2015-11-15 content updated --pb  2019-12-09 content validated --pb  2020-12-14 changed Due in # Days from 135& to 120& & Duration from 7 to 46& --pb&  ', 2, 'todo', 94, 21, '{}'::jsonb),
  ('25cff542-141a-5776-b849-8ab11919a556', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set up a church calendar', 'Choose which calendar software to use to compile and keep track of every important date and event for the new church.', 'Whether or not you''ll be a program-driven church, there are things that happen in the life of your church each year. Keeping them all straight is important. Sub-calendars are key.  If you will be using your church management software (the church database) for the master church calendar, you''ll probably accomplish creating church sub-calendars by using different admin groups.  If you use a Google calendar, simply click the drop-down arrow next to  My calendars  in the left-hand column and choose  create new calendar  for each sub-calendar.  Other calendar systems typically have similar functionality.  Church sub-calendars are a great way to keep everything organized at your church. Setting them up is relatively easy and it solves the following 3 problems.  1. Too Much Information  The main reason for creating church sub-calendars is to ''control'' who sees what. A church admin or senior leader needs to see everything, but that can be totally overwhelming for someone checking out the website.  Or seeing everything could be totally inappropriate &ndash; the date & time of the next staff performance review for your worship leader isn''t really everybody''s business.  Create sub-calendars so that every church event rolls up into one master church calendar.  2. Double-Booking  Once your church is up and running, it''s crazy how many times different teams will book events at the exact same time. It''s tough for a guitar-playing dad to be at band practice and the youth group parent meeting at the same time.  This becomes even more important for churches that have a 24/7 facility and have to manage who''s using which room which night.  3. Over-Booking  Maybe you think you haven''t created an event-driven church. But once you overlay all the church sub-calendars above, what does that tell you about how busy you''re asking people to be? Setting a reasonable pace for your leaders and your congregation is easier if you have the raw data in front of you.  Possible Sub-Calendars  Here is a list of sub-calendars you may want to create now or add later:  Prayer Team:  prayer events; reminders to send updates  Fundraising:  appointments; desserts or other events; reminders to send thank yous, etc  Finances & Governance:  annual budget preparation season; quarterly and annual Board meetings; annual report filing deadlines  Discipleship/Small Groups:  dates & times of small group meetings; leader training events  Networking:  appointments with civic leaders; reminders to follow up  Community Service:  events; planning meetings  Marketing & Outreach:  events/festivals; design & publication deadlines; online campaign run dates; etc  Staffing:  performance reviews; job interview dates  Leadership & Training:  retreats; leadership meetings; conferences  Communications (Internal):  newsletters; social media posts; serving schedule publication dates  Preaching & Creative Team:  sermon calendar; production deadlines; planning meetings  Assimilation & Membership:  discovery classes; membership classes; etc', 'Set up online calendar(s) and share with Management Team members, coach, staff and key leaders.  Consider how it will interplay with your eventual church website (no one wants to enter every event twice).  Add key dates to the calendar.  This action is complete when you have set up the online calendar.', 'template: standard  2017-09-26 content overhauled --pb&  2020-01-24 content updated --pb  2020-12-14 changed Due in # Days from 56& to 102& & Duration from 14& to 7& --pb&  ', 3, 'todo', 101, 7, '{}'::jsonb),
  ('67df98fb-bf6e-5c2a-9176-15e808163c23', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit a volunteer webmaster', 'Empower a website champion to ensure that your church website is up-to-date and functioning properly at all times.', 'How often have you seen things like this on a church website: in March someone goes to the website to check out your church and the home page says, "Come to our special Christmas Eve service!"  What does that communicate to the potential guest?  Your church website needs to be updated at least weekly, if not several times a week:  post new events  pull down past events  post to the blog  moderate blog comments  post the sermon podcast or recording  update software: themes, plugins, security patches, etc.  etc.  Content is King  The added benefit of all the useful content is that your site will get ranked higher on search engine results. Which should result in more visibility and more web traffic.  Your site will actually be penalized as irrelevant by search engines if it''s been months since any fresh content was posted.  Plus the top 3 organic results in a Google search get clicked about 20 to 1 over the ads; you want that coveted position!', 'Find someone who is tech-friendly and detail-oriented. Initially, it doesn''t even have to be someone on the Launch Team, though that is preferable.  Recruit that person to be the church''s webmaster.  Empower that person with access to the administrative side of the site and with contact information to all of the ministry leaders. The webmaster needs to be in the know on everything that is happening in the church.  Maintain a close, healthy relationship with the webmaster through frequent communication.  This action is complete when the new Webmaster has been granted administrative access to the website.', 'template: standard  2017-11-14 content seriously overhauled --pb  2019-12-09 content updated & links verified --pb  2020-12-14 changed Due in # Days from 126& to 120& --pb&  2024-02-16 added link, removed old link --pb ', 4, 'todo', 104, 21, '{}'::jsonb),
  ('e54105c7-76bf-555d-8c44-93101e81e097', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Shoot a welcome video for website', 'Create a video for your website aimed at welcoming people who are checking out the church online.', '[content pending]', NULL, 'template:  ', 5, 'todo', 101, 21, '{}'::jsonb),
  ('61202f0d-0b0c-5ea3-b5b1-2371a413a49e', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set up website privacy policy and cookie disclosure', 'Honor your website visitors and the law by creating proper disclosures about data collection, privacy and use of cookies.', '[content pending]', NULL, 'template:  ', 6, 'todo', 119, 7, '{}'::jsonb),
  ('61f6dd37-8d08-5d05-a2fd-c2a09d7ee7c6', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set up website analytics', 'Get information that will help you refine and improve your website.', 'Website analytics reveal all kinds of things about your website:  how many users visited your site  how many pages they viewed  which pages were most popular  which city they''re in  which search phrase they used to find your site  which website they clicked through to yours from  etc.  Armed with this information, you can improve your site so that it performs better.  Google Analytics is the gold standard and provides the most insight. DIY website builders like SquareSpace, Wix & Weebly have a simplified version built in to their platform, but may also allow you to install Google Analytics.', 'Determine if your website platform has analytics built in.  Whether it does or not, consider installing Google Analytics for the richest insight.  Consider creating an automated weekly or monthly report to stay informed.  This action is complete when you can see website analytics data collected from users of your site.', 'template:  ', 7, 'todo', 119, 7, '{}'::jsonb),
  ('9f82ffc3-b37a-5089-b16c-a1b18321e0df', 'ab8301bc-6bcf-5063-84e5-7d3105209622', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Optimize church website to get found by search engines', 'Commission a trusted volunteer to get the church website to show up on the first page of online search results.', 'When somebody is searching online, if your church doesn''t show up on the first page of search results, you don''t exist.  Search Engine Optimization (SEO) is the half-art, half-science of getting on the first page. Google is the leader in this space, but it''s an ever-changing beast. About the time you figure some stuff out, <a href="https://blog.hubspot.com/marketing/google-algorithm-visual-history-infographic">Google changes their algorithm</a> and previous tactics have diminishing returns.  By and large, SEO tactics don''t cost you anything but time. But it requires ongoing vigilance and content creation, which a lead pastor doesn''t have time for. Find someone on your team or within your network of supporters that can learn about SEO, make the necessary changes, and keep stuff up-to-date.  A great starting place is to have them search online for <a href="https://www.google.com/search?q=church+website+SEO"> Church Website  SEO </a>. Set search results to show only articles from the last 12 months and read up on the latest and greatest.  Here''s a summary from articles we found in 2017 (effectiveness of these tactics subject to change without notice):  Pick a responsive design (the site resizes to any screen size, especially mobile)  Create useful content and publish new content regularly  Compress media (don''t use 10MB image files!)  Host videos on Youtube and embed them in your site  Include keyword phrases (reverse engineer what phrase people will search on where you want to show up on page 1)  Include metadata on every page  Put your church name, address & phone number on every page  Embed a Google map on your contact page  Submit your website to search engines (let them know you exist!)  Create church pages on the major social media sites & try to get the same username across platforms  Claim your local listings (see subsequent PlanterPlan task)  Get launch team members to submit non-fluff reviews on those listings and on social media sites  Use tools to analyze your progress and show you where to nip & tuck (read <a href="https://blog.hubspot.com/marketing/seo-analysis-tools">14 of the Best SEO Tools for Auditing & Monitoring Your Website in 2019</a>)', 'Recruit someone you trust to champion getting your church website onto the first page of search results.  Have them read several recently-published articles on church website SEO.  Empower them with access to your website builder tool and the church''s social media pages.  This action is complete once your champion has been empowered to make the necessary changes.', 'template: standard  2017-11-16 content & hyperlinks overhauled --pb  2019-12-09 content updated & links validated --pb  2020-12-14 changed Due in # Days from 142& to 166& & Duration from 7 to 14& --pb&  ', 8, 'todo', 119, 14, '{}'::jsonb),
  ('a9605156-f9ce-54cc-8f39-2665ebe12e18', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Talk to your spouse about their role', 'Decide how much or how little your spouse will work on during the planting process so that they are not overlooked or overworked.', 'Your spouse is a partner in ministry. Spouses play a critical role in the new church, and their gifts and passions should always be considered. What do they want to do? Invite them into that area of ministry. But also don''t overwork them to the point of breaking.  Also, be very hesitant to make your spouse fill in on a ministry team that doesn''t line up with their passion. They may be able to fill the role credibly in the short term, but burnout is all but inevitable.  Maybe your spouse will lead a particular ministry team. Or they may take point on items in the launch plan but delegate the work to other team members. Maybe their best fit is serving on a team that someone else is leading.  Whatever the case, don''t assume anything about your spouse''s involvement. Clear communication regarding expectations will alleviate great amounts of marital stress.', 'Invite your spouse to the PlanterPlan project (use  project > manage team ).  Review the PlanterPlan task list with your spouse to determine which actions they''ll be responsible for.  Assign those tasks to them using the  Lead  dropdown on each task (their initials will be listed).  This action is complete when you and your spouse have reviewed the PlanterPlan task list and determined which actions the spouse will take charge of.', 'template: standard  2017-06-12 content & resource link updated --pb&  2019-12-23 content updated --pb  2020-12-14 changed Due in # Days from 56& to 64 --pb&  ', 0, 'todo', 63, 7, '{}'::jsonb),
  ('048bbe92-4eac-5e1c-b03e-abe39723f8fe', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set Launch Team expectations', 'Have a clear picture of what you''re inviting people  to  when you ask them to join the Launch Team.', 'People need to know exactly what you''re asking of them and exactly what they''re committing to.  Chances are good you''ve been part of a team that didn''t have clear expectations or a common goal. How did that work out?  Creating community, common culture and team commitment includes setting clear expectations on the front end.  What you don''t want is a 4-page list of expectations that no Pharisee could ever live out. Or a 10-page software license agreement that no one ever reads. Keep it simple &mdash; no more than 3 to 5 points. The list should be catalytic and inspiring, not oppressive and demanding. Most importantly, it should be memorable because you''ll want your team members to recruit forward.  The expectations you list should be a version of the  Strategies  from your  Vision Frame  (see previous PlanterPlan task). What the church does after the launch of worship gatherings should not be terribly different from what you''re asking them to do prior to Launch.  Keep the expectations realistic. Are you asking them to commit so much time to serving on the team that they won''t have time left to build relationships with friends, neighbors and co-workers? Is the bar set so high that only full-time, vocational pastors could live up to them? Speaking of that, do you already live up to the expectations?  Think through how lost people might respond; you want them on your team. Do you have the same expectations of them? Will they be second-class citizens?  Develop the list in some kind of written form. Consider including your mission statement somewhere on that page. And consider whether or not to include a time aspect, like committing to 6 months, 12 months, etc.  In a subsequent task, you''ll decide whether people should sign the commitment/covenant or not. For now, simply craft the list of expectations.', 'Review the <a href="/resources/item/148">Sample Launch Team Expectations</a>  but don''t copy them .  Ask around and review copies of what other planters have used.  Develop your own short list of expectations.  This action is complete when you have finalized a written list of expectations for launch team members.', 'template: standard  2017-06-09 changed ''plan'' to ''strategy'' --pb  2017-06-12 updated content --pb  & 2020-12-14 changed Due in # Days from 56& to 64 --pb&  2019-12-23 content updated --pb  ', 1, 'todo', 63, 7, '{}'::jsonb),
  ('945484fe-9f1d-5dc2-bba2-72a53fa72165', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Decide how people will sign up to join the Launch Team', 'Determine how you''ll invite people to join the Launch Team and how you''ll direct them to respond.', 'Have you ever been part of a team and not known it?  We didn''t think so.  The process for accepting people into the Launch Team does not need to be complex. It should involve an opportunity for the planter to share the vision either one-on-one or in a group. And it needs to include some kind of opportunity for them to respond.  The response generally falls into one of three broad categories. Choose the one that is the most meaningful to people in your target area:  Verbal  - they respond to the invitation verbally, which may or may not be followed by a handshake, etc  Symbolic  - they respond to the invitation by signing their name to a poster, adding their puzzle piece with their name on it, or other symbol of the team  Covenantal  - they respond to the invitation by  signing  the expectations document (aka agreement, contract, covenant)  Think through whether the process will make it relatively easy or difficult for unchurched people to join the Launch Team.  A Positive "No"  Equally as important is the process for gently rejecting people who express interest but should not join the team. Most planters experience some version of unhealthy or downright toxic believers wanting to join the team, usually to drive a personal agenda.  The vision God has entrusted to you is not for sale. How will you let the toxic believer know that they aren''t welcome to join the team?', 'Write a short paragraph that describes how you will make the invitation to join the Launch Team.  Determine how you will direct people to officially sign up to join the team.  Include these in the Launch Team Development Strategy document.  This action is complete when you have decided on a process for people to sign up to join the Launch Team.', 'template: standard  2017-06-09 changed ''plan'' to ''strategy'' --pb  2017-06-14 updated content and hyperlinked book --pb  &  2019-12-23 content updated --pb  ', 2, 'todo', 63, 7, '{}'::jsonb),
  ('85168551-285f-591e-90e7-df817112c0c6', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine What Type of Informational Meetings to Have', 'Decide how to leverage vision casting in group settings to build the launch team faster.', 'You won''t be able to connect with enough people 1-on-1 to build a big enough Launch Team.  Just do the math: what if you could get 1 yes out of every 4 invitations? You''d need to have 200 one-on-one meetings to get the Launch Team to 50. At some point, you need to leverage group settings.  You''ll encourage your early team members to invite their friends and family to Launch Team meetings, which will help. And yet there will be people in your community who might very well join the team, but don''t know anyone already on the team. How will they get invited?  Some planters have rented a meeting room or facility and hosted a Vision Night. People are invited to hear about the new church and dream about what it might look like. There is a formal pitch to join the Launch Team that night before they leave.  In Ralph Moore''s book,  <a href="https://www.amazon.com/Starting-New-Church-Ralph-Moore/dp/0801018099/">Starting a New Church</a> , he talks about how when starting a new church, they would take an ad out in the local newspaper. The ad invited anyone who would be interested in being a part of a new church to come meet at a local restaurant. Ralph Moore says that often several initial Launch Team members will be recruited from those meetings.  Others have held cookouts our put on a movie night in the park and invited the community to come hear about the new church and enjoy the entertainment. These types of events are easy for existing Launch Team members to invite friends to as well. Just be careful not to bait and switch.  Regardless of your particular strategy or what you call it, look for opportunities to use group settings to get the word out about the new church and to build the Launch Team.', 'Brainstorm a list of ideas for holding Vision Nights or Info Meetings.  Determine which of those to put on and assign a date and cost to each meeting.  Add the meetings to your calendar and costs to your budget.  This action is complete when you have determined what types of meetings to hold and added them to the Launch Team Development Strategy document.', 'template: standard  2017-06-09 changed ''plan'' to ''strategy'' --pb  2017-06-14 content validated --pb  2019-12-23 content updated --pb  & 2020-12-14 changed Due in # Days from 56& to 64 --pb&  ', 3, 'todo', 63, 7, '{}'::jsonb),
  ('c5a04661-7559-580d-a709-18f84afbfa90', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Plan out what to do at Launch Team meetings', 'Develop a strategy for using meetings to build and train the Launch Team.', 'Once you have recruited the initial Launch Team members, you need to figure out how to train, teach and equip them. Launch team meetings are a natural forum for getting that done. Launch team meetings can serve one or more the following purposes:  Expanding the Launch Team  Invitation should be a primary focus of all Launch Team members. Everyone on the team has the job of recruiting people from their spheres of influence. You''ll have to consistently remind the Launch Team of this goal. You''ll want to include a welcome and basic overview info at Launch Team meetings; consider adding an invitation to join the team, too.  Fostering Fellowship  It is important for the Launch Team members to get to know each other. They should have opportunities to fellowship and develop friendships around the common cause of launching the church. Fellowship is a part of any gathering. But sometimes, it is good to plan an event solely for the purpose of fellowship. For example, have the launch team over to watch a big football game together.  Casting Vision  God has entrusted you with a vision for the new church. You have already cast that vision with launch team members individually. However, vision is leaky. You must continually cast the vision for what the new church is going to be like. Many planters rely heavily on oral presentations to communicate vision. Sometimes, though, the best way to make vision stick is by living it together. For example, if serving the community is a part of the desired DNA, rather than talking about it, schedule a gathering where the launch team actually serves the community.  Training  There are several jobs for the launch team to do in order to hold worship gatherings and accomplish the ministries of the church. Launch Team members have to be trained for each ministry and task that needs to be done. For example, choose to plan a Launch Team meeting to train the launch team on setting up the portable equipment.  Maybe you''ll create a rhythm that you follow at every Launch Team meeting, like  Head, Hands & Heart . Maybe you''ll structure it with large group time and then have the teams break off for team vision and training. Whatever it is, be intentional.  Don''t Default to Bible Study  Bible study and church groups are important. But the launch season won''t come around again, so make Launch Team meetings be different. Certainly, include some scripture. But Launch Team meetings should be about vision, some housekeeping, and a lot of conspiring to invade the community.', 'Brainstorm a list of ideas for Launch Team meetings in each area above.  Decide how to structure your meetings and/or vary them.  Assign a date and cost for each gathering and add it to the calendar & budget.  Include them in the Launch Team Development Strategy document.  This action is complete when you have determined what type of launch team meetings to have.', 'template: standard  2017-06-09 changed ''plan'' to ''strategy'' --pb  2016-06-14 content & hyperlink validated --pb&  2019-12-23 content updated and link verified --pb  2020-12-14 changed Due in # Days from 56& to 64 --pb ', 4, 'todo', 63, 7, '{}'::jsonb),
  ('3224eb6e-0a3c-5998-8fc4-56dd9678e56e', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set calendar date for initial Launch Team meeting', 'Commit to a specific date for the very first Launch Team meeting so you can make plans and work out details.', 'Every team needs time together. Your Launch Team is one of your best assets, but only if they''re actually a team.  You''ve already decided  what  to do at the Launch Team meetings. Now you just need to get the first one on the calendar.  Hold the first Launch Team meeting at least 6 months before the launch of worship gatherings.  Get in the routine of meeting on a regular basis: Passion for Planting recommends weekly leading up to the Opening Day of worship gatherings. In no case should it be less than once a month - vision leaks and there''s just too much to do!', 'Decide the schedule for ongoing gatherings.  Secure a location.  Set the date for the first meeting.  Invite all the team members.  This action is complete when you have scheduled the first Launch Team meeting.', 'template: standard  2017-06-14 content validated and resource link updated --pb ', 5, 'todo', 63, 7, '{}'::jsonb),
  ('46394ccb-2368-5a2b-8a70-8cbfc815defe', 'ad46e53b-f141-5ebe-b1b7-5bf232cfe04c', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Pick training materials for the Launch Team', 'Identify books, resources and tools you''ll use to increase your Launch Team''s capacity.', 'One way to create community, culture, and common language is to lead your team through some kind of training material or church campaign together. There is no need to reinvent the wheel.  You may want to plan a half-day or all-day training event. Maybe you''ll want to include the training as a regular segment of your Launch Team meetings each week.  Some planters have their Launch Team read a book together, one that ignites their imagination and inspires them to get on mission. Consider using the book that was foundational to you in your decision to plant the church. That will help people''s hearts beat closer to yours.  Other planters have picked ready-to-use solutions like:  <a href="https://www.experiencerooted.com">Rooted</a>  <a href="https://alphausa.org/about">Alpha</a>  etc  Others still have used evangelism-focused trainings that are widely available.', 'Review the plan for Launch Team meetings for which ones will need specific training materials.  Contact other planters and pastors to learn what they have used.  Include your decisions in the Launch Team Development Strategy document.  This action is complete when you have picked training resources to use with your Launch Team.', 'template: standard  2017-06-14 content updated& --pb  2020-01-13 updated content --pb  2020-12-14 changed Due in # Days from 64& to 67& & Duration from 14 to 7& --pb&  ', 6, 'todo', 63, 7, '{}'::jsonb),
  ('29b5950b-5108-5aee-8c13-cdc43deca298', 'adbc3016-1383-5bbc-a053-fa0d0a21cc7f', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Create media disclaimer sign', 'Create a media disclaimer sign and page for the church website.', 'Capturing photos at church events is a must for churches. Photos and videos from service events and launch team gathering will help you share your church''s story. However, not everyone who comes to your church gatherings will be comfortable having their picture taken and shared on the internet or even on print material. That''s why it is important to create a media disclaimer sign that you can put up at events when you''ll be snapping pictures or recording video.  What should this sign say? Google Church media disclaimer sign and you''ll find several examples of what to say on the sign. Basically, it''ll say you''re taking pictures or video that may be included in church promotional material and if anyone does not wish to have their image recorded and shared to let the church know.  If you have church insurance, you should check to see if they have a media disclaimer already developed for you.  Keep in mind we''re not lawyers, so consulting with a lawyer in your area and asking them about how to capture and share media safely is advised.', 'Read <a href="https://prochurchtools.com/how-real-churches-get-photo-release-forms-ep-178/">How Real Churches Get Photo Release Forms</a> by Pro Church Tools.  Check with your church''s insurance company about a media disclaimer form.  Develop language to put on a sign that you can display at church events.  Design and print the media disclaimer sign.  This task is complete once the media disclaimer sign is in your possession.', 'template:  ', 0, 'todo', 97, 7, '{}'::jsonb),
  ('7363cdc2-20c5-5ec6-bd07-d14b7fdaa2c4', 'adbc3016-1383-5bbc-a053-fa0d0a21cc7f', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Get signed media release forms for minors', 'Obtain a photo release form that asks guardians for permission to capture photos or video of their children at church events.', 'Sharing pictures and videos of children at church gatherings without consent from their parents or guardians is asking for trouble. That''s why you should develop and distribute a media release form that grants your church permission to take pictures and video of their children and publish them.  Your church insurance company probably already has a form like this. Take their form and modify it to fit your church''s brand. Here''s an example from <a href="https://www.brotherhoodmutual.com/resources/safety-library/risk-management-forms/photo-use-agreement1/">Brotherhood Mutual</a>.  Consider including this release form as a part of the registration form for your children''s ministry.', 'Develop your church''s media release form for minors.  Add this form to your children''s ministry registration form.  This task is complete once the form has been developed and is ready to be distributed to parents/guardians.', 'template:  ', 1, 'todo', 97, 7, '{}'::jsonb),
  ('57331288-a230-5c3f-8e83-a07877481862', 'b1a2cf82-7e4f-5888-92c2-ec8c9d1c8179', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Review church strategies and measures', 'Review the church''s Vision Frame to keep groups structure and systems in alignment with the vision of the church.', 'When you did the hard work of prayerfully setting the church''s DNA through the  Vision Frame  process, you were led to particular strategies. One of those strategies was invariably some version of church groups.  Reorient yourself to the entirety of the Vision Frame and keep the Measures firmly in mind as you strategize your groups systems and structures. Will the groups you envision really produce the kind of disciple described in the church Measures?  Will the groups interplay with the other Strategies to accomplish the Mission of the church?', 'Reread your  Vision Frame  document.  Consider the role of groups in the overall  Vision Frame .  Keep all of that in mind as you proceed to fully flesh out your groups strategy.  This action is complete when you have reviewed your Vision Frame and committed to designing your groups strategy to support it.', 'template: standard  2018-03-28 content overhauled --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 140& to 60 --pb&  2022-11-21 updated link --sc ', 0, 'todo', 59, 7, '{}'::jsonb),
  ('cea33e69-f849-5592-baf1-5c034c4c3794', 'b1a2cf82-7e4f-5888-92c2-ec8c9d1c8179', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Define what kind of groups to have', 'Clearly articulate what groups will look like and how they will function at the new church.', 'There are tons of options for church groups. Your strategy may even include several types or levels of groups, like micro, small, and large groups. Explore different models and prayerfully determine what will work best in your context.  There are lots of ways to approach groups. Here are 11 small group archetypes outlined on <a href="https://www.smallgroupchurches.com/11-small-group-strategies-for-churches/">smallgroupchurches.com</a>:  On-going Open Group  Semester Sermon Study  Semester Elective-Group  40-Day Campaign  9-Month Closed Group  Mid-sized Geographic  a System that Promotes 2 or More Group Types  the Both/And System  Cell-Based Church  Groups of 12  Missional Communities  But also consider:  discipleship micro-groups (huddles, triads, etc.)  Sunday school classes (gasp!)  12-Step recovery groups  &hellip;others not mentioned here  Important decisions you''ll need to make for each kind or category of groups you''ll start include:  How big should the groups be (min/max)?  What will you call them?  What will be their focus and/or expected outcomes?  What will their format or curriculum be?  What will their duration and annual rhythms look like?', 'Research different groups models.  Determine which model will best fit the new church.  Complete the  Types of Groups  table in the  Church Groups Strategy Template .  This action is complete you have charted out specific details for each kind/category of group you will start.', 'template: standard  2018-03-28 content overhauled --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 140& to 60 --pb&  ', 1, 'todo', 59, 7, '{}'::jsonb),
  ('9fa0be73-c8ae-55ca-9cf6-ae21dd4c124a', 'b1a2cf82-7e4f-5888-92c2-ec8c9d1c8179', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set a goal for groups at launch', 'Prayerfully set goals for what you want your groups system to look like when you launch regular worship gatherings.', 'Goals help guide our actions and priorities. Setting comfortable goals that we know can be accomplished leaves little room for God''s provision. Big goals will force you to pray more and make different kinds of decisions to get there.  Set clear goals for the following:  Percentage of Launch Team active in groups  Number of groups at Launch  Number of groups ready to multiply at Launch  Percentage of average attendance active in groups after Launch, or maybe groups to attendance ratio', 'Set goals for each of the above along with any other useful health metric.  Strategize how you''ll get from where you are today to where you want to be at Launch.  Record the goals strategies in your  Church Groups Strategy  document.  This action is complete when you have set goals for your groups and charted a path to attain them.', 'template: standard  2018-03-28 content overhauled --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 140& to 60 --pb&  ', 2, 'todo', 59, 7, '{}'::jsonb),
  ('aee31551-c617-5451-9ed3-00bfa6fcdf88', 'b1a2cf82-7e4f-5888-92c2-ec8c9d1c8179', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Establish expectations of group leaders', 'Clearly define what is expected of group leaders to guide their growth and decision-making.', 'Every volunteer needs clear expectations. They want to know what is being asked of them and how much time it will take them to do the job.  For leadership positions, including group leaders, there are higher expectations. But what exactly are those expectations? Do your group leaders need an MDiv before you''ll let them lead? Or will they only to have to pass the ''can fog up a mirror'' test?  What, if any, moral or behavior boundaries will you set for them? How Pharisaic should that list be?  What are their time commitments for training, preparing, shepherding, etc? What are they responsible for?', 'Write out clear group leader expectations. Consider using a job description or leadership covenant for the group leader to sign.  Record the expectations in your  Church Groups Strategy  document.  This action is complete when you have written out clear expectations of group leaders.', 'template: standard  2018-03-28 content overhauled --pb  2019-11-26 content validated --pb  2020-12-11 changed Due in # Days from 140& to 60& & Duration from 14& to 7& --pb&  ', 3, 'todo', 59, 7, '{}'::jsonb),
  ('dc852114-dd37-5dfe-b1ef-79d35e988341', 'b1a2cf82-7e4f-5888-92c2-ec8c9d1c8179', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Develop a training plan for group leaders', 'Chart a path for people to grow into group leadership so that groups can grow and multiply.', 'Leadership training provides one of the best opportunities to communicate with and cast vision to key influencers in the new church. You simply cannot spend enough time with these church leaders. The degree to which they buy in and own the process will affect the DNA and health of the church.  In developing a training plan, consider:  the type of training (book study, interactive, lecture, etc.)  frequency of training (weekly, monthly, etc.)  method of training (ex: formal classroom or informal small group environment)  length of training (1 hour, all day, etc.)  content of training  whether to use of outside workshops/seminars (Exponential, Willow Creek, etc.)', 'Review group leader training plans at other healthy churches.  Determine what plans fit the vision and style of your church.  Develop or customize a plan to train your group leaders.  Include the training plan in your  Church Groups Strategy  document.  This action is complete when you have a written strategy to train group leaders.', 'template: standard  2018-03-28 content overhauled --pb  2019-11-26 content validated --pb  2020-12-14 changed Due in # Days from 140& to 74& --pb&  2022-11-16 updated SOAP study link to an existing site. --nz ', 4, 'todo', 59, 7, '{}'::jsonb),
  ('c4c9c313-439d-527b-a6f6-aaf87721eaaa', 'b4e6657e-3e29-5b88-9a5a-d8d2020a2ce7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Brainstorm list of potential Prayer Team partners', 'Recruit an army of people to pray for the you, your family, and the new church.', 'In 30 minutes, sit down and compile a list of every person you know who would pray for the church. Utilize tools you already have such as your address book, Facebook, etc. Consider the following groups of people to include in your list:  Family and extended family  Friends  Neighbors  Co-workers, previous co-workers, and other Christians in the work place  Current and previous church memberships  Other church memberships', 'Brainstorm a list of potential prayer partners.  Compile their names and email addresses in a spreadsheet, address book, closed social media group or email marketing app (Mailchimp, ConstantContact, etc).  This action is complete when you have brainstormed a list of potential prayer partners.', 'template: standard  2017-05-31 content updated --pb  &  ', 0, 'todo', 13, 7, '{}'::jsonb),
  ('8e6ff2a8-910e-54e0-8553-996aacd0d13d', 'b4e6657e-3e29-5b88-9a5a-d8d2020a2ce7', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Determine Prayer Team communication method(s)', 'Determine the best way to communicate prayer needs in order to minimize your admin burden and maximize the team''s engagement.', 'Group email programs allow members to easily signup to receive emails and for planters to email large numbers of people in a single email. Most group email apps also allow tracking to determine what percentages of emails are being opened. Passion for Planting recommends <a href="https://mailchimp.com/">Mailchimp</a>. It is a powerful yet easy-to-use app that produces professional-looking group emails. It has numerous pre-designed templates.  Social media also provides a simple and often real-time way to communicate with your prayer team. If you are active on social media like Facebook, create a closed Group and add your prayer team members.  Blogging is also an effective way to update the prayer team. Simply subscribe the prayer team to receive emails of each blog post. This will keep them in the loop and help them know how to pray.  Writing letters or sending pictures from time to time is also effective. This can give your intercessory prayer team something to stick on the fridge as a daily reminder to pray.  At the end of the day, you need to pick a method that will not be so labor-intensive that you stop using it when your schedule gets busy. Sending a 280-character tweet every week beats a monthly newsletter that never gets written.', 'Determine the easiest and most widely used way(s) to communicate with the prayer team.  Create an account or group.  This action is complete when you have determined the best way to communicate with the prayer team.', 'template: standard  2017-05-31 content updated, preferred vendor changed from ConstantContact to Mailchimp --pb  2019-11-22 content updated --pb ', 1, 'todo', 13, 7, '{}'::jsonb),
  ('6c9cf24c-9647-5779-9e7b-3aff096feadb', 'ef5549b6-92e2-59a2-8336-e6fc416efce5', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set a goal for number of community leaders to meet weekly', 'Challenge yourself to a sustainable pace of meeting leaders and influencers in your community.', NULL, 'content pending...', NULL, 0, 'todo', 44, 7, '{}'::jsonb),
  ('172a557c-5f4b-5325-8f9c-0a13157fe940', 'ef5549b6-92e2-59a2-8336-e6fc416efce5', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Write questions to ask community leaders', 'Develop a short list of questions to ask community leaders when you meet with them.', 'You''re going to start with a list of community leaders that is too big for you alone to meet with each of them. Of course you want to make as many connections as possible, but you''re probably going to have to recruit others to help so you can meet with everyone on the list. If you''re blessed with multiple staff, require each staff person to meet with community leaders, especially those in their sphere of influence (music, kids, etc.).  Developing a list of questions or a script to give to staff and volunteers can go a long way to helping them feel comfortable. It will also help prepare you for your own meetings with community leaders.  The one question that should always be asked toward the end of a conversation is, "Who else should I be sure to talk with (and would you introduce me)?"', 'Read the <a href="/resources/item/52">Sample Community Networking Interview Questions</a>.  Write the list of questions in your  Community Networking Strategy  document.  This action is complete when you have written out a short list of questions to ask community leaders.', 'template: standard  2017-11-13 content updated --pb  2019-12-09 content updated --pb  2020-12-14 changed Due in # Days from 140& to 137 & Duration from 38 to 45; name changed from "Conduct your community needs survey" --pb&  ', 1, 'todo', 44, 7, '{}'::jsonb),
  ('c0c87970-b4b0-5711-b256-fdf6f94d00d7', 'f57dc1ba-0c46-5cb2-93a8-8c97d6c953aa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Recruit a worship team leader', 'Recruit a worship team leader who will be responsible to make things happen while equipping and caring for team members.', 'For your church to be healthy, you have to equip people to lead and take ownership of ministry teams. Work your Leadership Development strategies to identify someone who has both leadership potential and musical ability.  Your worship team leader needs to quickly embrace the values of the church; they''ll be responsible to live them out and communicate those values to team members.  Consider writing out a job description and basic expectations you''d have of any worship team leader. Go over those with your candidate and be sure they understand what they''re signing up for. Things they''ll need to jump on right away are:  recruiting team members  choosing songs for initial repertoire  finding a rehearsal location and setting dates for rehearsals  scheduling volunteers so that there are no gaping holes in the band  Welcome to the "Joe Planter" show!  If you''re the Lead Planter, don''t try to pull off the dual role of preacher and worship leader. It''s a bad idea for lots of reasons. Find a volunteer or hire a staff person for this important leadership role.', 'Spend time in prayer asking God to raise up leaders.  Identify a person to lead the worship team.  Communicate expectations to the leader.  Get a commitment from the leader to own the processes and leadership of the team.  This action is complete when you have recruited and trained a team leader.', 'template: standard  2017-06-05 content validated --pb  2020-01-14 content updated --pb  2020-12-14 changed Due in # Days from 201& to 204& --pb&  ', 0, 'todo', 196, 31, '{}'::jsonb),
  ('4ea1022c-192c-5fb5-9660-bd031cc70bce', 'f57dc1ba-0c46-5cb2-93a8-8c97d6c953aa', (SELECT id FROM auth.users WHERE email = 'timothy.cheung58@gmail.com'), 'template', 'Set date for beginning rehearsals', 'Prepare for public worship gatherings by practicing with the band and sound technicians.', 'To gel and have good chemistry, the band and sound team have to practice together. Sound glitches, feedback, uncomfortable pauses, off-pitch singing, off-beat bands, etc. can all leave a negative impression on people attending the church.  In order to eliminate as many of these problems as possible, insist that the band practice many times before the first public worship gathering.  Regardless how good the band is, they won''t sound good unless the sound team has practiced with them to be able to get the most out of the equipment.', 'Schedule at least two full rehearsals with the full sound system and sound team.  Debrief after each rehearsal to discuss the needs of the band members and the sound team.  This action is complete when the band has practiced with the sound team and both teams are ready to lead worship during public gatherings.', 'template: standard  2017-06-05 content updated --pb  2020-01-14 content updated --pb  2020-12-14 changed Due in # Days from 130& to 135& --pb&  ', 1, 'todo', 203, 7, '{}'::jsonb);
